#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DaemonRoundTransitionEvidence {
    pub latest_round_state: String,
    pub done_round: Option<u64>,
    pub ledger_round: Option<u64>,
    pub round_in_progress: bool,
    pub reason_codes: Vec<String>,
    pub side_effects: bool,
}

impl DaemonRoundTransitionEvidence {
    pub fn round_done_waiting_ledger_commit(done_round: u64, ledger_round: u64) -> Self {
        Self {
            latest_round_state: "round_done_waiting_ledger_commit".to_owned(),
            done_round: Some(done_round),
            ledger_round: Some(ledger_round),
            round_in_progress: false,
            reason_codes: vec!["stdout_done_marker_seen_waiting_for_ledger_commit".to_owned()],
            side_effects: false,
        }
    }

    pub fn with_side_effects(mut self, side_effects: bool) -> Self {
        self.side_effects = side_effects;
        self
    }

    pub fn no_side_effects(&self) -> bool {
        !self.side_effects
    }

    pub fn is_round_done_waiting_ledger_commit(&self) -> bool {
        self.latest_round_state == "round_done_waiting_ledger_commit"
            && self.done_round.is_some()
            && self.ledger_round.is_some()
            && !self.round_in_progress
            && self
                .reason_codes
                .iter()
                .any(|reason| reason == "stdout_done_marker_seen_waiting_for_ledger_commit")
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DaemonRoundTransitionGate {
    pub require_round_done_waiting_ledger_commit_shape: bool,
    pub require_no_side_effects: bool,
}

impl DaemonRoundTransitionGate {
    pub fn strict() -> Self {
        Self {
            require_round_done_waiting_ledger_commit_shape: true,
            require_no_side_effects: true,
        }
    }

    pub fn evaluate(&self, evidence: &DaemonRoundTransitionEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_round_done_waiting_ledger_commit_shape
            && !evidence.is_round_done_waiting_ledger_commit()
        {
            decision = decision.merge(GateDecision::block(
                "daemon round transition evidence is not round_done_waiting_ledger_commit",
            ));
        }
        if self.require_no_side_effects && !evidence.no_side_effects() {
            decision = decision.merge(GateDecision::block(
                "daemon round transition evidence observed side effects",
            ));
        }
        decision
    }
}

