#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DaemonRoundTransitionBoundaryContract {
    pub schema_name: &'static str,
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl DaemonRoundTransitionBoundaryContract {
    pub fn daemon_round_transition_v1() -> Self {
        Self {
            schema_name: "daemon_round_transition_report_v1",
            entrypoints: vec![
                "DaemonRoundTransitionEvidence::round_done_waiting_ledger_commit",
                "DaemonRoundTransitionEvidence::no_side_effects",
                "DaemonRoundTransitionGate::evaluate",
                "DaemonRoundTransitionReport::from_gate_and_evidence",
            ],
            allowed_inputs: vec![
                "DaemonRoundTransitionEvidence",
                "DaemonRoundTransitionGate",
                "latest_round_state",
                "done_round",
                "ledger_round",
                "round_in_progress",
                "reason_codes",
                "side_effects",
            ],
            produced_outputs: vec![
                "DaemonRoundTransitionEvidence",
                "GateDecision",
                "DaemonRoundTransitionReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "file_io",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "daemon_control",
                "runner_state",
                "remote_mac_call",
                "model_call",
                "chat_stream",
                "ndkv_write",
                "runtime_side_effect_execution",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn schema_sources_within_boundary(
        &self,
        schema: &DaemonRoundTransitionReportSchema,
    ) -> bool {
        schema
            .fields
            .iter()
            .all(|field| field.source.starts_with("DaemonRoundTransition"))
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.schema_name == "daemon_round_transition_report_v1"
            && self.exposes_entrypoint(
                "DaemonRoundTransitionEvidence::round_done_waiting_ledger_commit",
            )
            && self.exposes_entrypoint("DaemonRoundTransitionGate::evaluate")
            && self.exposes_entrypoint("DaemonRoundTransitionReport::from_gate_and_evidence")
            && self.allows_input("DaemonRoundTransitionEvidence")
            && self.allows_input("latest_round_state")
            && self.allows_input("done_round")
            && self.allows_input("ledger_round")
            && self.allows_input("side_effects")
            && !self.allows_input("DaemonHandle")
            && !self.allows_input("LedgerReader")
            && !self.allows_input("EvolutionLoopRunner")
            && self.produces_output("DaemonRoundTransitionReport")
            && [
                "jsonl_io",
                "file_io",
                "http_sse",
                "process_spawn",
                "daemon_control",
                "runner_state",
                "remote_mac_call",
                "model_call",
                "chat_stream",
                "ndkv_write",
                "runtime_side_effect_execution",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LiveStatusBundleDaemonState {
    pub transition_kind: String,
    pub active_round: Option<u64>,
    pub ledger_latest_round: Option<u64>,
    pub latest_done_round: Option<u64>,
    pub round_in_progress: bool,
    pub read_only: bool,
    pub starts_process: bool,
    pub sends_prompt: bool,
}

impl LiveStatusBundleDaemonState {
    pub fn normal_in_progress(
        active_round: u64,
        ledger_latest_round: u64,
        latest_done_round: u64,
    ) -> Self {
        Self {
            transition_kind: "normal_in_progress".to_owned(),
            active_round: Some(active_round),
            ledger_latest_round: Some(ledger_latest_round),
            latest_done_round: Some(latest_done_round),
            round_in_progress: true,
            read_only: true,
            starts_process: false,
            sends_prompt: false,
        }
    }

    pub fn round_done_waiting_ledger_commit(done_round: u64, ledger_round: u64) -> Self {
        Self {
            transition_kind: "round_done_waiting_ledger_commit".to_owned(),
            active_round: None,
            ledger_latest_round: Some(ledger_round),
            latest_done_round: Some(done_round),
            round_in_progress: false,
            read_only: true,
            starts_process: false,
            sends_prompt: false,
        }
    }

    pub fn with_runtime_side_effects(mut self, starts_process: bool, sends_prompt: bool) -> Self {
        self.starts_process = starts_process;
        self.sends_prompt = sends_prompt;
        self
    }

    pub fn with_read_only(mut self, read_only: bool) -> Self {
        self.read_only = read_only;
        self
    }

    pub fn display_state(&self) -> &'static str {
        if self.round_in_progress {
            "active_busy"
        } else if self.transition_kind == "round_done_waiting_ledger_commit"
            || self.latest_done_round > self.ledger_latest_round
        {
            "ledger_pending"
        } else {
            "ledger_synced"
        }
    }

    pub fn is_known_display_state(&self) -> bool {
        matches!(
            self.display_state(),
            "active_busy" | "ledger_pending" | "ledger_synced"
        )
    }

    pub fn no_runtime_dispatch(&self) -> bool {
        self.read_only && !self.starts_process && !self.sends_prompt
    }
}

