#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LiveStatusBundleGate {
    pub require_known_display_state: bool,
    pub require_service_cli_context_read_only: bool,
    pub require_daemon_state_read_only: bool,
    pub reject_work_dispatch: bool,
    pub reject_prompt_replay: bool,
    pub reject_process_start: bool,
    pub reject_memory_write: bool,
    pub reject_ndkv_write: bool,
    pub reject_polluted_or_completed_window_actionability: bool,
}

impl LiveStatusBundleGate {
    pub fn strict() -> Self {
        Self {
            require_known_display_state: true,
            require_service_cli_context_read_only: true,
            require_daemon_state_read_only: true,
            reject_work_dispatch: true,
            reject_prompt_replay: true,
            reject_process_start: true,
            reject_memory_write: true,
            reject_ndkv_write: true,
            reject_polluted_or_completed_window_actionability: true,
        }
    }

    pub fn evaluate(&self, evidence: &LiveStatusBundleEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_known_display_state && !evidence.daemon_state.is_known_display_state() {
            decision = decision.merge(GateDecision::block(
                "live status bundle daemon state has no known display state",
            ));
        }
        if self.require_service_cli_context_read_only && !evidence.service_cli_context_read_only {
            decision = decision.merge(GateDecision::block(
                "live status bundle service/CLI context is not read-only",
            ));
        }
        if self.require_daemon_state_read_only && !evidence.daemon_state.read_only {
            decision = decision.merge(GateDecision::block(
                "live status bundle daemon transition state is not read-only",
            ));
        }
        if self.reject_work_dispatch && evidence.dispatches_work {
            decision = decision.merge(GateDecision::block(
                "live status bundle attempted to dispatch work",
            ));
        }
        if self.reject_prompt_replay
            && (evidence.replays_prompts || evidence.daemon_state.sends_prompt)
        {
            decision = decision.merge(GateDecision::block(
                "live status bundle attempted to replay or send prompts",
            ));
        }
        if self.reject_process_start
            && (evidence.starts_processes || evidence.daemon_state.starts_process)
        {
            decision = decision.merge(GateDecision::block(
                "live status bundle attempted to start a process",
            ));
        }
        if self.reject_memory_write && evidence.writes_memory {
            decision = decision.merge(GateDecision::block(
                "live status bundle attempted to write memory",
            ));
        }
        if self.reject_ndkv_write && evidence.writes_ndkv {
            decision = decision.merge(GateDecision::block(
                "live status bundle attempted to write .ndkv",
            ));
        }
        if self.reject_polluted_or_completed_window_actionability
            && evidence.marks_polluted_or_completed_windows_actionable
        {
            decision = decision.merge(GateDecision::block(
                "live status bundle marked polluted or completed windows actionable",
            ));
        }
        decision
    }
}

