        assert_eq!(report.evidence_count, 2);
        assert_eq!(
            report.allowed_evidence_labels,
            vec![
                "crates/norion-eval/src/lib.rs",
                "docs/runbooks/smartsteam-parallel-coordination.md tail"
            ]
        );
        assert!(report.polluted_evidence_labels.is_empty());
        assert!(report.context_hygiene_passed);
