        assert!(schema_fields.contains(&"next_round_decision.readiness_can_schedule_next_round"));
        assert!(schema_fields.contains(&"next_round_decision.read_only"));
        assert!(schema_fields.contains(&"next_round_decision.report_only"));
        assert!(schema_fields.contains(&"next_round_decision.no_side_effects"));
        assert!(schema_fields.contains(&"next_round_decision.dispatch_work_allowed"));
        assert!(schema_fields.contains(&"next_round_decision.prompt_replay_allowed"));
        assert!(schema_fields.contains(&"next_round_decision.process_start_allowed"));
        assert!(schema_fields.contains(&"next_round_decision.memory_write_allowed"));
        assert!(schema_fields.contains(&"next_round_decision.ndkv_write_allowed"));
        assert!(contract.schema_sources_within_boundary(&schema));
        assert!(contract.stays_pure_data_boundary());
        assert!(plan.stays_pure_data_boundary());
        assert!(plan.has_decision_status("safe_to_wait_current_round_active"));
        assert!(plan.has_decision_status("safe_to_continue_after_current_round"));
        assert!(plan.has_decision_status("operator_attention_blocked"));
        assert!(!plan.may_dispatch_work());
        assert!(plan.preserves_legacy_runner);
        assert!(!contract.allows_input("DaemonHandle"));
        assert!(!contract.allows_input("ServiceClient"));
        assert!(!contract.allows_input("CliExecutor"));
        assert!(!contract.allows_input("PromptReplayer"));
        assert!(contract.forbids_capability("dispatch_work"));
