#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RollbackPlan {
    pub required: bool,
    pub reason: String,
    pub actions: Vec<String>,
}

impl RollbackPlan {
    pub fn none() -> Self {
        Self {
            required: false,
            reason: "no rollback required".to_owned(),
            actions: Vec::new(),
        }
    }

    pub fn validation_failure(reason: impl Into<String>) -> Self {
        Self {
            required: true,
            reason: reason.into(),
            actions: vec![
                "stop scheduling new evolution rounds".to_owned(),
                "preserve failing ledger record for report gate".to_owned(),
                "re-run the planned validation command before resuming".to_owned(),
            ],
        }
    }

    pub fn from_decision(decision: &GateDecision) -> Self {
        if decision.blocked {
            Self::validation_failure(decision.reasons.join("; "))
        } else {
            Self::none()
        }
    }
}

