#[derive(Debug, Clone, PartialEq)]
pub struct ContextRotTrendWindowSummary {
    pub rounds: usize,
    pub first_round: Option<u64>,
    pub last_round: Option<u64>,
    pub latest_noisy_records: u64,
    pub latest_duplicate_outputs: u64,
    pub latest_noise_penalty: f64,
    pub noisy_records_delta: i64,
    pub duplicate_outputs_delta: i64,
    pub max_consecutive_noisy_rounds: usize,
    pub max_consecutive_duplicate_rounds: usize,
    pub remediation_applied_rounds: usize,
    pub remediation_improved_noise: bool,
    pub remediation_improved_duplicates: bool,
}

impl ContextRotTrendWindowSummary {
    pub fn from_points(points: &[ContextRotTrendPoint]) -> Self {
        let first = points.first();
        let last = points.last();
        let mut max_consecutive_noisy_rounds = 0;
        let mut current_consecutive_noisy_rounds = 0;
        let mut max_consecutive_duplicate_rounds = 0;
        let mut current_consecutive_duplicate_rounds = 0;
        let mut remediation_applied_rounds = 0;

        for point in points {
            if point.has_noisy_signal() {
                current_consecutive_noisy_rounds += 1;
                max_consecutive_noisy_rounds =
                    max_consecutive_noisy_rounds.max(current_consecutive_noisy_rounds);
            } else {
                current_consecutive_noisy_rounds = 0;
            }
            if point.has_duplicate_signal() {
                current_consecutive_duplicate_rounds += 1;
                max_consecutive_duplicate_rounds =
                    max_consecutive_duplicate_rounds.max(current_consecutive_duplicate_rounds);
            } else {
                current_consecutive_duplicate_rounds = 0;
            }
            if point.remediation_applied {
                remediation_applied_rounds += 1;
            }
        }

        let first_noisy_records = first.map_or(0, |point| point.signal.noisy_records);
        let latest_noisy_records = last.map_or(0, |point| point.signal.noisy_records);
        let first_duplicate_outputs = first.map_or(0, |point| point.signal.duplicate_outputs);
        let latest_duplicate_outputs = last.map_or(0, |point| point.signal.duplicate_outputs);
        let first_noise_penalty = first.map_or(0.0, |point| point.signal.max_noise_penalty);
        let latest_noise_penalty = last.map_or(0.0, |point| point.signal.max_noise_penalty);

        Self {
            rounds: points.len(),
            first_round: first.map(|point| point.round),
            last_round: last.map(|point| point.round),
            latest_noisy_records,
            latest_duplicate_outputs,
            latest_noise_penalty,
            noisy_records_delta: latest_noisy_records as i64 - first_noisy_records as i64,
            duplicate_outputs_delta: latest_duplicate_outputs as i64
                - first_duplicate_outputs as i64,
            max_consecutive_noisy_rounds,
            max_consecutive_duplicate_rounds,
            remediation_applied_rounds,
            remediation_improved_noise: remediation_applied_rounds == 0
                || latest_noisy_records < first_noisy_records
                || latest_noise_penalty < first_noise_penalty,
            remediation_improved_duplicates: remediation_applied_rounds == 0
                || latest_duplicate_outputs < first_duplicate_outputs,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ContextRotTrendGate {
    pub min_window_rounds: usize,
    pub max_latest_noisy_records: u64,
    pub max_latest_duplicate_outputs: u64,
    pub max_consecutive_noisy_rounds: usize,
    pub max_consecutive_duplicate_rounds: usize,
    pub require_remediation_improves_noise: bool,
    pub require_remediation_improves_duplicates: bool,
}

impl ContextRotTrendGate {
    pub fn strict() -> Self {
        Self {
            min_window_rounds: 3,
            max_latest_noisy_records: 0,
            max_latest_duplicate_outputs: 0,
            max_consecutive_noisy_rounds: 1,
            max_consecutive_duplicate_rounds: 0,
            require_remediation_improves_noise: true,
            require_remediation_improves_duplicates: true,
        }
    }

    pub fn evaluate(&self, summary: &ContextRotTrendWindowSummary) -> GateDecision {
        let mut decision = GateDecision::pass();
        if summary.rounds < self.min_window_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Context Rot trend window too short: {} < {}",
                summary.rounds, self.min_window_rounds
            )));
        }
        if summary.latest_noisy_records > self.max_latest_noisy_records {
            decision = decision.merge(GateDecision::block(format!(
                "latest noisy records {} above maximum {}",
                summary.latest_noisy_records, self.max_latest_noisy_records
            )));
        }
        if summary.latest_duplicate_outputs > self.max_latest_duplicate_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "latest duplicate outputs {} above maximum {}",
                summary.latest_duplicate_outputs, self.max_latest_duplicate_outputs
            )));
        }
        if summary.max_consecutive_noisy_rounds > self.max_consecutive_noisy_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "consecutive noisy rounds {} above maximum {}",
                summary.max_consecutive_noisy_rounds, self.max_consecutive_noisy_rounds
            )));
        }
        if summary.max_consecutive_duplicate_rounds > self.max_consecutive_duplicate_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "consecutive duplicate-output rounds {} above maximum {}",
                summary.max_consecutive_duplicate_rounds, self.max_consecutive_duplicate_rounds
            )));
        }
        if self.require_remediation_improves_noise
            && summary.remediation_applied_rounds > 0
            && !summary.remediation_improved_noise
        {
            decision = decision.merge(GateDecision::block(
                "Context Rot remediation did not improve noise trend",
            ));
        }
        if self.require_remediation_improves_duplicates
            && summary.remediation_applied_rounds > 0
            && !summary.remediation_improved_duplicates
        {
            decision = decision.merge(GateDecision::block(
                "Context Rot remediation did not improve duplicate-output trend",
            ));
        }
        decision
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ContextRotTrendReport {
    pub rounds: usize,
    pub first_round: Option<u64>,
    pub last_round: Option<u64>,
    pub latest_noisy_records: u64,
    pub latest_duplicate_outputs: u64,
    pub latest_noise_penalty: f64,
    pub noisy_records_delta: i64,
    pub duplicate_outputs_delta: i64,
    pub max_consecutive_noisy_rounds: usize,
    pub max_consecutive_duplicate_rounds: usize,
    pub remediation_applied_rounds: usize,
    pub remediation_improved_noise: bool,
    pub remediation_improved_duplicates: bool,
    pub trend_blocked: bool,
    pub allow_unattended_continuation: bool,
    pub failure_reasons: Vec<String>,
}

impl ContextRotTrendReport {
    pub fn from_summary_and_decision(
        summary: &ContextRotTrendWindowSummary,
        decision: &GateDecision,
    ) -> Self {
        Self {
            rounds: summary.rounds,
            first_round: summary.first_round,
            last_round: summary.last_round,
            latest_noisy_records: summary.latest_noisy_records,
            latest_duplicate_outputs: summary.latest_duplicate_outputs,
            latest_noise_penalty: summary.latest_noise_penalty,
            noisy_records_delta: summary.noisy_records_delta,
            duplicate_outputs_delta: summary.duplicate_outputs_delta,
            max_consecutive_noisy_rounds: summary.max_consecutive_noisy_rounds,
            max_consecutive_duplicate_rounds: summary.max_consecutive_duplicate_rounds,
            remediation_applied_rounds: summary.remediation_applied_rounds,
            remediation_improved_noise: summary.remediation_improved_noise,
            remediation_improved_duplicates: summary.remediation_improved_duplicates,
            trend_blocked: decision.blocked,
            allow_unattended_continuation: !decision.blocked,
            failure_reasons: decision.reasons.clone(),
        }
    }

    pub fn from_points_and_gate(
        points: &[ContextRotTrendPoint],
        gate: &ContextRotTrendGate,
    ) -> Self {
        let summary = ContextRotTrendWindowSummary::from_points(points);
        let decision = gate.evaluate(&summary);
        Self::from_summary_and_decision(&summary, &decision)
    }
}

