#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterContextRotTrendBoundaryContract {
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl AdapterContextRotTrendBoundaryContract {
    pub fn context_rot_trend_v1() -> Self {
        Self {
            entrypoints: vec![
                "ContextRotTrendWindowSummary::from_points",
                "ContextRotTrendGate::evaluate",
                "ContextRotTrendReport::from_points_and_gate",
            ],
            allowed_inputs: vec![
                "ContextRotSignal",
                "ContextRotTrendPoint",
                "ContextRotTrendGate",
            ],
            produced_outputs: vec![
                "ContextRotTrendWindowSummary",
                "GateDecision",
                "ContextRotTrendReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "filesystem_scan",
                "quarantine_action_execution",
                "clean_gist_write",
                "duplicate_output_delete",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.exposes_entrypoint("ContextRotTrendWindowSummary::from_points")
            && self.exposes_entrypoint("ContextRotTrendGate::evaluate")
            && self.exposes_entrypoint("ContextRotTrendReport::from_points_and_gate")
            && self.allows_input("ContextRotSignal")
            && self.allows_input("ContextRotTrendPoint")
            && self.allows_input("ContextRotTrendGate")
            && !self.allows_input("FilesystemScanner")
            && !self.allows_input("JsonlReader")
            && self.produces_output("ContextRotTrendWindowSummary")
            && self.produces_output("GateDecision")
            && self.produces_output("ContextRotTrendReport")
            && [
                "jsonl_io",
                "filesystem_scan",
                "quarantine_action_execution",
                "clean_gist_write",
                "duplicate_output_delete",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ExperimentRolloutGate {
    pub max_enabled_rollout_percent: u8,
    pub require_owner: bool,
    pub require_clean_context_rot: bool,
}

impl ExperimentRolloutGate {
    pub fn conservative() -> Self {
        Self {
            max_enabled_rollout_percent: 10,
            require_owner: true,
            require_clean_context_rot: true,
        }
    }

    pub fn evaluate(
        &self,
        flag: &ExperimentFlag,
        context_rot_decision: &GateDecision,
    ) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_owner && flag.owner.trim().is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} has no owner",
                flag.name
            )));
        }
        if flag.enabled && flag.rollout_percent > self.max_enabled_rollout_percent {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} rollout {} above maximum {}",
                flag.name, flag.rollout_percent, self.max_enabled_rollout_percent
            )));
        }
        if flag.enabled && self.require_clean_context_rot && context_rot_decision.blocked {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} requires clean Context Rot gate: {}",
                flag.name,
                context_rot_decision.reasons.join("; ")
            )));
        }
        decision
    }
}

