#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ModelWorkerRecord {
    pub worker_id: String,
    pub role: ModelRole,
    pub model: String,
    pub latency_ms: u64,
    pub runtime_tokens: u64,
    pub success: bool,
    pub feedback_applied: u64,
    pub validation_checked: bool,
    pub validation_passed: bool,
    pub duplicate_output: bool,
    pub noisy_output: bool,
    pub blocked_primary_12b: bool,
    pub failure_kind: RootAdapterFailureKind,
}

impl ModelWorkerRecord {
    pub fn new(worker_id: impl Into<String>, role: ModelRole, model: impl Into<String>) -> Self {
        Self {
            worker_id: worker_id.into(),
            role,
            model: model.into(),
            latency_ms: 0,
            runtime_tokens: 0,
            success: false,
            feedback_applied: 0,
            validation_checked: false,
            validation_passed: false,
            duplicate_output: false,
            noisy_output: false,
            blocked_primary_12b: false,
            failure_kind: RootAdapterFailureKind::None,
        }
    }

    pub fn with_runtime(mut self, latency_ms: u64, runtime_tokens: u64) -> Self {
        self.latency_ms = latency_ms;
        self.runtime_tokens = runtime_tokens;
        self
    }

    pub fn with_success(mut self, success: bool) -> Self {
        self.success = success;
        self
    }

    pub fn with_feedback(mut self, feedback_applied: u64) -> Self {
        self.feedback_applied = feedback_applied;
        self
    }

    pub fn with_validation(mut self, checked: bool, passed: bool) -> Self {
        self.validation_checked = checked;
        self.validation_passed = passed;
        self
    }

    pub fn with_output_quality(mut self, duplicate: bool, noisy: bool) -> Self {
        self.duplicate_output = duplicate;
        self.noisy_output = noisy;
        self
    }

    pub fn with_primary_blocked(mut self, blocked: bool) -> Self {
        self.blocked_primary_12b = blocked;
        self
    }

    pub fn with_failure_kind(mut self, failure_kind: RootAdapterFailureKind) -> Self {
        self.failure_kind = failure_kind;
        self
    }

    pub fn development_claim_blockers(&self) -> Vec<&'static str> {
        let mut blockers = Vec::new();
        if !self.success {
            blockers.push("worker_not_successful");
        }
        if self.latency_ms == 0 {
            blockers.push("missing_latency_ms");
        }
        if self.runtime_tokens == 0 {
            blockers.push("missing_runtime_tokens");
        }
        if self.feedback_applied == 0 {
            blockers.push("feedback_not_applied");
        }
        if !self.validation_checked {
            blockers.push("validation_not_checked");
        } else if !self.validation_passed {
            blockers.push("validation_not_passed");
        }
        if self.duplicate_output {
            blockers.push("duplicate_output");
        }
        if self.noisy_output {
            blockers.push("noisy_output");
        }
        if self.blocked_primary_12b {
            blockers.push("blocked_primary_12b");
        }
        if self.failure_kind.is_operational_readiness() {
            blockers.push("operational_readiness_failure");
        } else if self.failure_kind.counts_as_model_quality_failure() {
            blockers.push("model_quality_failure");
        } else if matches!(
            self.failure_kind,
            RootAdapterFailureKind::StreamOrFinalMissing
                | RootAdapterFailureKind::RuntimeResponseMissing
        ) {
            blockers.push("runtime_response_failure");
        } else if self.failure_kind == RootAdapterFailureKind::Unknown {
            blockers.push("unknown_failure");
        }
        blockers
    }

    pub fn allows_development_claim(&self) -> bool {
        self.development_claim_blockers().is_empty()
    }
}

