#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFutureEventCoverageEvidence {
    pub source_contracts: Vec<&'static str>,
    pub required_future_events: Vec<&'static str>,
    pub planned_future_events: Vec<&'static str>,
}

impl AdapterFutureEventCoverageEvidence {
    pub fn from_required_and_emission<I, J>(
        source_contracts: Vec<&'static str>,
        required_future_events: I,
        planned_future_events: J,
    ) -> Self
    where
        I: IntoIterator<Item = &'static str>,
        J: IntoIterator<Item = &'static str>,
    {
        Self {
            source_contracts,
            required_future_events: dedup_static(required_future_events),
            planned_future_events: dedup_static(planned_future_events),
        }
    }

    pub fn apple_silicon_adapter_contracts() -> Self {
        let worker_plan = ModelWorkerLedgerAdapterPlan::evolution_loop_ledger();
        let baseline_plan = AppleSiliconBaselineAdapterPlan::root_business_cycle_json();
        let mut required = Vec::new();

        for mapping in worker_plan.future_event_mappings() {
            if let AdapterEvidenceSource::FutureEvent(name) = mapping.source {
                required.push(name);
            }
        }
        required.extend(baseline_plan.future_event_names());
        required.extend([
            "backend_8686_reachable",
            "prompt_gate_blocked",
            "final_json_present",
            "runtime_model_present",
            "runtime_tokens",
            "business_cycle_passed",
            "context_rot_noisy_records",
            "context_rot_noise_penalty",
            "context_rot_duplicate_outputs",
            "context_rot_quarantine_candidates",
            "context_rot_trend_window_rounds",
            "context_rot_consecutive_noisy_rounds",
            "context_rot_consecutive_duplicate_rounds",
            "context_rot_remediation_applied",
            "context_rot_clean_gist_backfilled",
            "context_rot_legacy_metadata_repaired",
            "steam_case_id",
            "steam_case_endpoint",
            "steam_case_kind",
            "validation_command_phase",
            "validation_command_line",
            "validation_command_status_code",
            "validation_output_tail",
        ]);

        Self::from_required_and_emission(
            vec![
                "ModelWorkerLedgerAdapterPlan::evolution_loop_ledger",
                "AppleSiliconBaselineAdapterPlan::root_business_cycle_json",
                "RootBusinessCycleAdapterPlan::root_business_cycle_json",
                "ContextRotAcceptanceContract",
                "ContextRotTrendGate",
                "ContextRotRemediationGate",
                "SteamCaseCoverageGate",
                "ValidationCommandCoverageGate",
            ],
            required,
            AdapterReportEmissionPlan::apple_silicon_development_effect().future_events(),
        )
    }

    pub fn missing_required_events(&self) -> Vec<&'static str> {
        self.required_future_events
            .iter()
            .copied()
            .filter(|event| !self.planned_future_events.contains(event))
            .collect()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AdapterFutureEventCoverageGate {
    pub stage: RootAdapterRolloutStage,
    pub require_required_events_planned: bool,
}

impl AdapterFutureEventCoverageGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_required_events_planned: stage == RootAdapterRolloutStage::Enforced,
        }
    }

    pub fn evaluate(&self, evidence: &AdapterFutureEventCoverageEvidence) -> GateDecision {
        if !self.require_required_events_planned {
            return GateDecision::pass();
        }

        let missing = evidence.missing_required_events();
        if missing.is_empty() {
            GateDecision::pass()
        } else {
            GateDecision::block(format!(
                "adapter emission plan is missing required future event(s): {}",
                missing.join(", ")
            ))
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFutureEventCoverageReport {
    pub stage: &'static str,
    pub source_contracts: Vec<&'static str>,
    pub required_future_events: Vec<&'static str>,
    pub planned_future_events: Vec<&'static str>,
    pub missing_required_events: Vec<&'static str>,
    pub coverage_blocked: bool,
    pub allow_adapter_emission_promotion: bool,
    pub failure_reasons: Vec<String>,
}

impl AdapterFutureEventCoverageReport {
    pub fn from_gate_and_evidence(
        gate: &AdapterFutureEventCoverageGate,
        evidence: &AdapterFutureEventCoverageEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            source_contracts: evidence.source_contracts.clone(),
            required_future_events: evidence.required_future_events.clone(),
            planned_future_events: evidence.planned_future_events.clone(),
            missing_required_events: evidence.missing_required_events(),
            coverage_blocked: decision.blocked,
            allow_adapter_emission_promotion: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFutureEventCoverageReportSchema {
    pub fields: Vec<ReportSchemaField>,
}

impl AdapterFutureEventCoverageReportSchema {
    pub fn adapter_future_event_coverage_v1() -> Self {
        Self {
            fields: vec![
                ReportSchemaField {
                    name: "adapter_future_events.stage",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "AdapterFutureEventCoverageGate::stage",
                },
                ReportSchemaField {
                    name: "adapter_future_events.source_contracts",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "AdapterFutureEventCoverageEvidence::source_contracts",
                },
                ReportSchemaField {
                    name: "adapter_future_events.required_future_events",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "adapter contract future-event declarations",
                },
                ReportSchemaField {
                    name: "adapter_future_events.planned_future_events",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "AdapterReportEmissionPlan::future_events",
                },
                ReportSchemaField {
                    name: "adapter_future_events.missing_required_events",
                    stage: ReportSchemaStage::Enforced,
                    source: "AdapterFutureEventCoverageEvidence::missing_required_events",
                },
                ReportSchemaField {
                    name: "adapter_future_events.coverage_blocked",
                    stage: ReportSchemaStage::Enforced,
                    source: "AdapterFutureEventCoverageGate::evaluate",
                },
                ReportSchemaField {
                    name: "adapter_future_events.allow_adapter_emission_promotion",
                    stage: ReportSchemaStage::Enforced,
                    source: "AdapterFutureEventCoverageGate::evaluate",
                },
                ReportSchemaField {
                    name: "adapter_future_events.failure_reasons",
                    stage: ReportSchemaStage::Enforced,
                    source: "AdapterFutureEventCoverageGate::evaluate reasons",
                },
            ],
        }
    }

    pub fn field_names(&self) -> Vec<&'static str> {
        self.fields.iter().map(|field| field.name).collect()
    }

    pub fn fields_for_stage(&self, stage: RootAdapterRolloutStage) -> Vec<&ReportSchemaField> {
        match stage {
            RootAdapterRolloutStage::ShadowOnly => Vec::new(),
            RootAdapterRolloutStage::ReportOnly => self
                .fields
                .iter()
                .filter(|field| field.stage == ReportSchemaStage::ReportOnly)
                .collect(),
            RootAdapterRolloutStage::Enforced => self.fields.iter().collect(),
        }
    }
}

