#[derive(Debug, Clone, PartialEq, Eq)]
pub struct LegacyLedgerReplayReport {
    pub stage: &'static str,
    pub ledger_rows_present: bool,
    pub base_ledger_fields_present: bool,
    pub required_existing_fields: Vec<&'static str>,
    pub optional_additive_reports: Vec<&'static str>,
    pub missing_additive_reports: Vec<&'static str>,
    pub compatibility_blocked: bool,
    pub failure_reasons: Vec<String>,
}

impl LegacyLedgerReplayReport {
    pub fn from_contract_evidence_and_decision(
        contract: &LegacyLedgerReplayCompatibility,
        evidence: &LegacyLedgerReplayEvidence,
        decision: &GateDecision,
    ) -> Self {
        Self {
            stage: contract.stage.as_str(),
            ledger_rows_present: evidence.ledger_rows_present,
            base_ledger_fields_present: evidence.base_ledger_fields_present,
            required_existing_fields: contract.required_existing_fields.clone(),
            optional_additive_reports: contract.optional_additive_reports.clone(),
            missing_additive_reports: contract.missing_additive_reports(evidence),
            compatibility_blocked: decision.blocked,
            failure_reasons: decision.reasons.clone(),
        }
    }

    pub fn from_summary_and_contract(
        summary: &LedgerSummary,
        contract: &LegacyLedgerReplayCompatibility,
    ) -> Self {
        let evidence = LegacyLedgerReplayEvidence::from_ledger_summary(summary);
        let decision = contract.evaluate_replay(&evidence);
        Self::from_contract_evidence_and_decision(contract, &evidence, &decision)
    }

    pub fn from_records_and_contract(
        records: &[LedgerRecord],
        contract: &LegacyLedgerReplayCompatibility,
    ) -> Self {
        let summary = LedgerSummary::from_records(records);
        Self::from_summary_and_contract(&summary, contract)
    }
}

