#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RootAdapterFailureEvidence {
    pub backend_8686_reachable: Option<bool>,
    pub prompt_gate_blocked: bool,
    pub final_json_present: bool,
    pub runtime_model_present: bool,
    pub runtime_tokens: Option<u64>,
    pub business_cycle_passed: Option<bool>,
    pub error: Option<String>,
}

impl RootAdapterFailureEvidence {
    pub fn clean() -> Self {
        Self {
            backend_8686_reachable: Some(true),
            prompt_gate_blocked: false,
            final_json_present: true,
            runtime_model_present: true,
            runtime_tokens: Some(1),
            business_cycle_passed: Some(true),
            error: None,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RootAdapterFailureKind {
    None,
    ChainNotReady,
    ModelUnavailable,
    StreamOrFinalMissing,
    RuntimeResponseMissing,
    ModelQualityFailure,
    Unknown,
}

impl RootAdapterFailureKind {
    pub fn as_code(&self) -> &'static str {
        match self {
            Self::None => "none",
            Self::ChainNotReady => "chain_not_ready",
            Self::ModelUnavailable => "model_unavailable",
            Self::StreamOrFinalMissing => "stream_or_final_missing",
            Self::RuntimeResponseMissing => "runtime_response_missing",
            Self::ModelQualityFailure => "model_quality_failure",
            Self::Unknown => "unknown",
        }
    }

    pub fn resume_gate(&self) -> &'static str {
        match self {
            Self::None => "none",
            Self::ChainNotReady => "chain_readiness_gate",
            Self::ModelUnavailable => "runtime_backend_health_check",
            Self::StreamOrFinalMissing => "stream_continuity_validation",
            Self::RuntimeResponseMissing => "runtime_response_gate",
            Self::ModelQualityFailure => "model_quality_review",
            Self::Unknown => "manual_failure_classification",
        }
    }

    pub fn is_operational_readiness(&self) -> bool {
        matches!(self, Self::ChainNotReady | Self::ModelUnavailable)
    }

    pub fn counts_as_model_quality_failure(&self) -> bool {
        *self == Self::ModelQualityFailure
    }
}

pub fn root_adapter_failure_resume_gate_from_code(code: &str) -> &'static str {
    match code {
        "none" => "none",
        "chain_not_ready" => "chain_readiness_gate",
        "model_unavailable" => "runtime_backend_health_check",
        "stream_or_final_missing" => "stream_continuity_validation",
        "runtime_response_missing" => "runtime_response_gate",
        "model_quality_failure" => "model_quality_review",
        "unknown" => "manual_failure_classification",
        _ => "manual_failure_classification",
    }
}

pub fn classify_root_adapter_failure(
    evidence: &RootAdapterFailureEvidence,
) -> RootAdapterFailureKind {
    if evidence.prompt_gate_blocked {
        return RootAdapterFailureKind::ChainNotReady;
    }
    if evidence.backend_8686_reachable == Some(false) {
        return RootAdapterFailureKind::ModelUnavailable;
    }
    if !evidence.final_json_present {
        return RootAdapterFailureKind::StreamOrFinalMissing;
    }
    if !evidence.runtime_model_present || evidence.runtime_tokens.unwrap_or(0) == 0 {
        return RootAdapterFailureKind::RuntimeResponseMissing;
    }
    if evidence.business_cycle_passed == Some(false) {
        return RootAdapterFailureKind::ModelQualityFailure;
    }
    if evidence.business_cycle_passed == Some(true) {
        RootAdapterFailureKind::None
    } else {
        RootAdapterFailureKind::Unknown
    }
}

pub fn rollback_plan_for_root_adapter_failure(kind: RootAdapterFailureKind) -> RollbackPlan {
    match kind {
        RootAdapterFailureKind::None => RollbackPlan::none(),
        RootAdapterFailureKind::ChainNotReady => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "pause root adapter enforcement".to_owned(),
                "preserve prompt-gate evidence".to_owned(),
                "resume after chain readiness gate passes".to_owned(),
            ],
        },
        RootAdapterFailureKind::ModelUnavailable => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "pause model-pool enforcement".to_owned(),
                "preserve backend 8686 health evidence".to_owned(),
                "resume after runtime backend health check passes".to_owned(),
            ],
        },
        RootAdapterFailureKind::StreamOrFinalMissing => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "stop scheduling new evolution rounds".to_owned(),
                "preserve stream transcript and incomplete final JSON".to_owned(),
                "re-run stream continuity validation before resuming".to_owned(),
            ],
        },
        RootAdapterFailureKind::RuntimeResponseMissing => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "stop scheduling new evolution rounds".to_owned(),
                "preserve runtime response metadata".to_owned(),
                "re-run runtime response gate before resuming".to_owned(),
            ],
        },
        RootAdapterFailureKind::ModelQualityFailure => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "stop scheduling new evolution rounds".to_owned(),
                "preserve final JSON and validation evidence".to_owned(),
                "route failure to model-quality review before resuming".to_owned(),
            ],
        },
        RootAdapterFailureKind::Unknown => RollbackPlan {
            required: true,
            reason: kind.as_code().to_owned(),
            actions: vec![
                "pause root adapter enforcement".to_owned(),
                "preserve raw adapter evidence".to_owned(),
                "classify the failure before resuming".to_owned(),
            ],
        },
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RollbackDrillCase {
    pub failure_kind: RootAdapterFailureKind,
    pub rollback_required: bool,
    pub rollback_reason: String,
    pub rollback_actions: Vec<String>,
    pub resume_gate: &'static str,
}

impl RollbackDrillCase {
    pub fn from_failure_kind(failure_kind: RootAdapterFailureKind) -> Self {
        let plan = rollback_plan_for_root_adapter_failure(failure_kind);

        Self {
            failure_kind,
            rollback_required: plan.required,
            rollback_reason: plan.reason,
            rollback_actions: plan.actions,
            resume_gate: failure_kind.resume_gate(),
        }
    }

    pub fn with_rollback_reason(mut self, reason: impl Into<String>) -> Self {
        self.rollback_reason = reason.into();
        self
    }

    pub fn with_resume_gate(mut self, resume_gate: &'static str) -> Self {
        self.resume_gate = resume_gate;
        self
    }

    pub fn with_rollback_actions<I, S>(mut self, actions: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        self.rollback_actions = actions.into_iter().map(Into::into).collect();
        self
    }

    pub fn with_rollback_required(mut self, required: bool) -> Self {
        self.rollback_required = required;
        self
    }

    pub fn expected_rollback_reason(&self) -> &'static str {
        match self.failure_kind {
            RootAdapterFailureKind::None => "no rollback required",
            _ => self.failure_kind.as_code(),
        }
    }

    pub fn rollback_reason_is_stable(&self) -> bool {
        self.rollback_reason == self.expected_rollback_reason()
    }

    pub fn resume_gate_is_stable(&self) -> bool {
        self.resume_gate == self.failure_kind.resume_gate()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RollbackDrillMatrixEvidence {
    pub cases: Vec<RollbackDrillCase>,
}

impl RollbackDrillMatrixEvidence {
    pub fn from_cases<I>(cases: I) -> Self
    where
        I: IntoIterator<Item = RollbackDrillCase>,
    {
        Self {
            cases: cases.into_iter().collect(),
        }
    }

    pub fn root_adapter_policy_matrix() -> Self {
        Self::from_cases(
            [
                RootAdapterFailureKind::None,
                RootAdapterFailureKind::ChainNotReady,
                RootAdapterFailureKind::ModelUnavailable,
                RootAdapterFailureKind::StreamOrFinalMissing,
                RootAdapterFailureKind::RuntimeResponseMissing,
                RootAdapterFailureKind::ModelQualityFailure,
                RootAdapterFailureKind::Unknown,
            ]
            .into_iter()
            .map(RollbackDrillCase::from_failure_kind),
        )
    }

    pub fn failure_kinds(&self) -> Vec<&'static str> {
        self.cases
            .iter()
            .map(|case| case.failure_kind.as_code())
            .collect()
    }

    pub fn rollback_reasons(&self) -> Vec<String> {
        self.cases
            .iter()
            .map(|case| case.rollback_reason.clone())
            .collect()
    }

    pub fn resume_gates(&self) -> Vec<&'static str> {
        self.cases.iter().map(|case| case.resume_gate).collect()
    }

    pub fn covered_failure_kinds(&self) -> Vec<&'static str> {
        self.failure_kinds()
    }

    pub fn missing_failure_kinds(
        &self,
        required_kinds: &[RootAdapterFailureKind],
    ) -> Vec<&'static str> {
        required_kinds
            .iter()
            .filter(|kind| !self.cases.iter().any(|case| case.failure_kind == **kind))
            .map(RootAdapterFailureKind::as_code)
            .collect()
    }

    pub fn unstable_rollback_reasons(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| !case.rollback_reason_is_stable())
            .map(|case| {
                format!(
                    "{} reason {} expected {}",
                    case.failure_kind.as_code(),
                    case.rollback_reason,
                    case.expected_rollback_reason()
                )
            })
            .collect()
    }

    pub fn unstable_resume_gates(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| !case.resume_gate_is_stable())
            .map(|case| {
                format!(
                    "{} resume_gate {} expected {}",
                    case.failure_kind.as_code(),
                    case.resume_gate,
                    case.failure_kind.resume_gate()
                )
            })
            .collect()
    }

    pub fn empty_action_failure_kinds(&self) -> Vec<&'static str> {
        self.cases
            .iter()
            .filter(|case| case.rollback_required && case.rollback_actions.is_empty())
            .map(|case| case.failure_kind.as_code())
            .collect()
    }

    pub fn none_requires_rollback(&self) -> bool {
        self.cases
            .iter()
            .any(|case| case.failure_kind == RootAdapterFailureKind::None && case.rollback_required)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RollbackDrillMatrixGate {
    pub stage: RootAdapterRolloutStage,
    pub required_failure_kinds: Vec<RootAdapterFailureKind>,
    pub require_stable_rollback_reason: bool,
    pub require_stable_resume_gate: bool,
    pub require_actions_for_required_rollback: bool,
    pub forbid_none_rollback: bool,
}

impl RollbackDrillMatrixGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            required_failure_kinds: vec![
                RootAdapterFailureKind::None,
                RootAdapterFailureKind::ChainNotReady,
                RootAdapterFailureKind::ModelUnavailable,
                RootAdapterFailureKind::StreamOrFinalMissing,
                RootAdapterFailureKind::RuntimeResponseMissing,
                RootAdapterFailureKind::ModelQualityFailure,
                RootAdapterFailureKind::Unknown,
            ],
            require_stable_rollback_reason: true,
            require_stable_resume_gate: true,
            require_actions_for_required_rollback: true,
            forbid_none_rollback: true,
        }
    }

    pub fn evaluate(&self, evidence: &RollbackDrillMatrixEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        let missing = evidence.missing_failure_kinds(&self.required_failure_kinds);
        if !missing.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "rollback drill missing failure kinds: {}",
                missing.join(", ")
            )));
        }

        if self.require_stable_rollback_reason {
            let unstable = evidence.unstable_rollback_reasons();
            if !unstable.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "rollback drill has unstable rollback reasons: {}",
                    unstable.join("; ")
                )));
            }
        }

        if self.require_stable_resume_gate {
            let unstable = evidence.unstable_resume_gates();
            if !unstable.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "rollback drill has unstable resume gates: {}",
                    unstable.join("; ")
                )));
            }
        }

        if self.require_actions_for_required_rollback {
            let empty = evidence.empty_action_failure_kinds();
            if !empty.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "rollback drill has required rollbacks without actions: {}",
                    empty.join(", ")
                )));
            }
        }

        if self.forbid_none_rollback && evidence.none_requires_rollback() {
            decision = decision.merge(GateDecision::block(
                "rollback drill makes clean root adapter evidence require rollback",
            ));
        }

        decision
    }
}

