#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterRollbackDrillMatrixBoundaryContract {
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl AdapterRollbackDrillMatrixBoundaryContract {
    pub fn rollback_drill_matrix_v1() -> Self {
        Self {
            entrypoints: vec![
                "RollbackDrillCase::from_failure_kind",
                "RollbackDrillMatrixEvidence::root_adapter_policy_matrix",
                "RollbackDrillMatrixGate::evaluate",
                "RollbackDrillMatrixReport::from_gate_and_evidence",
            ],
            allowed_inputs: vec![
                "RootAdapterFailureKind",
                "RollbackDrillCase",
                "RollbackDrillMatrixEvidence",
                "RollbackDrillMatrixGate",
            ],
            produced_outputs: vec![
                "RollbackDrillCase",
                "RollbackDrillMatrixEvidence",
                "GateDecision",
                "RollbackDrillMatrixReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "rollback_action_execution",
                "resume_action_execution",
                "runner_state",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.exposes_entrypoint("RollbackDrillCase::from_failure_kind")
            && self.exposes_entrypoint("RollbackDrillMatrixEvidence::root_adapter_policy_matrix")
            && self.exposes_entrypoint("RollbackDrillMatrixGate::evaluate")
            && self.exposes_entrypoint("RollbackDrillMatrixReport::from_gate_and_evidence")
            && self.allows_input("RootAdapterFailureKind")
            && self.allows_input("RollbackDrillCase")
            && self.allows_input("RollbackDrillMatrixEvidence")
            && self.allows_input("RollbackDrillMatrixGate")
            && !self.allows_input("RollbackActionExecutor")
            && !self.allows_input("ResumeActionExecutor")
            && !self.allows_input("EvolutionLoopRunner")
            && self.produces_output("RollbackDrillCase")
            && self.produces_output("RollbackDrillMatrixEvidence")
            && self.produces_output("GateDecision")
            && self.produces_output("RollbackDrillMatrixReport")
            && [
                "jsonl_io",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "rollback_action_execution",
                "resume_action_execution",
                "runner_state",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFixtureCase {
    pub name: String,
    pub root_fixture_present: bool,
    pub ledger_projection_checked: bool,
    pub model_worker_projection_checked: bool,
    pub report_bundle_projection_checked: bool,
    pub evidence: RootAdapterFailureEvidence,
    pub expected_failure_kind: RootAdapterFailureKind,
}

impl AdapterFixtureCase {
    pub fn new(
        name: impl Into<String>,
        evidence: RootAdapterFailureEvidence,
        expected_failure_kind: RootAdapterFailureKind,
    ) -> Self {
        Self {
            name: name.into(),
            root_fixture_present: true,
            ledger_projection_checked: false,
            model_worker_projection_checked: false,
            report_bundle_projection_checked: false,
            evidence,
            expected_failure_kind,
        }
    }

    pub fn clean_success(name: impl Into<String>) -> Self {
        Self::new(
            name,
            RootAdapterFailureEvidence::clean(),
            RootAdapterFailureKind::None,
        )
        .with_all_projections_checked()
    }

    pub fn with_all_projections_checked(mut self) -> Self {
        self.ledger_projection_checked = true;
        self.model_worker_projection_checked = true;
        self.report_bundle_projection_checked = true;
        self
    }

    pub fn with_root_fixture_present(mut self, present: bool) -> Self {
        self.root_fixture_present = present;
        self
    }

    pub fn actual_failure_kind(&self) -> RootAdapterFailureKind {
        classify_root_adapter_failure(&self.evidence)
    }

    pub fn classification_matches(&self) -> bool {
        self.actual_failure_kind() == self.expected_failure_kind
    }

    pub fn expects_operational_as_quality_failure(&self) -> bool {
        matches!(
            self.actual_failure_kind(),
            RootAdapterFailureKind::ChainNotReady | RootAdapterFailureKind::ModelUnavailable
        ) && self.expected_failure_kind == RootAdapterFailureKind::ModelQualityFailure
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFixtureEvidence {
    pub cases: Vec<AdapterFixtureCase>,
}

impl AdapterFixtureEvidence {
    pub fn from_cases<I>(cases: I) -> Self
    where
        I: IntoIterator<Item = AdapterFixtureCase>,
    {
        Self {
            cases: cases.into_iter().collect(),
        }
    }

    pub fn fixture_count(&self) -> usize {
        self.cases.len()
    }

    pub fn case_names(&self) -> Vec<String> {
        self.cases.iter().map(|case| case.name.clone()).collect()
    }

    pub fn expected_failure_kinds(&self) -> Vec<&'static str> {
        self.cases
            .iter()
            .map(|case| case.expected_failure_kind.as_code())
            .collect()
    }

    pub fn actual_failure_kinds(&self) -> Vec<&'static str> {
        self.cases
            .iter()
            .map(|case| case.actual_failure_kind().as_code())
            .collect()
    }

    pub fn classification_mismatches(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| !case.classification_matches())
            .map(|case| {
                format!(
                    "{} expected {} but classified {}",
                    case.name,
                    case.expected_failure_kind.as_code(),
                    case.actual_failure_kind().as_code()
                )
            })
            .collect()
    }

    pub fn missing_required_kinds(
        &self,
        required_kinds: &[RootAdapterFailureKind],
    ) -> Vec<&'static str> {
        required_kinds
            .iter()
            .filter(|kind| {
                !self
                    .cases
                    .iter()
                    .any(|case| case.expected_failure_kind == **kind)
            })
            .map(RootAdapterFailureKind::as_code)
            .collect()
    }

    pub fn missing_root_fixture_cases(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| !case.root_fixture_present)
            .map(|case| case.name.clone())
            .collect()
    }

    pub fn missing_projection_cases(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| {
                !case.ledger_projection_checked
                    || !case.model_worker_projection_checked
                    || !case.report_bundle_projection_checked
            })
            .map(|case| case.name.clone())
            .collect()
    }

    pub fn operational_quality_confusions(&self) -> Vec<String> {
        self.cases
            .iter()
            .filter(|case| case.expects_operational_as_quality_failure())
            .map(|case| {
                format!(
                    "{} treats {} as model_quality_failure",
                    case.name,
                    case.actual_failure_kind().as_code()
                )
            })
            .collect()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterFixtureGate {
    pub stage: RootAdapterRolloutStage,
    pub required_failure_kinds: Vec<RootAdapterFailureKind>,
    pub require_root_fixture: bool,
    pub require_ledger_projection: bool,
    pub require_model_worker_projection: bool,
    pub require_report_bundle_projection: bool,
    pub forbid_operational_quality_confusion: bool,
}

impl AdapterFixtureGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            required_failure_kinds: vec![
                RootAdapterFailureKind::None,
                RootAdapterFailureKind::ChainNotReady,
                RootAdapterFailureKind::ModelUnavailable,
                RootAdapterFailureKind::StreamOrFinalMissing,
                RootAdapterFailureKind::RuntimeResponseMissing,
                RootAdapterFailureKind::ModelQualityFailure,
            ],
            require_root_fixture: true,
            require_ledger_projection: true,
            require_model_worker_projection: true,
            require_report_bundle_projection: true,
            forbid_operational_quality_confusion: true,
        }
    }

    pub fn evaluate(&self, evidence: &AdapterFixtureEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        let missing_kinds = evidence.missing_required_kinds(&self.required_failure_kinds);
        if !missing_kinds.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "adapter fixtures missing failure kinds: {}",
                missing_kinds.join(", ")
            )));
        }

        let mismatches = evidence.classification_mismatches();
        if !mismatches.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "adapter fixture classification mismatches: {}",
                mismatches.join("; ")
            )));
        }

        if self.require_root_fixture {
            let missing = evidence.missing_root_fixture_cases();
            if !missing.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "adapter fixtures missing root fixture evidence: {}",
                    missing.join(", ")
                )));
            }
        }

        if self.require_ledger_projection
            || self.require_model_worker_projection
            || self.require_report_bundle_projection
        {
            let missing = evidence.missing_projection_cases();
            if !missing.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "adapter fixtures missing projection checks: {}",
                    missing.join(", ")
                )));
            }
        }

        if self.forbid_operational_quality_confusion {
            let confused = evidence.operational_quality_confusions();
            if !confused.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "adapter fixtures confuse operational readiness with model quality: {}",
                    confused.join("; ")
                )));
            }
        }

        decision
    }
}

