impl CurrentRunnerCompatibilityReport {
    pub fn from_gate_and_evidence(
        gate: &CurrentRunnerCompatibilityGate,
        evidence: &CurrentRunnerCompatibilityEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            legacy_replay_passed: evidence.legacy_replay_passed,
            report_bundle_complete: evidence.report_bundle_complete,
            schema_drift_passed: evidence.schema_drift_passed,
            adapter_report_emission_passed: evidence.adapter_report_emission_passed,
            adapter_report_field_coverage_passed: evidence.adapter_report_field_coverage_passed,
            adapter_future_event_coverage_passed: evidence.adapter_future_event_coverage_passed,
            model_pool_development_window_passed: evidence.model_pool_development_window_passed,
            apple_silicon_development_effect_passed: evidence
                .apple_silicon_development_effect_passed,
            feedback_self_improve_passed: evidence.feedback_self_improve_passed,
            self_evolution_continuity_passed: evidence.self_evolution_continuity_passed,
            self_evolution_regression_passed: evidence.self_evolution_regression_passed,
            readiness_next_round_passed: evidence.readiness_next_round_passed,
            self_evolution_unattended_prerequisites_passed: evidence
                .self_evolution_unattended_prerequisites_passed,
            context_rot_trend_passed: evidence.context_rot_trend_passed,
            context_rot_remediation_passed: evidence.context_rot_remediation_passed,
            rollback_resume_passed: evidence.rollback_resume_passed,
            adapter_fixture_passed: evidence.adapter_fixture_passed,
            steam_case_matrix_passed: evidence.steam_case_matrix_passed,
            validation_command_coverage_passed: evidence.validation_command_coverage_passed,
            promotion_window_passed: evidence.promotion_window_passed,
            handoff_passed: evidence.handoff_passed,
            evolution_loop_tests_passed: evidence.evolution_loop_tests_passed,
            workspace_tests_passed: evidence.workspace_tests_passed,
            compatibility_blocked: decision.blocked,
            allow_enforced_wiring: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterCurrentRunnerCompatibilityBoundaryContract {
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl AdapterCurrentRunnerCompatibilityBoundaryContract {
    pub fn current_runner_compatibility_v1() -> Self {
        Self {
            entrypoints: vec![
                "CurrentRunnerCompatibilityEvidence::all_passed",
                "CurrentRunnerCompatibilityEvidence::crate_only",
                "CurrentRunnerCompatibilityEvidence::with_adapter_report_emission_report",
                "CurrentRunnerCompatibilityEvidence::with_adapter_report_field_coverage_from_report",
                "CurrentRunnerCompatibilityEvidence::with_adapter_future_event_coverage_report",
                "CurrentRunnerCompatibilityEvidence::with_report_bundle_gate_report",
                "CurrentRunnerCompatibilityEvidence::with_schema_drift_report",
                "CurrentRunnerCompatibilityEvidence::with_adapter_fixture_report",
                "CurrentRunnerCompatibilityEvidence::with_handoff_report_pass_bits",
                "CurrentRunnerCompatibilityGate::for_stage",
                "CurrentRunnerCompatibilityGate::evaluate",
                "CurrentRunnerCompatibilityReport::from_gate_and_evidence",
            ],
            allowed_inputs: vec![
                "RootAdapterRolloutStage",
                "CurrentRunnerCompatibilityGate",
                "CurrentRunnerCompatibilityEvidence",
                "AdapterReportEmissionReport",
                "AdapterFutureEventCoverageReport",
                "EvalReportBundleGateReport",
                "EvalSchemaDriftReport",
                "AdapterFixtureReport",
                "AdapterHandoffReport",
                "upstream_gate_pass_bits",
                "test_result_pass_bits",
            ],
            produced_outputs: vec![
                "CurrentRunnerCompatibilityEvidence",
                "GateDecision",
                "CurrentRunnerCompatibilityReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "file_io",
                "http_sse",
                "process_spawn",
                "cargo_test_execution",
                "workspace_test_execution",
                "evolution_loop_test_execution",
                "model_call",
                "runner_switch_execution",
                "runner_wiring_execution",
                "runner_state_mutation",
                "remote_mac_call",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.exposes_entrypoint("CurrentRunnerCompatibilityEvidence::all_passed")
            && self.exposes_entrypoint("CurrentRunnerCompatibilityEvidence::crate_only")
            && self.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_adapter_report_emission_report",
            )
            && self.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_adapter_report_field_coverage_from_report",
            )
            && self.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_adapter_future_event_coverage_report",
            )
            && self.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_report_bundle_gate_report",
            )
            && self
                .exposes_entrypoint("CurrentRunnerCompatibilityEvidence::with_schema_drift_report")
            && self.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_adapter_fixture_report",
            )
            && self
                .exposes_entrypoint("CurrentRunnerCompatibilityEvidence::with_handoff_report_pass_bits")
            && self.exposes_entrypoint("CurrentRunnerCompatibilityGate::for_stage")
            && self.exposes_entrypoint("CurrentRunnerCompatibilityGate::evaluate")
            && self
                .exposes_entrypoint("CurrentRunnerCompatibilityReport::from_gate_and_evidence")
            && self.allows_input("RootAdapterRolloutStage")
            && self.allows_input("CurrentRunnerCompatibilityGate")
            && self.allows_input("CurrentRunnerCompatibilityEvidence")
            && self.allows_input("AdapterReportEmissionReport")
            && self.allows_input("AdapterFutureEventCoverageReport")
            && self.allows_input("EvalReportBundleGateReport")
            && self.allows_input("EvalSchemaDriftReport")
            && self.allows_input("AdapterFixtureReport")
            && self.allows_input("AdapterHandoffReport")
            && self.allows_input("upstream_gate_pass_bits")
            && self.allows_input("test_result_pass_bits")
            && !self.allows_input("CommandExecutor")
            && !self.allows_input("EvolutionLoopRunner")
            && !self.allows_input("RunnerSwitcher")
            && !self.allows_input("JsonlReader")
            && self.produces_output("CurrentRunnerCompatibilityEvidence")
            && self.produces_output("GateDecision")
            && self.produces_output("CurrentRunnerCompatibilityReport")
            && [
                "jsonl_io",
                "file_io",
                "http_sse",
                "process_spawn",
                "cargo_test_execution",
                "workspace_test_execution",
                "evolution_loop_test_execution",
                "model_call",
                "runner_switch_execution",
                "runner_wiring_execution",
                "runner_state_mutation",
                "remote_mac_call",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RootAdapterAcceptanceContract {
    pub stage: RootAdapterRolloutStage,
    pub root_plan: RootBusinessCycleAdapterPlan,
    pub report_schema: ModelPoolReportSchema,
    pub worker_event_schema: WorkerEventSchema,
    pub test_gates: Vec<AdapterTestGate>,
}

impl RootAdapterAcceptanceContract {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            root_plan: RootBusinessCycleAdapterPlan::root_business_cycle_json(),
            report_schema: ModelPoolReportSchema::apple_silicon_development(),
            worker_event_schema: WorkerEventSchema::model_worker_v1(),
            test_gates: vec![
                AdapterTestGate {
                    name: "norion-test",
                    command: "cargo test --manifest-path crates/norion-test/Cargo.toml",
                    required_evidence: "adapter acceptance plan remains data-only",
                },
                AdapterTestGate {
                    name: "norion-eval",
                    command: "cargo test --manifest-path crates/norion-eval/Cargo.toml",
                    required_evidence: "root adapter acceptance contract and attribution tests pass",
                },
                AdapterTestGate {
                    name: "evolution-loop",
                    command: "cargo test --manifest-path tools/evolution-loop/Cargo.toml",
                    required_evidence: "required before the adapter can block the current runner",
                },
                AdapterTestGate {
                    name: "workspace",
                    command: "cargo test --workspace",
                    required_evidence: "required before enforced root adapter rollout",
                },
            ],
        }
    }

    pub fn shadow_only() -> Self {
        Self::for_stage(RootAdapterRolloutStage::ShadowOnly)
    }

    pub fn report_only() -> Self {
        Self::for_stage(RootAdapterRolloutStage::ReportOnly)
    }

    pub fn enforced() -> Self {
        Self::for_stage(RootAdapterRolloutStage::Enforced)
    }

    pub fn blocks_current_runner(&self) -> bool {
        self.stage == RootAdapterRolloutStage::Enforced
    }

    pub fn requires_outage_attribution(&self) -> bool {
        self.stage != RootAdapterRolloutStage::ShadowOnly
    }

    pub fn report_fields_for_stage(&self) -> Vec<&ReportSchemaField> {
        match self.stage {
            RootAdapterRolloutStage::ShadowOnly => Vec::new(),
            RootAdapterRolloutStage::ReportOnly => self
                .report_schema
                .fields
                .iter()
                .filter(|field| field.stage == ReportSchemaStage::ReportOnly)
                .collect(),
            RootAdapterRolloutStage::Enforced => self.report_schema.fields.iter().collect(),
        }
    }

    pub fn worker_event_fields_for_stage(&self) -> Vec<&WorkerEventField> {
        match self.stage {
            RootAdapterRolloutStage::ShadowOnly | RootAdapterRolloutStage::ReportOnly => {
                self.worker_event_schema.required_for_projection()
            }
            RootAdapterRolloutStage::Enforced => {
                self.worker_event_schema.required_for_enforcement()
            }
        }
    }

    pub fn enforceable_root_mappings(&self) -> Vec<&RootBusinessCycleFieldMapping> {
        if self.stage == RootAdapterRolloutStage::Enforced {
            self.root_plan.strong_mappings()
        } else {
            Vec::new()
        }
    }

    pub fn model_quality_failure_allowed(&self, evidence: &RootAdapterFailureEvidence) -> bool {
        self.stage == RootAdapterRolloutStage::Enforced
            && classify_root_adapter_failure(evidence)
                == RootAdapterFailureKind::ModelQualityFailure
    }
}

