#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconDevelopmentGate {
    pub max_latency_multiplier: f64,
    pub max_token_multiplier: f64,
    pub require_success_not_regressed: bool,
    pub require_validation_not_regressed: bool,
    pub min_feedback_delta: i64,
    pub max_duplicate_outputs: usize,
    pub max_noisy_outputs: usize,
    pub max_primary_12b_blockers: usize,
}

impl AppleSiliconDevelopmentGate {
    pub fn conservative() -> Self {
        Self {
            max_latency_multiplier: 1.5,
            max_token_multiplier: 2.0,
            require_success_not_regressed: true,
            require_validation_not_regressed: true,
            min_feedback_delta: 1,
            max_duplicate_outputs: 0,
            max_noisy_outputs: 0,
            max_primary_12b_blockers: 0,
        }
    }

    pub fn evaluate(&self, effect: &ModelPoolDevelopmentEffect) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_success_not_regressed
            && effect.baseline_12b_success
            && effect.pool_success_rate < 1.0
        {
            decision = decision.merge(GateDecision::block(format!(
                "model pool success rate {:.3} regressed below 12B baseline",
                effect.pool_success_rate
            )));
        }
        if self.require_validation_not_regressed
            && effect.baseline_12b_validation_passed
            && effect.pool_validation_pass_rate < 1.0
        {
            decision = decision.merge(GateDecision::block(format!(
                "model pool validation pass rate {:.3} regressed below 12B baseline",
                effect.pool_validation_pass_rate
            )));
        }
        let feedback_delta =
            effect.pool_feedback_applied_total as i64 - effect.baseline_12b_feedback_applied as i64;
        if feedback_delta < self.min_feedback_delta {
            decision = decision.merge(GateDecision::block(format!(
                "model pool feedback delta {} below minimum {}",
                feedback_delta, self.min_feedback_delta
            )));
        }
        if exceeds_multiplier(
            effect.pool_latency_ms_total,
            effect.baseline_12b_latency_ms,
            self.max_latency_multiplier,
        ) {
            decision = decision.merge(GateDecision::block(format!(
                "model pool latency {}ms above {:.2}x 12B baseline {}ms",
                effect.pool_latency_ms_total,
                self.max_latency_multiplier,
                effect.baseline_12b_latency_ms
            )));
        }
        if exceeds_multiplier(
            effect.pool_runtime_tokens_total,
            effect.baseline_12b_runtime_tokens,
            self.max_token_multiplier,
        ) {
            decision = decision.merge(GateDecision::block(format!(
                "model pool runtime tokens {} above {:.2}x 12B baseline {}",
                effect.pool_runtime_tokens_total,
                self.max_token_multiplier,
                effect.baseline_12b_runtime_tokens
            )));
        }
        if effect.duplicate_outputs > self.max_duplicate_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "model pool duplicate outputs {} above maximum {}",
                effect.duplicate_outputs, self.max_duplicate_outputs
            )));
        }
        if effect.noisy_outputs > self.max_noisy_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "model pool noisy outputs {} above maximum {}",
                effect.noisy_outputs, self.max_noisy_outputs
            )));
        }
        if effect.primary_12b_blockers > self.max_primary_12b_blockers {
            decision = decision.merge(GateDecision::block(format!(
                "model pool primary 12B blockers {} above maximum {}",
                effect.primary_12b_blockers, self.max_primary_12b_blockers
            )));
        }
        decision
    }
}

