#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalReportBundleManifest {
    pub stage: RootAdapterRolloutStage,
    pub schema_names: Vec<&'static str>,
}

impl EvalReportBundleManifest {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        let manifest = EvalSchemaManifest::evolution_loop_handoff_v1();
        let schema_names = match stage {
            RootAdapterRolloutStage::ShadowOnly => Vec::new(),
            RootAdapterRolloutStage::ReportOnly => manifest
                .entries
                .iter()
                .filter(|entry| entry.stage == ReportSchemaStage::ReportOnly)
                .map(|entry| entry.name)
                .collect(),
            RootAdapterRolloutStage::Enforced => manifest.names(),
        };

        Self {
            stage,
            schema_names,
        }
    }

    pub fn includes(&self, schema_name: &str) -> bool {
        self.schema_names.contains(&schema_name)
    }

    pub fn missing_from(&self, evidence: &EvalReportBundleEvidence) -> Vec<&'static str> {
        self.schema_names
            .iter()
            .copied()
            .filter(|schema| !evidence.includes(schema))
            .collect()
    }

    pub fn evaluate_bundle(&self, evidence: &EvalReportBundleEvidence) -> GateDecision {
        let missing = self.missing_from(evidence);
        let mut decision = GateDecision::pass();
        if !missing.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "report bundle missing required schemas: {}",
                missing.join(", ")
            )));
        }
        if self.stage == RootAdapterRolloutStage::Enforced
            && !evidence.adapter_report_field_coverage_passed
        {
            decision = decision.merge(GateDecision::block(
                "report bundle adapter report field coverage did not pass",
            ));
        }
        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalReportBundleEvidence {
    pub observed_schema_names: Vec<String>,
    pub adapter_report_field_coverage_passed: bool,
}

impl EvalReportBundleEvidence {
    pub fn from_schema_names<I, S>(names: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        Self {
            observed_schema_names: names.into_iter().map(Into::into).collect(),
            adapter_report_field_coverage_passed: true,
        }
    }

    pub fn empty() -> Self {
        Self {
            observed_schema_names: Vec::new(),
            adapter_report_field_coverage_passed: true,
        }
    }

    pub fn includes(&self, schema_name: &str) -> bool {
        self.observed_schema_names
            .iter()
            .any(|observed| observed == schema_name)
    }

    pub fn with_adapter_report_field_coverage_passed(mut self, passed: bool) -> Self {
        self.adapter_report_field_coverage_passed = passed;
        self
    }

    pub fn with_adapter_report_field_coverage_from_report(
        mut self,
        report: &AdapterReportEmissionReport,
    ) -> Self {
        self.adapter_report_field_coverage_passed = report.field_coverage_passed();
        self
    }

    pub fn from_adapter_report_emission_report(report: &AdapterReportEmissionReport) -> Self {
        Self {
            observed_schema_names: report.observed_report_schema_names.clone(),
            adapter_report_field_coverage_passed: report.field_coverage_passed(),
        }
    }
}

