#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalReportBundleGateReport {
    pub stage: &'static str,
    pub expected_schema_names: Vec<&'static str>,
    pub observed_schema_names: Vec<String>,
    pub missing_schema_names: Vec<&'static str>,
    pub adapter_report_field_coverage_passed: bool,
    pub bundle_blocked: bool,
    pub failure_reasons: Vec<String>,
    pub complete: bool,
}

impl EvalReportBundleGateReport {
    pub fn from_manifest_and_evidence(
        manifest: &EvalReportBundleManifest,
        evidence: &EvalReportBundleEvidence,
    ) -> Self {
        let decision = manifest.evaluate_bundle(evidence);

        Self {
            stage: manifest.stage.as_str(),
            expected_schema_names: manifest.schema_names.clone(),
            observed_schema_names: evidence.observed_schema_names.clone(),
            missing_schema_names: manifest.missing_from(evidence),
            adapter_report_field_coverage_passed: evidence.adapter_report_field_coverage_passed,
            bundle_blocked: decision.blocked,
            complete: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_manifest_and_adapter_report_emission_report(
        manifest: &EvalReportBundleManifest,
        report: &AdapterReportEmissionReport,
    ) -> Self {
        let evidence = EvalReportBundleEvidence::from_adapter_report_emission_report(report);
        Self::from_manifest_and_evidence(manifest, &evidence)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterReportBundleGateBoundaryContract {
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl AdapterReportBundleGateBoundaryContract {
    pub fn report_bundle_gate_v1() -> Self {
        Self {
            entrypoints: vec![
                "EvalReportBundleManifest::for_stage",
                "EvalReportBundleEvidence::from_schema_names",
                "EvalReportBundleEvidence::with_adapter_report_field_coverage_from_report",
                "EvalReportBundleEvidence::from_adapter_report_emission_report",
                "EvalReportBundleManifest::evaluate_bundle",
                "EvalReportBundleGateReport::from_manifest_and_evidence",
                "EvalReportBundleGateReport::from_manifest_and_adapter_report_emission_report",
            ],
            allowed_inputs: vec![
                "RootAdapterRolloutStage",
                "observed_schema_names",
                "EvalReportBundleManifest",
                "EvalReportBundleEvidence",
                "adapter_report_field_coverage_passed",
                "AdapterReportEmissionReport::field_coverage_passed",
                "AdapterReportEmissionReport",
            ],
            produced_outputs: vec![
                "EvalReportBundleManifest",
                "EvalReportBundleEvidence",
                "GateDecision",
                "EvalReportBundleGateReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "file_io",
                "report_directory_scan",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.exposes_entrypoint("EvalReportBundleManifest::for_stage")
            && self.exposes_entrypoint("EvalReportBundleEvidence::from_schema_names")
            && self.exposes_entrypoint(
                "EvalReportBundleEvidence::with_adapter_report_field_coverage_from_report",
            )
            && self
                .exposes_entrypoint("EvalReportBundleEvidence::from_adapter_report_emission_report")
            && self.exposes_entrypoint("EvalReportBundleManifest::evaluate_bundle")
            && self.exposes_entrypoint("EvalReportBundleGateReport::from_manifest_and_evidence")
            && self.exposes_entrypoint(
                "EvalReportBundleGateReport::from_manifest_and_adapter_report_emission_report",
            )
            && self.allows_input("RootAdapterRolloutStage")
            && self.allows_input("observed_schema_names")
            && self.allows_input("EvalReportBundleManifest")
            && self.allows_input("EvalReportBundleEvidence")
            && self.allows_input("adapter_report_field_coverage_passed")
            && self.allows_input("AdapterReportEmissionReport::field_coverage_passed")
            && self.allows_input("AdapterReportEmissionReport")
            && !self.allows_input("ReportDirectoryScanner")
            && !self.allows_input("JsonlReader")
            && !self.allows_input("EvolutionLoopRunner")
            && self.produces_output("EvalReportBundleManifest")
            && self.produces_output("EvalReportBundleEvidence")
            && self.produces_output("GateDecision")
            && self.produces_output("EvalReportBundleGateReport")
            && [
                "jsonl_io",
                "file_io",
                "report_directory_scan",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalSchemaFingerprint {
    pub schema_count: usize,
    pub canonical_schema_names: Vec<String>,
    pub checksum: String,
}

impl EvalSchemaFingerprint {
    pub fn from_schema_names<I, S>(names: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: AsRef<str>,
    {
        let mut canonical_schema_names = names
            .into_iter()
            .map(|name| name.as_ref().to_owned())
            .collect::<Vec<_>>();
        canonical_schema_names.sort();

        Self {
            schema_count: canonical_schema_names.len(),
            checksum: stable_schema_checksum(&canonical_schema_names),
            canonical_schema_names,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalSchemaDriftEvidence {
    pub stage: RootAdapterRolloutStage,
    pub manifest_schema_names: Vec<&'static str>,
    pub bundle_schema_names: Vec<&'static str>,
    pub checklist_schema_names: Vec<&'static str>,
    pub manifest_report_field_names: Vec<&'static str>,
    pub adapter_emission_report_field_names: Vec<&'static str>,
}

impl EvalSchemaDriftEvidence {
    pub fn from_current_contracts(stage: RootAdapterRolloutStage) -> Self {
        let manifest = EvalSchemaManifest::evolution_loop_handoff_v1();
        let bundle = EvalReportBundleManifest::for_stage(stage);
        let checklist = AdapterHandoffChecklist::before_runner_wiring(stage);
        let adapter_emission_plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let report_field_names = adapter_emission_plan.required_report_fields();

        Self {
            stage,
            manifest_schema_names: manifest.names_for_stage(stage),
            bundle_schema_names: bundle.schema_names,
            checklist_schema_names: checklist.required_schemas,
            manifest_report_field_names: report_field_names.clone(),
            adapter_emission_report_field_names: report_field_names,
        }
    }

    pub fn from_adapter_closure_schema_document(
        stage: RootAdapterRolloutStage,
        document: &AdapterClosureSchemaDocument,
    ) -> Self {
        let manifest = EvalSchemaManifest::evolution_loop_handoff_v1();
        let bundle = EvalReportBundleManifest::for_stage(stage);
        let checklist = AdapterHandoffChecklist::before_runner_wiring(stage);
        let adapter_emission_plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let adapter_closure_report_fields = adapter_emission_plan
            .required_report_fields()
            .into_iter()
            .filter(|field| field.starts_with("adapter_closure."))
            .collect::<Vec<_>>();

        Self {
            stage,
            manifest_schema_names: manifest.names_for_stage(stage),
            bundle_schema_names: bundle.schema_names,
            checklist_schema_names: checklist.required_schemas,
            manifest_report_field_names: document.field_names.clone(),
            adapter_emission_report_field_names: adapter_closure_report_fields,
        }
    }

    pub fn with_adapter_report_field_coverage_from_report(
        mut self,
        report: &AdapterReportEmissionReport,
    ) -> Self {
        self.adapter_emission_report_field_names
            .retain(|field| !report.missing_report_fields.contains(field));
        self
    }

    pub fn manifest_fingerprint(&self) -> EvalSchemaFingerprint {
        EvalSchemaFingerprint::from_schema_names(self.manifest_schema_names.iter().copied())
    }

    pub fn bundle_fingerprint(&self) -> EvalSchemaFingerprint {
        EvalSchemaFingerprint::from_schema_names(self.bundle_schema_names.iter().copied())
    }

    pub fn checklist_fingerprint(&self) -> EvalSchemaFingerprint {
        EvalSchemaFingerprint::from_schema_names(self.checklist_schema_names.iter().copied())
    }

    pub fn manifest_report_field_fingerprint(&self) -> EvalSchemaFingerprint {
        EvalSchemaFingerprint::from_schema_names(self.manifest_report_field_names.iter().copied())
    }

    pub fn adapter_emission_report_field_fingerprint(&self) -> EvalSchemaFingerprint {
        EvalSchemaFingerprint::from_schema_names(
            self.adapter_emission_report_field_names.iter().copied(),
        )
    }

    pub fn bundle_missing_schema_names(&self) -> Vec<String> {
        missing_schema_names(&self.manifest_fingerprint(), &self.bundle_fingerprint())
    }

    pub fn bundle_extra_schema_names(&self) -> Vec<String> {
        extra_schema_names(&self.manifest_fingerprint(), &self.bundle_fingerprint())
    }

    pub fn checklist_missing_schema_names(&self) -> Vec<String> {
        missing_schema_names(&self.manifest_fingerprint(), &self.checklist_fingerprint())
    }

    pub fn checklist_extra_schema_names(&self) -> Vec<String> {
        extra_schema_names(&self.manifest_fingerprint(), &self.checklist_fingerprint())
    }

    pub fn missing_report_field_names(&self) -> Vec<String> {
        missing_schema_names(
            &self.manifest_report_field_fingerprint(),
            &self.adapter_emission_report_field_fingerprint(),
        )
    }

    pub fn extra_report_field_names(&self) -> Vec<String> {
        extra_schema_names(
            &self.manifest_report_field_fingerprint(),
            &self.adapter_emission_report_field_fingerprint(),
        )
    }

    pub fn duplicate_schema_names(&self) -> Vec<String> {
        let mut duplicates = duplicate_names(&self.manifest_fingerprint().canonical_schema_names);
        duplicates.extend(duplicate_names(
            &self.bundle_fingerprint().canonical_schema_names,
        ));
        duplicates.extend(duplicate_names(
            &self.checklist_fingerprint().canonical_schema_names,
        ));
        duplicates.sort();
        duplicates.dedup();
        duplicates
    }

    pub fn duplicate_report_field_names(&self) -> Vec<String> {
        let mut duplicates = duplicate_names(
            &self
                .manifest_report_field_fingerprint()
                .canonical_schema_names,
        );
        duplicates.extend(duplicate_names(
            &self
                .adapter_emission_report_field_fingerprint()
                .canonical_schema_names,
        ));
        duplicates.sort();
        duplicates.dedup();
        duplicates
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalSchemaDriftGate {
    pub stage: RootAdapterRolloutStage,
}

impl EvalSchemaDriftGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self { stage }
    }

    pub fn evaluate(&self, evidence: &EvalSchemaDriftEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        let bundle_missing = evidence.bundle_missing_schema_names();
        if !bundle_missing.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "report bundle missing manifest schemas: {}",
                bundle_missing.join(", ")
            )));
        }

        let bundle_extra = evidence.bundle_extra_schema_names();
        if !bundle_extra.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "report bundle has schemas outside manifest: {}",
                bundle_extra.join(", ")
            )));
        }

        let checklist_missing = evidence.checklist_missing_schema_names();
        if !checklist_missing.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "handoff checklist missing manifest schemas: {}",
                checklist_missing.join(", ")
            )));
        }

        let checklist_extra = evidence.checklist_extra_schema_names();
        if !checklist_extra.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "handoff checklist has schemas outside manifest: {}",
                checklist_extra.join(", ")
            )));
        }

        let duplicates = evidence.duplicate_schema_names();
        if !duplicates.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "schema lists contain duplicate names: {}",
                duplicates.join(", ")
            )));
        }

        let missing_report_fields = evidence.missing_report_field_names();
        if !missing_report_fields.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "adapter report field contract missing fields: {}",
                missing_report_fields.join(", ")
            )));
        }

        let extra_report_fields = evidence.extra_report_field_names();
        if !extra_report_fields.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "adapter report field contract has fields outside manifest: {}",
                extra_report_fields.join(", ")
            )));
        }

        let duplicate_report_fields = evidence.duplicate_report_field_names();
        if !duplicate_report_fields.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "adapter report field contract contains duplicate fields: {}",
                duplicate_report_fields.join(", ")
            )));
        }

        decision
    }
}

