#[derive(Debug, Clone, PartialEq, Eq)]
pub struct EvalSchemaDriftReport {
    pub stage: &'static str,
    pub manifest_schema_names: Vec<&'static str>,
    pub bundle_schema_names: Vec<&'static str>,
    pub checklist_schema_names: Vec<&'static str>,
    pub manifest_checksum: String,
    pub bundle_checksum: String,
    pub checklist_checksum: String,
    pub manifest_report_field_checksum: String,
    pub adapter_emission_report_field_checksum: String,
    pub bundle_missing_schema_names: Vec<String>,
    pub bundle_extra_schema_names: Vec<String>,
    pub checklist_missing_schema_names: Vec<String>,
    pub checklist_extra_schema_names: Vec<String>,
    pub duplicate_schema_names: Vec<String>,
    pub missing_report_field_names: Vec<String>,
    pub extra_report_field_names: Vec<String>,
    pub duplicate_report_field_names: Vec<String>,
    pub drift_blocked: bool,
    pub failure_reasons: Vec<String>,
    pub allow_runner_wiring: bool,
}

impl EvalSchemaDriftReport {
    pub fn from_gate_and_evidence(
        gate: &EvalSchemaDriftGate,
        evidence: &EvalSchemaDriftEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            manifest_schema_names: evidence.manifest_schema_names.clone(),
            bundle_schema_names: evidence.bundle_schema_names.clone(),
            checklist_schema_names: evidence.checklist_schema_names.clone(),
            manifest_checksum: evidence.manifest_fingerprint().checksum,
            bundle_checksum: evidence.bundle_fingerprint().checksum,
            checklist_checksum: evidence.checklist_fingerprint().checksum,
            manifest_report_field_checksum: evidence.manifest_report_field_fingerprint().checksum,
            adapter_emission_report_field_checksum: evidence
                .adapter_emission_report_field_fingerprint()
                .checksum,
            bundle_missing_schema_names: evidence.bundle_missing_schema_names(),
            bundle_extra_schema_names: evidence.bundle_extra_schema_names(),
            checklist_missing_schema_names: evidence.checklist_missing_schema_names(),
            checklist_extra_schema_names: evidence.checklist_extra_schema_names(),
            duplicate_schema_names: evidence.duplicate_schema_names(),
            missing_report_field_names: evidence.missing_report_field_names(),
            extra_report_field_names: evidence.extra_report_field_names(),
            duplicate_report_field_names: evidence.duplicate_report_field_names(),
            drift_blocked: decision.blocked,
            allow_runner_wiring: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AdapterSchemaDriftBoundaryContract {
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl AdapterSchemaDriftBoundaryContract {
    pub fn schema_drift_v1() -> Self {
        Self {
            entrypoints: vec![
                "EvalSchemaDriftEvidence::from_current_contracts",
                "EvalSchemaDriftEvidence::from_adapter_closure_schema_document",
                "EvalSchemaDriftEvidence::with_adapter_report_field_coverage_from_report",
                "EvalSchemaFingerprint::from_schema_names",
                "EvalSchemaDriftGate::evaluate",
                "EvalSchemaDriftReport::from_gate_and_evidence",
            ],
            allowed_inputs: vec![
                "RootAdapterRolloutStage",
                "EvalSchemaManifest",
                "EvalReportBundleManifest",
                "AdapterHandoffChecklist",
                "AdapterReportEmissionPlan::required_report_fields",
                "AdapterClosureSchemaDocument",
                "AdapterReportEmissionReport",
                "EvalSchemaDriftEvidence",
                "EvalSchemaDriftGate",
            ],
            produced_outputs: vec![
                "EvalSchemaFingerprint",
                "EvalSchemaDriftEvidence",
                "GateDecision",
                "EvalSchemaDriftReport",
            ],
            forbidden_capabilities: vec![
                "jsonl_io",
                "file_io",
                "schema_file_read",
                "report_directory_scan",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.exposes_entrypoint("EvalSchemaDriftEvidence::from_current_contracts")
            && self
                .exposes_entrypoint("EvalSchemaDriftEvidence::from_adapter_closure_schema_document")
            && self.exposes_entrypoint(
                "EvalSchemaDriftEvidence::with_adapter_report_field_coverage_from_report",
            )
            && self.exposes_entrypoint("EvalSchemaFingerprint::from_schema_names")
            && self.exposes_entrypoint("EvalSchemaDriftGate::evaluate")
            && self.exposes_entrypoint("EvalSchemaDriftReport::from_gate_and_evidence")
            && self.allows_input("RootAdapterRolloutStage")
            && self.allows_input("EvalSchemaManifest")
            && self.allows_input("EvalReportBundleManifest")
            && self.allows_input("AdapterHandoffChecklist")
            && self.allows_input("AdapterReportEmissionPlan::required_report_fields")
            && self.allows_input("AdapterClosureSchemaDocument")
            && self.allows_input("AdapterReportEmissionReport")
            && self.allows_input("EvalSchemaDriftEvidence")
            && self.allows_input("EvalSchemaDriftGate")
            && !self.allows_input("SchemaFileReader")
            && !self.allows_input("ReportDirectoryScanner")
            && !self.allows_input("EvolutionLoopRunner")
            && self.produces_output("EvalSchemaFingerprint")
            && self.produces_output("EvalSchemaDriftEvidence")
            && self.produces_output("GateDecision")
            && self.produces_output("EvalSchemaDriftReport")
            && [
                "jsonl_io",
                "file_io",
                "schema_file_read",
                "report_directory_scan",
                "http_sse",
                "process_spawn",
                "validation_command_spawn",
                "model_call",
                "runner_state",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

fn stable_schema_checksum(schema_names: &[String]) -> String {
    let mut hash = 0xcbf2_9ce4_8422_2325_u64;
    for byte in schema_names.join("|").bytes() {
        hash ^= u64::from(byte);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    format!("{hash:016x}")
}

fn missing_schema_names(
    expected: &EvalSchemaFingerprint,
    observed: &EvalSchemaFingerprint,
) -> Vec<String> {
    expected
        .canonical_schema_names
        .iter()
        .filter(|name| !observed.canonical_schema_names.contains(name))
        .cloned()
        .collect()
}

fn extra_schema_names(
    expected: &EvalSchemaFingerprint,
    observed: &EvalSchemaFingerprint,
) -> Vec<String> {
    observed
        .canonical_schema_names
        .iter()
        .filter(|name| !expected.canonical_schema_names.contains(name))
        .cloned()
        .collect()
}

fn duplicate_names(sorted_names: &[String]) -> Vec<String> {
    let mut duplicates = sorted_names
        .windows(2)
        .filter_map(|pair| {
            if pair[0] == pair[1] {
                Some(pair[0].clone())
            } else {
                None
            }
        })
        .collect::<Vec<_>>();
    duplicates.dedup();
    duplicates
}

