impl ReportFreshnessReport {
    pub fn from_status_and_ledger_gate(
        status: &ReportFreshnessStatus,
        ledger_gate: &LedgerGateReport,
    ) -> Self {
        let mut failure_reasons = Vec::new();

        if status.rounds != ledger_gate.total_rounds {
            failure_reasons.push(format!(
                "report refresh rounds {} do not match ledger gate total_rounds {}",
                status.rounds, ledger_gate.total_rounds
            ));
        }
        if status.ledger_lag > 0 {
            failure_reasons.push(format!(
                "report refresh ledger_lag {} above maximum 0",
                status.ledger_lag
            ));
        }
        if status.stale {
            failure_reasons.push("report refresh marked stale".to_owned());
        }
        if status.gate_failures > 0 {
            failure_reasons.push(format!(
                "report refresh gate_failures {} above maximum 0",
                status.gate_failures
            ));
        }

        let freshness_blocked = !failure_reasons.is_empty();

        Self {
            rounds: status.rounds,
            ledger_lag: status.ledger_lag,
            stale: status.stale,
            gate_failures: status.gate_failures,
            ledger_gate_total_rounds: ledger_gate.total_rounds,
            ledger_gate_blocked: ledger_gate.gate_blocked,
            ledger_gate_allow_next_round: ledger_gate.allow_next_round,
            freshness_blocked,
            allow_report_refresh: !freshness_blocked,
            failure_reasons,
        }
    }
}

