#[derive(Debug, Clone, PartialEq)]
pub struct ModelPoolDevelopmentReport {
    pub workers: usize,
    pub successful_workers: usize,
    pub success_rate: f64,
    pub validation_checked: usize,
    pub validation_passed: usize,
    pub validation_pass_rate: f64,
    pub latency_ms_total: u64,
    pub latency_ms_max: u64,
    pub runtime_tokens_total: u64,
    pub runtime_tokens_max: u64,
    pub feedback_applied_total: u64,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub operational_readiness_failures: usize,
    pub model_quality_failures: usize,
    pub feedback_delta: i64,
    pub latency_multiplier: f64,
    pub token_multiplier: f64,
    pub pool_gate_blocked: bool,
    pub development_gate_blocked: bool,
    pub failure_reasons: Vec<String>,
    pub root_adapter_failure_kind: &'static str,
}

impl ModelPoolDevelopmentReport {
    pub fn from_summary_effect_and_decisions(
        summary: &ModelPoolSummary,
        effect: &ModelPoolDevelopmentEffect,
        pool_decision: &GateDecision,
        development_decision: &GateDecision,
        root_adapter_failure: RootAdapterFailureKind,
    ) -> Self {
        let mut failure_reasons = pool_decision.reasons.clone();
        failure_reasons.extend(development_decision.reasons.clone());

        Self {
            workers: summary.workers,
            successful_workers: summary.successful_workers,
            success_rate: summary.success_rate(),
            validation_checked: summary.validation_checked,
            validation_passed: summary.validation_passed,
            validation_pass_rate: summary.validation_pass_rate(),
            latency_ms_total: summary.latency_ms_total,
            latency_ms_max: summary.latency_ms_max,
            runtime_tokens_total: summary.runtime_tokens_total,
            runtime_tokens_max: summary.runtime_tokens_max,
            feedback_applied_total: summary.feedback_applied_total,
            duplicate_outputs: summary.duplicate_outputs,
            noisy_outputs: summary.noisy_outputs,
            primary_12b_blockers: summary.primary_12b_blockers,
            operational_readiness_failures: summary.operational_readiness_failures,
            model_quality_failures: summary.model_quality_failures,
            feedback_delta: effect.pool_feedback_applied_total as i64
                - effect.baseline_12b_feedback_applied as i64,
            latency_multiplier: multiplier(
                effect.pool_latency_ms_total,
                effect.baseline_12b_latency_ms,
            ),
            token_multiplier: multiplier(
                effect.pool_runtime_tokens_total,
                effect.baseline_12b_runtime_tokens,
            ),
            pool_gate_blocked: pool_decision.blocked,
            development_gate_blocked: development_decision.blocked,
            failure_reasons,
            root_adapter_failure_kind: root_adapter_failure.as_code(),
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ModelPoolDevelopmentWindowRecord {
    pub round: u64,
    pub feedback_delta: i64,
    pub latency_multiplier: f64,
    pub token_multiplier: f64,
    pub pool_gate_blocked: bool,
    pub development_gate_blocked: bool,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub root_adapter_failure_kind: &'static str,
}

impl ModelPoolDevelopmentWindowRecord {
    pub fn from_report(round: u64, report: &ModelPoolDevelopmentReport) -> Self {
        Self {
            round,
            feedback_delta: report.feedback_delta,
            latency_multiplier: report.latency_multiplier,
            token_multiplier: report.token_multiplier,
            pool_gate_blocked: report.pool_gate_blocked,
            development_gate_blocked: report.development_gate_blocked,
            duplicate_outputs: report.duplicate_outputs,
            noisy_outputs: report.noisy_outputs,
            primary_12b_blockers: report.primary_12b_blockers,
            root_adapter_failure_kind: report.root_adapter_failure_kind,
        }
    }

    pub fn allows_development_claim(&self) -> bool {
        self.feedback_delta > 0
            && !self.pool_gate_blocked
            && !self.development_gate_blocked
            && self.duplicate_outputs == 0
            && self.noisy_outputs == 0
            && self.primary_12b_blockers == 0
            && self.root_adapter_failure_kind == RootAdapterFailureKind::None.as_code()
    }

    pub fn is_operational_readiness_failure(&self) -> bool {
        self.root_adapter_failure_kind == RootAdapterFailureKind::ChainNotReady.as_code()
            || self.root_adapter_failure_kind == RootAdapterFailureKind::ModelUnavailable.as_code()
    }

    pub fn is_model_quality_failure(&self) -> bool {
        self.root_adapter_failure_kind == RootAdapterFailureKind::ModelQualityFailure.as_code()
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ModelPoolDevelopmentWindowSummary {
    pub rounds: usize,
    pub first_round: Option<u64>,
    pub last_round: Option<u64>,
    pub development_claim_rounds: usize,
    pub blocked_rounds: usize,
    pub operational_readiness_rounds: usize,
    pub model_quality_failure_rounds: usize,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub feedback_delta_total: i64,
    pub max_latency_multiplier: f64,
    pub max_token_multiplier: f64,
}

impl ModelPoolDevelopmentWindowSummary {
    pub fn from_records(records: &[ModelPoolDevelopmentWindowRecord]) -> Self {
        let mut summary = Self {
            rounds: records.len(),
            first_round: records.first().map(|record| record.round),
            last_round: records.last().map(|record| record.round),
            development_claim_rounds: 0,
            blocked_rounds: 0,
            operational_readiness_rounds: 0,
            model_quality_failure_rounds: 0,
            duplicate_outputs: 0,
            noisy_outputs: 0,
            primary_12b_blockers: 0,
            feedback_delta_total: 0,
            max_latency_multiplier: 0.0,
            max_token_multiplier: 0.0,
        };

        for record in records {
            if record.allows_development_claim() {
                summary.development_claim_rounds += 1;
            }
            if record.pool_gate_blocked || record.development_gate_blocked {
                summary.blocked_rounds += 1;
            }
            if record.is_operational_readiness_failure() {
                summary.operational_readiness_rounds += 1;
            }
            if record.is_model_quality_failure() {
                summary.model_quality_failure_rounds += 1;
            }
            summary.duplicate_outputs += record.duplicate_outputs;
            summary.noisy_outputs += record.noisy_outputs;
            summary.primary_12b_blockers += record.primary_12b_blockers;
            summary.feedback_delta_total += record.feedback_delta;
            summary.max_latency_multiplier = summary
                .max_latency_multiplier
                .max(record.latency_multiplier);
            summary.max_token_multiplier =
                summary.max_token_multiplier.max(record.token_multiplier);
        }

        summary
    }

    pub fn development_claim_rate(&self) -> f64 {
        ratio(self.development_claim_rounds, self.rounds)
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconDevelopmentWindowGate {
    pub min_rounds: usize,
    pub min_development_claim_rate: f64,
    pub min_feedback_delta_total: i64,
    pub max_latency_multiplier: f64,
    pub max_token_multiplier: f64,
    pub max_duplicate_outputs: usize,
    pub max_noisy_outputs: usize,
    pub max_primary_12b_blockers: usize,
    pub max_model_quality_failure_rounds: usize,
    pub require_no_operational_readiness_failures_before_claim: bool,
}

impl AppleSiliconDevelopmentWindowGate {
    pub fn conservative() -> Self {
        Self {
            min_rounds: 3,
            min_development_claim_rate: 0.67,
            min_feedback_delta_total: 3,
            max_latency_multiplier: 1.5,
            max_token_multiplier: 2.0,
            max_duplicate_outputs: 0,
            max_noisy_outputs: 0,
            max_primary_12b_blockers: 0,
            max_model_quality_failure_rounds: 0,
            require_no_operational_readiness_failures_before_claim: true,
        }
    }

    pub fn evaluate(&self, summary: &ModelPoolDevelopmentWindowSummary) -> GateDecision {
        let mut decision = GateDecision::pass();
        if summary.rounds < self.min_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "model pool development window rounds {} below minimum {}",
                summary.rounds, self.min_rounds
            )));
        }
        if summary.development_claim_rate() < self.min_development_claim_rate {
            decision = decision.merge(GateDecision::block(format!(
                "model pool development claim rate {:.3} below minimum {:.3}",
                summary.development_claim_rate(),
                self.min_development_claim_rate
            )));
        }
        if summary.feedback_delta_total < self.min_feedback_delta_total {
            decision = decision.merge(GateDecision::block(format!(
                "model pool feedback delta total {} below minimum {}",
                summary.feedback_delta_total, self.min_feedback_delta_total
            )));
        }
        if summary.max_latency_multiplier > self.max_latency_multiplier {
            decision = decision.merge(GateDecision::block(format!(
                "model pool max latency multiplier {:.3} above maximum {:.3}",
                summary.max_latency_multiplier, self.max_latency_multiplier
            )));
        }
        if summary.max_token_multiplier > self.max_token_multiplier {
            decision = decision.merge(GateDecision::block(format!(
                "model pool max token multiplier {:.3} above maximum {:.3}",
                summary.max_token_multiplier, self.max_token_multiplier
            )));
        }
        if summary.duplicate_outputs > self.max_duplicate_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "model pool window duplicate outputs {} above maximum {}",
                summary.duplicate_outputs, self.max_duplicate_outputs
            )));
        }
        if summary.noisy_outputs > self.max_noisy_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "model pool window noisy outputs {} above maximum {}",
                summary.noisy_outputs, self.max_noisy_outputs
            )));
        }
        if summary.primary_12b_blockers > self.max_primary_12b_blockers {
            decision = decision.merge(GateDecision::block(format!(
                "model pool window primary 12B blockers {} above maximum {}",
                summary.primary_12b_blockers, self.max_primary_12b_blockers
            )));
        }
        if summary.model_quality_failure_rounds > self.max_model_quality_failure_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "model pool window model quality failure rounds {} above maximum {}",
                summary.model_quality_failure_rounds, self.max_model_quality_failure_rounds
            )));
        }
        if self.require_no_operational_readiness_failures_before_claim
            && summary.operational_readiness_rounds > 0
        {
            decision = decision.merge(GateDecision::block(format!(
                "model pool window operational readiness failures {} must be fixed before claiming Apple Silicon development gain",
                summary.operational_readiness_rounds
            )));
        }
        decision
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct ModelPoolDevelopmentWindowReport {
    pub rounds: usize,
    pub first_round: Option<u64>,
    pub last_round: Option<u64>,
    pub development_claim_rounds: usize,
    pub development_claim_rate: f64,
    pub blocked_rounds: usize,
    pub operational_readiness_rounds: usize,
    pub model_quality_failure_rounds: usize,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub feedback_delta_total: i64,
    pub max_latency_multiplier: f64,
    pub max_token_multiplier: f64,
    pub window_blocked: bool,
    pub allow_development_claim: bool,
    pub failure_reasons: Vec<String>,
}

impl ModelPoolDevelopmentWindowReport {
    pub fn from_gate_and_summary(
        gate: &AppleSiliconDevelopmentWindowGate,
        summary: &ModelPoolDevelopmentWindowSummary,
    ) -> Self {
        let decision = gate.evaluate(summary);

        Self {
            rounds: summary.rounds,
            first_round: summary.first_round,
            last_round: summary.last_round,
            development_claim_rounds: summary.development_claim_rounds,
            development_claim_rate: summary.development_claim_rate(),
            blocked_rounds: summary.blocked_rounds,
            operational_readiness_rounds: summary.operational_readiness_rounds,
            model_quality_failure_rounds: summary.model_quality_failure_rounds,
            duplicate_outputs: summary.duplicate_outputs,
            noisy_outputs: summary.noisy_outputs,
            primary_12b_blockers: summary.primary_12b_blockers,
            feedback_delta_total: summary.feedback_delta_total,
            max_latency_multiplier: summary.max_latency_multiplier,
            max_token_multiplier: summary.max_token_multiplier,
            window_blocked: decision.blocked,
            allow_development_claim: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }
}

