#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconBaselineComparisonRecord {
    pub round: u64,
    pub baseline_12b_feedback_applied: u64,
    pub pool_feedback_applied_total: u64,
    pub baseline_12b_latency_ms: u64,
    pub pool_latency_ms_total: u64,
    pub baseline_12b_runtime_tokens: u64,
    pub pool_runtime_tokens_total: u64,
    pub baseline_12b_success: bool,
    pub pool_success: bool,
    pub baseline_12b_validation_passed: bool,
    pub pool_validation_passed: bool,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub root_adapter_failure_kind: &'static str,
}

impl AppleSiliconBaselineComparisonRecord {
    pub fn feedback_delta(&self) -> i64 {
        self.pool_feedback_applied_total as i64 - self.baseline_12b_feedback_applied as i64
    }

    pub fn latency_multiplier(&self) -> f64 {
        multiplier(self.pool_latency_ms_total, self.baseline_12b_latency_ms)
    }

    pub fn token_multiplier(&self) -> f64 {
        multiplier(
            self.pool_runtime_tokens_total,
            self.baseline_12b_runtime_tokens,
        )
    }

    pub fn pool_improved_feedback(&self) -> bool {
        self.feedback_delta() > 0
    }

    pub fn success_regressed(&self) -> bool {
        self.baseline_12b_success && !self.pool_success
    }

    pub fn validation_regressed(&self) -> bool {
        self.baseline_12b_validation_passed && !self.pool_validation_passed
    }

    pub fn is_operational_readiness_failure(&self) -> bool {
        self.root_adapter_failure_kind == RootAdapterFailureKind::ChainNotReady.as_code()
            || self.root_adapter_failure_kind == RootAdapterFailureKind::ModelUnavailable.as_code()
    }

    pub fn is_model_quality_failure(&self) -> bool {
        self.root_adapter_failure_kind == RootAdapterFailureKind::ModelQualityFailure.as_code()
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconBaselineComparisonSummary {
    pub paired_rounds: usize,
    pub first_round: Option<u64>,
    pub last_round: Option<u64>,
    pub pool_feedback_gain_rounds: usize,
    pub feedback_delta_total: i64,
    pub success_regression_rounds: usize,
    pub validation_regression_rounds: usize,
    pub latency_budget_exceeded_rounds: usize,
    pub token_budget_exceeded_rounds: usize,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
    pub operational_readiness_rounds: usize,
    pub model_quality_failure_rounds: usize,
    pub max_latency_multiplier: f64,
    pub max_token_multiplier: f64,
}

impl AppleSiliconBaselineComparisonSummary {
    pub fn from_records(
        records: &[AppleSiliconBaselineComparisonRecord],
        max_latency_multiplier: f64,
        max_token_multiplier: f64,
    ) -> Self {
        let mut summary = Self {
            paired_rounds: records.len(),
            first_round: records.first().map(|record| record.round),
            last_round: records.last().map(|record| record.round),
            pool_feedback_gain_rounds: 0,
            feedback_delta_total: 0,
            success_regression_rounds: 0,
            validation_regression_rounds: 0,
            latency_budget_exceeded_rounds: 0,
            token_budget_exceeded_rounds: 0,
            duplicate_outputs: 0,
            noisy_outputs: 0,
            primary_12b_blockers: 0,
            operational_readiness_rounds: 0,
            model_quality_failure_rounds: 0,
            max_latency_multiplier: 0.0,
            max_token_multiplier: 0.0,
        };

        for record in records {
            if record.pool_improved_feedback() {
                summary.pool_feedback_gain_rounds += 1;
            }
            summary.feedback_delta_total += record.feedback_delta();
            if record.success_regressed() {
                summary.success_regression_rounds += 1;
            }
            if record.validation_regressed() {
                summary.validation_regression_rounds += 1;
            }
            if record.latency_multiplier() > max_latency_multiplier {
                summary.latency_budget_exceeded_rounds += 1;
            }
            if record.token_multiplier() > max_token_multiplier {
                summary.token_budget_exceeded_rounds += 1;
            }
            summary.duplicate_outputs += record.duplicate_outputs;
            summary.noisy_outputs += record.noisy_outputs;
            summary.primary_12b_blockers += record.primary_12b_blockers;
            if record.is_operational_readiness_failure() {
                summary.operational_readiness_rounds += 1;
            }
            if record.is_model_quality_failure() {
                summary.model_quality_failure_rounds += 1;
            }
            summary.max_latency_multiplier = summary
                .max_latency_multiplier
                .max(record.latency_multiplier());
            summary.max_token_multiplier =
                summary.max_token_multiplier.max(record.token_multiplier());
        }

        summary
    }

    pub fn feedback_gain_rate(&self) -> f64 {
        ratio(self.pool_feedback_gain_rounds, self.paired_rounds)
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconBaselineComparisonGate {
    pub stage: RootAdapterRolloutStage,
    pub min_paired_rounds: usize,
    pub min_feedback_gain_rounds: usize,
    pub min_feedback_delta_total: i64,
    pub max_success_regression_rounds: usize,
    pub max_validation_regression_rounds: usize,
    pub max_latency_budget_exceeded_rounds: usize,
    pub max_token_budget_exceeded_rounds: usize,
    pub max_duplicate_outputs: usize,
    pub max_noisy_outputs: usize,
    pub max_primary_12b_blockers: usize,
    pub max_model_quality_failure_rounds: usize,
    pub require_no_operational_readiness_failures_before_claim: bool,
}

impl AppleSiliconBaselineComparisonGate {
    pub fn conservative(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            min_paired_rounds: 3,
            min_feedback_gain_rounds: 2,
            min_feedback_delta_total: 3,
            max_success_regression_rounds: 0,
            max_validation_regression_rounds: 0,
            max_latency_budget_exceeded_rounds: 0,
            max_token_budget_exceeded_rounds: 0,
            max_duplicate_outputs: 0,
            max_noisy_outputs: 0,
            max_primary_12b_blockers: 0,
            max_model_quality_failure_rounds: 0,
            require_no_operational_readiness_failures_before_claim: true,
        }
    }

    pub fn evaluate(&self, summary: &AppleSiliconBaselineComparisonSummary) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if summary.paired_rounds < self.min_paired_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison paired rounds {} below minimum {}",
                summary.paired_rounds, self.min_paired_rounds
            )));
        }
        if summary.pool_feedback_gain_rounds < self.min_feedback_gain_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison feedback gain rounds {} below minimum {}",
                summary.pool_feedback_gain_rounds, self.min_feedback_gain_rounds
            )));
        }
        if summary.feedback_delta_total < self.min_feedback_delta_total {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison feedback delta total {} below minimum {}",
                summary.feedback_delta_total, self.min_feedback_delta_total
            )));
        }
        if summary.success_regression_rounds > self.max_success_regression_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison success regressions {} above maximum {}",
                summary.success_regression_rounds, self.max_success_regression_rounds
            )));
        }
        if summary.validation_regression_rounds > self.max_validation_regression_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison validation regressions {} above maximum {}",
                summary.validation_regression_rounds, self.max_validation_regression_rounds
            )));
        }
        if summary.latency_budget_exceeded_rounds > self.max_latency_budget_exceeded_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison latency budget exceeded rounds {} above maximum {}",
                summary.latency_budget_exceeded_rounds,
                self.max_latency_budget_exceeded_rounds
            )));
        }
        if summary.token_budget_exceeded_rounds > self.max_token_budget_exceeded_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison token budget exceeded rounds {} above maximum {}",
                summary.token_budget_exceeded_rounds, self.max_token_budget_exceeded_rounds
            )));
        }
        if summary.duplicate_outputs > self.max_duplicate_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison duplicate outputs {} above maximum {}",
                summary.duplicate_outputs, self.max_duplicate_outputs
            )));
        }
        if summary.noisy_outputs > self.max_noisy_outputs {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison noisy outputs {} above maximum {}",
                summary.noisy_outputs, self.max_noisy_outputs
            )));
        }
        if summary.primary_12b_blockers > self.max_primary_12b_blockers {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison primary 12B blockers {} above maximum {}",
                summary.primary_12b_blockers, self.max_primary_12b_blockers
            )));
        }
        if summary.model_quality_failure_rounds > self.max_model_quality_failure_rounds {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison model quality failure rounds {} above maximum {}",
                summary.model_quality_failure_rounds,
                self.max_model_quality_failure_rounds
            )));
        }
        if self.require_no_operational_readiness_failures_before_claim
            && summary.operational_readiness_rounds > 0
        {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon baseline comparison operational readiness failures {} must be fixed before claiming model-pool gain",
                summary.operational_readiness_rounds
            )));
        }

        decision
    }
}

