#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconDevelopmentEffectEvidence {
    pub attribution_report: ModelPoolDevelopmentAttributionReport,
    pub budget_fairness_report: ModelPoolBudgetFairnessReport,
    pub development_window_report: ModelPoolDevelopmentWindowReport,
    pub baseline_comparison_report: AppleSiliconBaselineComparisonReport,
    pub root_adapter_failure_kind: RootAdapterFailureKind,
}

impl AppleSiliconDevelopmentEffectEvidence {
    pub fn from_reports(
        attribution_report: ModelPoolDevelopmentAttributionReport,
        budget_fairness_report: ModelPoolBudgetFairnessReport,
        development_window_report: ModelPoolDevelopmentWindowReport,
        baseline_comparison_report: AppleSiliconBaselineComparisonReport,
        root_adapter_failure_kind: RootAdapterFailureKind,
    ) -> Self {
        Self {
            attribution_report,
            budget_fairness_report,
            development_window_report,
            baseline_comparison_report,
            root_adapter_failure_kind,
        }
    }

    pub fn worker_metric_rows_consistent(&self) -> bool {
        let workers = self.attribution_report.worker_ids.len();
        self.attribution_report.roles.len() == workers
            && self.attribution_report.latency_ms.len() == workers
            && self.attribution_report.runtime_tokens.len() == workers
            && self.attribution_report.success.len() == workers
            && self.attribution_report.feedback_applied.len() == workers
            && self.attribution_report.validation_checked.len() == workers
            && self.attribution_report.validation_passed.len() == workers
            && self.attribution_report.duplicate_output.len() == workers
            && self.attribution_report.noisy_output.len() == workers
            && self.attribution_report.blocked_primary_12b.len() == workers
            && self.attribution_report.failure_kinds.len() == workers
            && self
                .attribution_report
                .worker_development_claim_allowed
                .len()
                == workers
            && self.attribution_report.worker_claim_blockers.len() == workers
    }

    pub fn successful_workers_missing_runtime_metrics(&self) -> usize {
        self.attribution_report
            .success
            .iter()
            .zip(self.attribution_report.latency_ms.iter())
            .zip(self.attribution_report.runtime_tokens.iter())
            .filter(|((success, latency_ms), runtime_tokens)| {
                **success && (**latency_ms == 0 || **runtime_tokens == 0)
            })
            .count()
    }

    pub fn quality_attribution_clean(&self) -> bool {
        self.attribution_report.reported_model_quality_failures
            == self.attribution_report.model_quality_failure_count
    }

    pub fn worker_metric_coverage(&self) -> AppleSiliconWorkerMetricCoverage {
        AppleSiliconWorkerMetricCoverage::from_attribution_report(&self.attribution_report)
    }

    pub fn worker_claim_blocker_count(&self) -> usize {
        self.attribution_report
            .worker_claim_blockers
            .iter()
            .filter(|blockers| !blockers.is_empty())
            .count()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AppleSiliconWorkerMetricCoverage {
    pub worker_count: usize,
    pub latency_rows: usize,
    pub runtime_token_rows: usize,
    pub success_rows: usize,
    pub feedback_rows: usize,
    pub validation_checked_rows: usize,
    pub validation_passed_rows: usize,
    pub duplicate_output_rows: usize,
    pub noisy_output_rows: usize,
    pub primary_12b_blocking_rows: usize,
    pub successful_workers_missing_latency: usize,
    pub successful_workers_missing_runtime_tokens: usize,
    pub validation_unchecked_workers: usize,
    pub validation_failed_workers: usize,
    pub duplicate_outputs: usize,
    pub noisy_outputs: usize,
    pub primary_12b_blockers: usize,
}

impl AppleSiliconWorkerMetricCoverage {
    pub fn from_attribution_report(report: &ModelPoolDevelopmentAttributionReport) -> Self {
        let worker_count = report.worker_ids.len();
        let successful_workers_missing_latency = report
            .success
            .iter()
            .zip(report.latency_ms.iter())
            .filter(|(success, latency_ms)| **success && **latency_ms == 0)
            .count();
        let successful_workers_missing_runtime_tokens = report
            .success
            .iter()
            .zip(report.runtime_tokens.iter())
            .filter(|(success, runtime_tokens)| **success && **runtime_tokens == 0)
            .count();

        Self {
            worker_count,
            latency_rows: report.latency_ms.len(),
            runtime_token_rows: report.runtime_tokens.len(),
            success_rows: report.success.len(),
            feedback_rows: report.feedback_applied.len(),
            validation_checked_rows: report.validation_checked.len(),
            validation_passed_rows: report.validation_passed.len(),
            duplicate_output_rows: report.duplicate_output.len(),
            noisy_output_rows: report.noisy_output.len(),
            primary_12b_blocking_rows: report.blocked_primary_12b.len(),
            successful_workers_missing_latency,
            successful_workers_missing_runtime_tokens,
            validation_unchecked_workers: report
                .validation_checked
                .iter()
                .filter(|checked| !**checked)
                .count(),
            validation_failed_workers: report
                .validation_passed
                .iter()
                .filter(|passed| !**passed)
                .count(),
            duplicate_outputs: report
                .duplicate_output
                .iter()
                .filter(|duplicate| **duplicate)
                .count(),
            noisy_outputs: report.noisy_output.iter().filter(|noisy| **noisy).count(),
            primary_12b_blockers: report
                .blocked_primary_12b
                .iter()
                .filter(|blocked| **blocked)
                .count(),
        }
    }

    pub fn metric_rows_complete(&self) -> bool {
        self.latency_rows == self.worker_count
            && self.runtime_token_rows == self.worker_count
            && self.success_rows == self.worker_count
            && self.feedback_rows == self.worker_count
            && self.validation_checked_rows == self.worker_count
            && self.validation_passed_rows == self.worker_count
            && self.duplicate_output_rows == self.worker_count
            && self.noisy_output_rows == self.worker_count
            && self.primary_12b_blocking_rows == self.worker_count
    }

    pub fn development_signal_clean(&self) -> bool {
        self.metric_rows_complete()
            && self.successful_workers_missing_latency == 0
            && self.successful_workers_missing_runtime_tokens == 0
            && self.validation_unchecked_workers == 0
            && self.validation_failed_workers == 0
            && self.duplicate_outputs == 0
            && self.noisy_outputs == 0
            && self.primary_12b_blockers == 0
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct AppleSiliconDevelopmentEffectGate {
    pub stage: RootAdapterRolloutStage,
    pub require_worker_metric_rows_consistent: bool,
    pub require_worker_metric_coverage: bool,
    pub require_attribution_claim: bool,
    pub require_budget_fairness: bool,
    pub require_development_window_claim: bool,
    pub require_baseline_comparison_claim: bool,
    pub require_root_adapter_ready: bool,
    pub forbid_operational_quality_confusion: bool,
}

impl AppleSiliconDevelopmentEffectGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        let enforced = stage == RootAdapterRolloutStage::Enforced;
        Self {
            stage,
            require_worker_metric_rows_consistent: enforced,
            require_worker_metric_coverage: enforced,
            require_attribution_claim: enforced,
            require_budget_fairness: enforced,
            require_development_window_claim: enforced,
            require_baseline_comparison_claim: enforced,
            require_root_adapter_ready: enforced,
            forbid_operational_quality_confusion: true,
        }
    }

    pub fn evaluate(&self, evidence: &AppleSiliconDevelopmentEffectEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if self.require_worker_metric_rows_consistent && !evidence.worker_metric_rows_consistent() {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon development effect has inconsistent per-worker metric rows",
            ));
        }
        let coverage = evidence.worker_metric_coverage();
        if self.require_worker_metric_coverage && !coverage.metric_rows_complete() {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker metric coverage incomplete for {} worker(s): latency rows {}, runtime token rows {}, success rows {}, validation rows {}/{}, duplicate/noisy/blocking rows {}/{}/{}",
                coverage.worker_count,
                coverage.latency_rows,
                coverage.runtime_token_rows,
                coverage.success_rows,
                coverage.validation_checked_rows,
                coverage.validation_passed_rows,
                coverage.duplicate_output_rows,
                coverage.noisy_output_rows,
                coverage.primary_12b_blocking_rows
            )));
        }
        let missing_runtime = evidence.successful_workers_missing_runtime_metrics();
        if missing_runtime > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon development effect has successful worker(s) missing latency/tokens metrics: {missing_runtime}"
            )));
        }
        if self.require_worker_metric_coverage && coverage.validation_unchecked_workers > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker validation unchecked for {} worker(s)",
                coverage.validation_unchecked_workers
            )));
        }
        if self.require_worker_metric_coverage && coverage.validation_failed_workers > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker validation failed for {} worker(s)",
                coverage.validation_failed_workers
            )));
        }
        if self.require_worker_metric_coverage && coverage.duplicate_outputs > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker duplicate output observed for {} worker(s)",
                coverage.duplicate_outputs
            )));
        }
        if self.require_worker_metric_coverage && coverage.noisy_outputs > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker noisy output observed for {} worker(s)",
                coverage.noisy_outputs
            )));
        }
        if self.require_worker_metric_coverage && coverage.primary_12b_blockers > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon worker blocked primary 12B for {} worker(s)",
                coverage.primary_12b_blockers
            )));
        }
        if self.require_attribution_claim && !evidence.attribution_report.allow_development_claim {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon worker attribution did not allow a development-effect claim",
            ));
        }
        let worker_claim_blocker_count = evidence.worker_claim_blocker_count();
        if self.require_attribution_claim && worker_claim_blocker_count > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon development effect has per-worker claim blockers for {} worker(s)",
                worker_claim_blocker_count
            )));
        }
        if self.require_budget_fairness && !evidence.budget_fairness_report.allow_pool_expansion {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon model-pool budget fairness did not allow pool expansion",
            ));
        }
        if self.require_development_window_claim
            && !evidence.development_window_report.allow_development_claim
        {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon development window did not allow a sustained development-effect claim",
            ));
        }
        if self.require_baseline_comparison_claim
            && !evidence
                .baseline_comparison_report
                .allow_development_gain_claim
        {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon baseline comparison did not allow a paired development-gain claim",
            ));
        }
        if evidence.attribution_report.operational_readiness_failures > 0 {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon development effect has operational readiness failures {} that block claims without counting as model quality failure",
                evidence.attribution_report.operational_readiness_failures
            )));
        }
        if self.forbid_operational_quality_confusion && !evidence.quality_attribution_clean() {
            decision = decision.merge(GateDecision::block(format!(
                "Apple Silicon development effect reported {} quality failure(s) but classified {} after readiness ordering",
                evidence.attribution_report.reported_model_quality_failures,
                evidence.attribution_report.model_quality_failure_count
            )));
        }
        if self.require_root_adapter_ready {
            if evidence
                .root_adapter_failure_kind
                .is_operational_readiness()
            {
                decision = decision.merge(GateDecision::block(format!(
                    "root adapter {} blocks Apple Silicon development-effect claim without counting as model quality failure",
                    evidence.root_adapter_failure_kind.as_code()
                )));
            } else if evidence
                .root_adapter_failure_kind
                .counts_as_model_quality_failure()
            {
                decision = decision.merge(GateDecision::block(
                    "root adapter model_quality_failure blocks Apple Silicon development-effect claim after runtime evidence",
                ));
            } else if evidence.root_adapter_failure_kind != RootAdapterFailureKind::None {
                decision = decision.merge(GateDecision::block(format!(
                    "root adapter {} blocks Apple Silicon development-effect claim until classified",
                    evidence.root_adapter_failure_kind.as_code()
                )));
            }
        }

        decision
    }
}

