#[derive(Debug, Clone, PartialEq)]
pub struct ModelWorkerGateReport {
    pub stage: &'static str,
    pub worker_ids: Vec<String>,
    pub roles: Vec<&'static str>,
    pub models: Vec<String>,
    pub latency_ms: Vec<u64>,
    pub runtime_tokens: Vec<u64>,
    pub success: Vec<bool>,
    pub feedback_applied: Vec<u64>,
    pub validation_checked: Vec<bool>,
    pub validation_passed: Vec<bool>,
    pub duplicate_output: Vec<bool>,
    pub noisy_output: Vec<bool>,
    pub blocked_primary_12b: Vec<bool>,
    pub failure_kinds: Vec<&'static str>,
    pub development_claim_allowed: Vec<bool>,
    pub claim_blockers: Vec<Vec<&'static str>>,
    pub root_adapter_failure_kind: &'static str,
    pub operational_readiness_blocked: bool,
    pub model_quality_failure_counted: bool,
    pub allow_development_claim: bool,
    pub failure_reasons: Vec<String>,
}

impl ModelWorkerGateReport {
    pub fn from_workers_and_decisions(
        stage: RootAdapterRolloutStage,
        workers: &[ModelWorkerRecord],
        pool_decision: &GateDecision,
        development_decision: &GateDecision,
        root_adapter_failure: RootAdapterFailureKind,
    ) -> Self {
        let mut failure_reasons = pool_decision.reasons.clone();
        failure_reasons.extend(development_decision.reasons.clone());

        if root_adapter_failure.is_operational_readiness() {
            failure_reasons.push(format!(
                "root adapter {} blocks development-effect claim without counting as model quality failure",
                root_adapter_failure.as_code()
            ));
        } else if root_adapter_failure.counts_as_model_quality_failure() {
            failure_reasons.push(
                "root adapter model_quality_failure counts only after final JSON and runtime evidence"
                    .to_owned(),
            );
        } else if root_adapter_failure != RootAdapterFailureKind::None {
            failure_reasons.push(format!(
                "root adapter {} blocks development-effect claim until classified",
                root_adapter_failure.as_code()
            ));
        }

        let claim_blockers = workers
            .iter()
            .map(ModelWorkerRecord::development_claim_blockers)
            .collect::<Vec<_>>();
        let blocked_workers = workers
            .iter()
            .zip(claim_blockers.iter())
            .filter(|(_, blockers)| !blockers.is_empty())
            .map(|(worker, blockers)| format!("{}={}", worker.worker_id, blockers.join("+")))
            .collect::<Vec<_>>();
        if !blocked_workers.is_empty() {
            failure_reasons.push(format!(
                "model worker claim blockers: {}",
                blocked_workers.join(", ")
            ));
        }

        let allow_development_claim = stage != RootAdapterRolloutStage::ShadowOnly
            && !pool_decision.blocked
            && !development_decision.blocked
            && root_adapter_failure == RootAdapterFailureKind::None
            && blocked_workers.is_empty();

        Self {
            stage: stage.as_str(),
            worker_ids: workers
                .iter()
                .map(|worker| worker.worker_id.clone())
                .collect(),
            roles: workers.iter().map(|worker| worker.role.as_str()).collect(),
            models: workers.iter().map(|worker| worker.model.clone()).collect(),
            latency_ms: workers.iter().map(|worker| worker.latency_ms).collect(),
            runtime_tokens: workers.iter().map(|worker| worker.runtime_tokens).collect(),
            success: workers.iter().map(|worker| worker.success).collect(),
            feedback_applied: workers
                .iter()
                .map(|worker| worker.feedback_applied)
                .collect(),
            validation_checked: workers
                .iter()
                .map(|worker| worker.validation_checked)
                .collect(),
            validation_passed: workers
                .iter()
                .map(|worker| worker.validation_passed)
                .collect(),
            duplicate_output: workers
                .iter()
                .map(|worker| worker.duplicate_output)
                .collect(),
            noisy_output: workers.iter().map(|worker| worker.noisy_output).collect(),
            blocked_primary_12b: workers
                .iter()
                .map(|worker| worker.blocked_primary_12b)
                .collect(),
            failure_kinds: workers
                .iter()
                .map(|worker| worker.failure_kind.as_code())
                .collect(),
            development_claim_allowed: workers
                .iter()
                .map(ModelWorkerRecord::allows_development_claim)
                .collect(),
            claim_blockers,
            root_adapter_failure_kind: root_adapter_failure.as_code(),
            operational_readiness_blocked: root_adapter_failure.is_operational_readiness(),
            model_quality_failure_counted: root_adapter_failure.counts_as_model_quality_failure(),
            allow_development_claim,
            failure_reasons,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerRootFailureConsistencyGate {
    pub stage: RootAdapterRolloutStage,
    pub require_single_worker_agreement: bool,
    pub keep_operational_failures_out_of_quality: bool,
}

impl WorkerRootFailureConsistencyGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_single_worker_agreement: stage == RootAdapterRolloutStage::Enforced,
            keep_operational_failures_out_of_quality: true,
        }
    }

    pub fn evaluate(&self, evidence: &WorkerRootFailureConsistencyEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if self.require_single_worker_agreement && !evidence.single_worker_consistent() {
            decision = decision.merge(GateDecision::block(format!(
                "single-worker root/worker failure-kind mismatch: root={} workers={}",
                evidence.root_adapter_failure_kind.as_code(),
                evidence.worker_failure_kind_codes().join(", ")
            )));
        }
        if self.keep_operational_failures_out_of_quality && evidence.operational_quality_confusion()
        {
            decision = decision.merge(GateDecision::block(
                "operational readiness failure was mixed with model_quality_failure",
            ));
        }

        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerRootFailureConsistencyEvidence {
    pub single_worker_projection: bool,
    pub worker_failure_kinds: Vec<RootAdapterFailureKind>,
    pub root_adapter_failure_kind: RootAdapterFailureKind,
}

impl WorkerRootFailureConsistencyEvidence {
    pub fn from_worker_records(
        single_worker_projection: bool,
        workers: &[ModelWorkerRecord],
        root_adapter_failure_kind: RootAdapterFailureKind,
    ) -> Self {
        Self {
            single_worker_projection,
            worker_failure_kinds: workers.iter().map(|worker| worker.failure_kind).collect(),
            root_adapter_failure_kind,
        }
    }

    pub fn single_worker_consistent(&self) -> bool {
        if !self.single_worker_projection {
            return true;
        }
        self.worker_failure_kinds.len() == 1
            && self.worker_failure_kinds[0] == self.root_adapter_failure_kind
    }

    pub fn operational_quality_confusion(&self) -> bool {
        let root_operational = self.root_adapter_failure_kind.is_operational_readiness();
        let root_quality = self
            .root_adapter_failure_kind
            .counts_as_model_quality_failure();
        let worker_operational = self
            .worker_failure_kinds
            .iter()
            .any(RootAdapterFailureKind::is_operational_readiness);
        let worker_quality = self
            .worker_failure_kinds
            .iter()
            .any(RootAdapterFailureKind::counts_as_model_quality_failure);

        (root_operational && worker_quality) || (root_quality && worker_operational)
    }

    pub fn worker_failure_kind_codes(&self) -> Vec<&'static str> {
        self.worker_failure_kinds
            .iter()
            .map(RootAdapterFailureKind::as_code)
            .collect()
    }
}

