#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentKillSwitchGate {
    pub stage: RootAdapterRolloutStage,
    pub require_for_disabled_flags: bool,
}

impl ExperimentKillSwitchGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_for_disabled_flags: false,
        }
    }

    pub fn evaluate(&self, evidence: &ExperimentKillSwitchEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }
        if !evidence.flag.enabled && !self.require_for_disabled_flags {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if evidence.flag.owner.trim().is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} has no owner for kill switch",
                evidence.flag.name
            )));
        }
        if !evidence.kill_switch_documented {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} has no documented kill switch",
                evidence.flag.name
            )));
        }
        if !evidence.rollback_report_present {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} has no rollback report",
                evidence.flag.name
            )));
        }
        if !evidence.rollback_resume_gate_present {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} has no rollback resume gate",
                evidence.flag.name
            )));
        }
        if !evidence.context_rot_clean {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} cannot expand while Context Rot is dirty",
                evidence.flag.name
            )));
        }
        if !evidence.owner_acknowledged {
            decision = decision.merge(GateDecision::block(format!(
                "experiment {} owner has not acknowledged rollback responsibility",
                evidence.flag.name
            )));
        }
        decision
    }
}

