#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentExpansionSafetyGate {
    pub stage: RootAdapterRolloutStage,
    pub require_rollout_report: bool,
    pub require_kill_switch_report: bool,
    pub require_clean_context_rot: bool,
    pub require_rollback_resume: bool,
    pub require_model_pool_attribution: bool,
    pub require_adapter_report_emission: bool,
    pub require_adapter_report_field_coverage: bool,
    pub require_apple_silicon_development_effect: bool,
    pub require_promotion_window: bool,
    pub require_readiness: bool,
    pub require_steam_case_matrix: bool,
    pub require_validation_command_coverage: bool,
    pub require_root_adapter_ready: bool,
    pub forbid_operational_quality_confusion: bool,
}

impl ExperimentExpansionSafetyGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_rollout_report: stage == RootAdapterRolloutStage::Enforced,
            require_kill_switch_report: stage == RootAdapterRolloutStage::Enforced,
            require_clean_context_rot: stage == RootAdapterRolloutStage::Enforced,
            require_rollback_resume: stage == RootAdapterRolloutStage::Enforced,
            require_model_pool_attribution: stage == RootAdapterRolloutStage::Enforced,
            require_adapter_report_emission: stage == RootAdapterRolloutStage::Enforced,
            require_adapter_report_field_coverage: stage == RootAdapterRolloutStage::Enforced,
            require_apple_silicon_development_effect: stage == RootAdapterRolloutStage::Enforced,
            require_promotion_window: stage == RootAdapterRolloutStage::Enforced,
            require_readiness: stage == RootAdapterRolloutStage::Enforced,
            require_steam_case_matrix: stage == RootAdapterRolloutStage::Enforced,
            require_validation_command_coverage: stage == RootAdapterRolloutStage::Enforced,
            require_root_adapter_ready: stage == RootAdapterRolloutStage::Enforced,
            forbid_operational_quality_confusion: true,
        }
    }

    pub fn evaluate(&self, evidence: &ExperimentExpansionSafetyEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced || evidence.enabled_flags().is_empty() {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        let missing_owners = evidence.missing_enabled_flag_owners();
        if !missing_owners.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "enabled experiments missing owners: {}",
                missing_owners.join(", ")
            )));
        }
        if self.require_rollout_report && !evidence.rollout_report_passed {
            decision = decision.merge(GateDecision::block(
                "experiment rollout report did not pass before expansion",
            ));
        }
        if self.require_kill_switch_report && !evidence.kill_switch_report_passed {
            decision = decision.merge(GateDecision::block(
                "experiment kill-switch report did not pass before expansion",
            ));
        }
        if self.require_clean_context_rot && !evidence.context_rot_report_passed {
            decision = decision.merge(GateDecision::block(
                "Context Rot report did not pass before experiment expansion",
            ));
        }
        if self.require_clean_context_rot && !evidence.context_rot_trend_passed {
            decision = decision.merge(GateDecision::block(
                "Context Rot trend did not pass before experiment expansion",
            ));
        }
        if self.require_clean_context_rot && !evidence.context_rot_remediation_passed {
            decision = decision.merge(GateDecision::block(
                "Context Rot remediation did not pass before experiment expansion",
            ));
        }
        if self.require_rollback_resume && !evidence.rollback_report_present {
            decision = decision.merge(GateDecision::block(
                "rollback report is missing before experiment expansion",
            ));
        }
        if self.require_rollback_resume && !evidence.rollback_resume_passed {
            decision = decision.merge(GateDecision::block(
                "rollback resume gate did not pass before experiment expansion",
            ));
        }
        if self.require_model_pool_attribution && !evidence.model_pool_attribution_passed {
            decision = decision.merge(GateDecision::block(
                "model-pool development attribution did not pass before experiment expansion",
            ));
        }
        if self.require_adapter_report_emission && !evidence.adapter_report_emission_passed {
            decision = decision.merge(GateDecision::block(
                "adapter report emission did not pass before experiment expansion",
            ));
        }
        if self.require_adapter_report_field_coverage
            && !evidence.adapter_report_field_coverage_passed
        {
            decision = decision.merge(GateDecision::block(
                "adapter report field coverage did not pass before experiment expansion",
            ));
        }
        if self.require_apple_silicon_development_effect
            && !evidence.apple_silicon_development_effect_passed
        {
            decision = decision.merge(GateDecision::block(
                "Apple Silicon development-effect gate did not pass before experiment expansion",
            ));
        }
        if self.require_promotion_window && !evidence.promotion_window_passed {
            decision = decision.merge(GateDecision::block(
                "adapter promotion window did not pass before experiment expansion",
            ));
        }
        if self.require_readiness && !evidence.readiness_passed {
            decision = decision.merge(GateDecision::block(
                "next-round readiness did not pass before experiment expansion",
            ));
        }
        if self.require_steam_case_matrix && !evidence.steam_case_matrix_passed {
            decision = decision.merge(GateDecision::block(
                "Steam case matrix did not pass before experiment expansion",
            ));
        }
        if self.require_validation_command_coverage && !evidence.validation_command_coverage_passed
        {
            decision = decision.merge(GateDecision::block(
                "validation command coverage did not pass before experiment expansion",
            ));
        }
        if self.require_root_adapter_ready
            && evidence.root_adapter_failure_kind != RootAdapterFailureKind::None
        {
            let kind = evidence.root_adapter_failure_kind.as_code();
            if evidence
                .root_adapter_failure_kind
                .is_operational_readiness()
            {
                decision = decision.merge(GateDecision::block(format!(
                    "root adapter operational readiness failure {kind} blocks experiment expansion without counting as model quality failure",
                )));
            } else {
                decision = decision.merge(GateDecision::block(format!(
                    "root adapter failure {kind} blocks experiment expansion",
                )));
            }
        }
        if self.forbid_operational_quality_confusion && !evidence.quality_attribution_clean() {
            decision = decision.merge(GateDecision::block(format!(
                "experiment expansion reported {} quality failure(s) but classified {} after readiness ordering",
                evidence.reported_model_quality_failures,
                evidence.classified_model_quality_failures()
            )));
        }

        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentExpansionSafetyReport {
    pub stage: &'static str,
    pub flag_names: Vec<String>,
    pub enabled_flag_names: Vec<String>,
    pub rollout_report_passed: bool,
    pub kill_switch_report_passed: bool,
    pub context_rot_report_passed: bool,
    pub context_rot_trend_passed: bool,
    pub context_rot_remediation_passed: bool,
    pub rollback_report_present: bool,
    pub rollback_resume_passed: bool,
    pub model_pool_attribution_passed: bool,
    pub adapter_report_emission_passed: bool,
    pub adapter_report_field_coverage_passed: bool,
    pub apple_silicon_development_effect_passed: bool,
    pub promotion_window_passed: bool,
    pub readiness_passed: bool,
    pub steam_case_matrix_passed: bool,
    pub validation_command_coverage_passed: bool,
    pub root_adapter_failure_kind: &'static str,
    pub reported_model_quality_failures: u64,
    pub classified_model_quality_failures: u64,
    pub expansion_blocked: bool,
    pub allow_experiment_expansion: bool,
    pub failure_reasons: Vec<String>,
}

impl ExperimentExpansionSafetyReport {
    pub fn from_gate_and_evidence(
        gate: &ExperimentExpansionSafetyGate,
        evidence: &ExperimentExpansionSafetyEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            flag_names: evidence
                .flags
                .iter()
                .map(|flag| flag.name.clone())
                .collect(),
            enabled_flag_names: evidence.enabled_flag_names(),
            rollout_report_passed: evidence.rollout_report_passed,
            kill_switch_report_passed: evidence.kill_switch_report_passed,
            context_rot_report_passed: evidence.context_rot_report_passed,
            context_rot_trend_passed: evidence.context_rot_trend_passed,
            context_rot_remediation_passed: evidence.context_rot_remediation_passed,
            rollback_report_present: evidence.rollback_report_present,
            rollback_resume_passed: evidence.rollback_resume_passed,
            model_pool_attribution_passed: evidence.model_pool_attribution_passed,
            adapter_report_emission_passed: evidence.adapter_report_emission_passed,
            adapter_report_field_coverage_passed: evidence.adapter_report_field_coverage_passed,
            apple_silicon_development_effect_passed: evidence
                .apple_silicon_development_effect_passed,
            promotion_window_passed: evidence.promotion_window_passed,
            readiness_passed: evidence.readiness_passed,
            steam_case_matrix_passed: evidence.steam_case_matrix_passed,
            validation_command_coverage_passed: evidence.validation_command_coverage_passed,
            root_adapter_failure_kind: evidence.root_adapter_failure_kind.as_code(),
            reported_model_quality_failures: evidence.reported_model_quality_failures,
            classified_model_quality_failures: evidence.classified_model_quality_failures(),
            expansion_blocked: decision.blocked,
            allow_experiment_expansion: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }
}

