#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentSwitchMatrixEvidence {
    pub flags: Vec<ExperimentFlag>,
    pub expansion_reports: Vec<ExperimentExpansionSafetyReport>,
}

impl ExperimentSwitchMatrixEvidence {
    pub fn from_flags_and_reports(
        flags: Vec<ExperimentFlag>,
        expansion_reports: Vec<ExperimentExpansionSafetyReport>,
    ) -> Self {
        Self {
            flags,
            expansion_reports,
        }
    }

    pub fn flag_names(&self) -> Vec<String> {
        self.flags.iter().map(|flag| flag.name.clone()).collect()
    }

    pub fn enabled_flag_names(&self) -> Vec<String> {
        self.flags
            .iter()
            .filter(|flag| flag.enabled)
            .map(|flag| flag.name.clone())
            .collect()
    }

    pub fn reported_enabled_flag_names(&self) -> Vec<String> {
        let mut names = Vec::new();
        for report in &self.expansion_reports {
            for name in &report.enabled_flag_names {
                if !names.contains(name) {
                    names.push(name.clone());
                }
            }
        }
        names
    }

    pub fn duplicate_enabled_flag_reports(&self) -> Vec<String> {
        let mut names = self
            .expansion_reports
            .iter()
            .flat_map(|report| report.enabled_flag_names.iter().cloned())
            .collect::<Vec<_>>();
        names.sort();
        duplicate_names(&names)
    }

    pub fn unknown_enabled_flag_reports(&self) -> Vec<String> {
        let enabled = self.enabled_flag_names();
        let mut reported = Vec::new();
        for report in &self.expansion_reports {
            for name in &report.flag_names {
                if !reported.contains(name) {
                    reported.push(name.clone());
                }
            }
        }
        reported
            .into_iter()
            .filter(|name| !enabled.contains(name))
            .collect()
    }

    pub fn missing_enabled_flag_reports(&self) -> Vec<String> {
        let reported = self.reported_enabled_flag_names();
        self.enabled_flag_names()
            .into_iter()
            .filter(|name| !reported.contains(name))
            .collect()
    }

    pub fn blocked_expansion_reports(&self) -> Vec<String> {
        self.expansion_reports
            .iter()
            .filter(|report| report.expansion_blocked)
            .map(|report| {
                if report.enabled_flag_names.is_empty() {
                    report.flag_names.join(",")
                } else {
                    report.enabled_flag_names.join(",")
                }
            })
            .collect()
    }

    pub fn all_enabled_reported(&self) -> bool {
        self.missing_enabled_flag_reports().is_empty()
    }

    pub fn exactly_one_report_per_enabled_flag(&self) -> bool {
        self.missing_enabled_flag_reports().is_empty()
            && self.duplicate_enabled_flag_reports().is_empty()
            && self.unknown_enabled_flag_reports().is_empty()
    }

    pub fn all_expansion_reports_passed(&self) -> bool {
        self.expansion_reports
            .iter()
            .all(|report| report.allow_experiment_expansion)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentSwitchMatrixGate {
    pub stage: RootAdapterRolloutStage,
    pub require_enabled_flags_reported: bool,
    pub require_exactly_one_report_per_enabled_flag: bool,
    pub require_all_expansion_reports_passed: bool,
}

impl ExperimentSwitchMatrixGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_enabled_flags_reported: stage == RootAdapterRolloutStage::Enforced,
            require_exactly_one_report_per_enabled_flag: stage == RootAdapterRolloutStage::Enforced,
            require_all_expansion_reports_passed: stage == RootAdapterRolloutStage::Enforced,
        }
    }

    pub fn evaluate(&self, evidence: &ExperimentSwitchMatrixEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        let missing = evidence.missing_enabled_flag_reports();
        if self.require_enabled_flags_reported && !missing.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "enabled experiment flags missing expansion reports: {}",
                missing.join(", ")
            )));
        }

        if self.require_exactly_one_report_per_enabled_flag {
            let duplicates = evidence.duplicate_enabled_flag_reports();
            if !duplicates.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "enabled experiment flags have duplicate expansion reports: {}",
                    duplicates.join(", ")
                )));
            }

            let unknown = evidence.unknown_enabled_flag_reports();
            if !unknown.is_empty() {
                decision = decision.merge(GateDecision::block(format!(
                    "expansion reports reference unknown or disabled enabled flags: {}",
                    unknown.join(", ")
                )));
            }
        }

        let blocked = evidence.blocked_expansion_reports();
        if self.require_all_expansion_reports_passed && !blocked.is_empty() {
            decision = decision.merge(GateDecision::block(format!(
                "experiment expansion reports blocked: {}",
                blocked.join("; ")
            )));
        }

        decision
    }
}

