#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ExperimentSwitchMatrixReport {
    pub stage: &'static str,
    pub flag_names: Vec<String>,
    pub enabled_flag_names: Vec<String>,
    pub reported_enabled_flag_names: Vec<String>,
    pub missing_enabled_flag_reports: Vec<String>,
    pub duplicate_enabled_flag_reports: Vec<String>,
    pub unknown_enabled_flag_reports: Vec<String>,
    pub expansion_report_count: usize,
    pub blocked_expansion_reports: Vec<String>,
    pub all_enabled_reported: bool,
    pub exactly_one_report_per_enabled_flag: bool,
    pub all_expansion_reports_passed: bool,
    pub switch_matrix_blocked: bool,
    pub allow_experiment_switch_expansion: bool,
    pub failure_reasons: Vec<String>,
}

impl ExperimentSwitchMatrixReport {
    pub fn from_gate_and_evidence(
        gate: &ExperimentSwitchMatrixGate,
        evidence: &ExperimentSwitchMatrixEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            flag_names: evidence.flag_names(),
            enabled_flag_names: evidence.enabled_flag_names(),
            reported_enabled_flag_names: evidence.reported_enabled_flag_names(),
            missing_enabled_flag_reports: evidence.missing_enabled_flag_reports(),
            duplicate_enabled_flag_reports: evidence.duplicate_enabled_flag_reports(),
            unknown_enabled_flag_reports: evidence.unknown_enabled_flag_reports(),
            expansion_report_count: evidence.expansion_reports.len(),
            blocked_expansion_reports: evidence.blocked_expansion_reports(),
            all_enabled_reported: evidence.all_enabled_reported(),
            exactly_one_report_per_enabled_flag: evidence.exactly_one_report_per_enabled_flag(),
            all_expansion_reports_passed: evidence.all_expansion_reports_passed(),
            switch_matrix_blocked: decision.blocked,
            allow_experiment_switch_expansion: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_flags_and_reports(
        gate: &ExperimentSwitchMatrixGate,
        flags: Vec<ExperimentFlag>,
        expansion_reports: Vec<ExperimentExpansionSafetyReport>,
    ) -> Self {
        let evidence =
            ExperimentSwitchMatrixEvidence::from_flags_and_reports(flags, expansion_reports);
        Self::from_gate_and_evidence(gate, &evidence)
    }
}

