#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContextRotRemediationGate {
    pub stage: RootAdapterRolloutStage,
    pub require_quarantine_complete: bool,
    pub require_legacy_metadata_repaired: bool,
    pub require_clean_gist_backfilled: bool,
    pub require_duplicates_removed: bool,
}

impl ContextRotRemediationGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_quarantine_complete: stage == RootAdapterRolloutStage::Enforced,
            require_legacy_metadata_repaired: stage == RootAdapterRolloutStage::Enforced,
            require_clean_gist_backfilled: stage == RootAdapterRolloutStage::Enforced,
            require_duplicates_removed: stage == RootAdapterRolloutStage::Enforced,
        }
    }

    pub fn evaluate(&self, evidence: &ContextRotRemediationEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if self.require_quarantine_complete
            && evidence.quarantined_records < evidence.quarantine_candidates
        {
            decision = decision.merge(GateDecision::block(format!(
                "context rot quarantine incomplete: {}/{} records quarantined",
                evidence.quarantined_records, evidence.quarantine_candidates
            )));
        }
        if self.require_legacy_metadata_repaired
            && evidence.repaired_legacy_metadata_lessons
                < evidence.repairable_legacy_metadata_lessons
        {
            decision = decision.merge(GateDecision::block(format!(
                "legacy metadata repair incomplete: {}/{} lessons repaired",
                evidence.repaired_legacy_metadata_lessons,
                evidence.repairable_legacy_metadata_lessons
            )));
        }
        if self.require_clean_gist_backfilled
            && evidence.clean_gists_backfilled < evidence.legacy_metadata_without_clean_gist
        {
            decision = decision.merge(GateDecision::block(format!(
                "clean gist backfill incomplete: {}/{} lessons backfilled",
                evidence.clean_gists_backfilled, evidence.legacy_metadata_without_clean_gist
            )));
        }
        if self.require_duplicates_removed
            && evidence.duplicate_outputs_removed < evidence.duplicate_outputs
        {
            decision = decision.merge(GateDecision::block(format!(
                "duplicate output cleanup incomplete: {}/{} duplicates removed",
                evidence.duplicate_outputs_removed, evidence.duplicate_outputs
            )));
        }

        decision
    }
}

