#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContextRotRemediationReport {
    pub stage: &'static str,
    pub quarantine_candidates: u64,
    pub quarantined_records: u64,
    pub repairable_legacy_metadata_lessons: u64,
    pub repaired_legacy_metadata_lessons: u64,
    pub legacy_metadata_without_clean_gist: u64,
    pub clean_gists_backfilled: u64,
    pub duplicate_outputs: u64,
    pub duplicate_outputs_removed: u64,
    pub remediation_blocked: bool,
    pub failure_reasons: Vec<String>,
    pub allow_experiment_rollout: bool,
}

impl ContextRotRemediationReport {
    pub fn from_gate_and_evidence(
        gate: &ContextRotRemediationGate,
        evidence: &ContextRotRemediationEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            quarantine_candidates: evidence.quarantine_candidates,
            quarantined_records: evidence.quarantined_records,
            repairable_legacy_metadata_lessons: evidence.repairable_legacy_metadata_lessons,
            repaired_legacy_metadata_lessons: evidence.repaired_legacy_metadata_lessons,
            legacy_metadata_without_clean_gist: evidence.legacy_metadata_without_clean_gist,
            clean_gists_backfilled: evidence.clean_gists_backfilled,
            duplicate_outputs: evidence.duplicate_outputs,
            duplicate_outputs_removed: evidence.duplicate_outputs_removed,
            remediation_blocked: decision.blocked,
            allow_experiment_rollout: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_gate_and_signal(
        gate: &ContextRotRemediationGate,
        signal: &ContextRotSignal,
    ) -> Self {
        let evidence = ContextRotRemediationEvidence::from_signal(signal);
        Self::from_gate_and_evidence(gate, &evidence)
    }
}

