#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SelfEvolutionContinuityEvidence {
    pub previous_round: u64,
    pub current_round: u64,
    pub previous_feedback_applied: u64,
    pub feedback_carried_forward: bool,
    pub self_improve_checked: bool,
    pub self_improve_passed: bool,
    pub validation_passed: bool,
}

impl SelfEvolutionContinuityEvidence {
    pub fn from_previous_and_current(previous: &LedgerRecord, current: &LedgerRecord) -> Self {
        Self {
            previous_round: previous.round.unwrap_or_default(),
            current_round: current.round.unwrap_or_default(),
            previous_feedback_applied: previous.feedback_applied,
            feedback_carried_forward: previous.feedback_applied == 0
                || current.self_improve_checked,
            self_improve_checked: current.self_improve_checked,
            self_improve_passed: current.self_improve_passed,
            validation_passed: current.validation_passed,
        }
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct SelfEvolutionContinuityGate {
    pub stage: RootAdapterRolloutStage,
    pub require_adjacent_rounds: bool,
    pub require_feedback_carryover: bool,
    pub require_self_improve_passed: bool,
    pub require_validation_passed: bool,
}

impl SelfEvolutionContinuityGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            require_adjacent_rounds: stage == RootAdapterRolloutStage::Enforced,
            require_feedback_carryover: stage == RootAdapterRolloutStage::Enforced,
            require_self_improve_passed: stage == RootAdapterRolloutStage::Enforced,
            require_validation_passed: stage == RootAdapterRolloutStage::Enforced,
        }
    }

    pub fn evaluate(&self, evidence: &SelfEvolutionContinuityEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if self.require_adjacent_rounds && evidence.current_round != evidence.previous_round + 1 {
            decision = decision.merge(GateDecision::block(format!(
                "self-evolution continuity round gap: previous {} current {}",
                evidence.previous_round, evidence.current_round
            )));
        }
        if self.require_feedback_carryover
            && evidence.previous_feedback_applied > 0
            && !evidence.feedback_carried_forward
        {
            decision = decision.merge(GateDecision::block(
                "previous feedback was not carried into self-improve",
            ));
        }
        if self.require_self_improve_passed
            && (!evidence.self_improve_checked || !evidence.self_improve_passed)
        {
            decision = decision.merge(GateDecision::block(
                "self-improve was not checked and passed for the follow-up round",
            ));
        }
        if self.require_validation_passed && !evidence.validation_passed {
            decision = decision.merge(GateDecision::block(
                "follow-up validation did not pass after self-improve",
            ));
        }

        decision
    }
}

