#[derive(Debug, Clone, PartialEq, Eq)]
pub struct NextRoundDecisionBoundaryContract {
    pub schema_name: &'static str,
    pub entrypoints: Vec<&'static str>,
    pub allowed_inputs: Vec<&'static str>,
    pub produced_outputs: Vec<&'static str>,
    pub forbidden_capabilities: Vec<&'static str>,
}

impl NextRoundDecisionBoundaryContract {
    pub fn next_round_decision_v1() -> Self {
        Self {
            schema_name: "next_round_decision_report_v1",
            entrypoints: vec![
                "NextRoundDecisionEvidence::from_reports",
                "NextRoundDecisionEvidence::current_round_active",
                "NextRoundDecisionEvidence::no_side_effects",
                "NextRoundDecisionGate::evaluate",
                "NextRoundDecisionReport::from_gate_and_evidence",
            ],
            allowed_inputs: vec![
                "LiveStatusBundleReport",
                "SelfEvolutionReadinessReport",
                "transition_kind",
                "active_round",
                "ledger_latest_round",
                "latest_done_round",
                "readiness_can_schedule_next_round",
                "report_gate_ready",
                "context_hygiene_passed",
            ],
            produced_outputs: vec![
                "GateDecision",
                "NextRoundDecisionReport",
                "next_round_decision_report_v1",
            ],
            forbidden_capabilities: vec![
                "dispatch_work",
                "prompt_replay",
                "process_start",
                "validation_command_spawn",
                "daemon_control",
                "runner_state",
                "service_call",
                "cli_execution",
                "http_sse",
                "jsonl_io",
                "file_io",
                "old_thread_read",
                "raw_dialog_payload_read",
                "completed_window_follow_up_reuse",
                "remote_mac_call",
                "model_download",
                "model_call",
                "chat_stream",
                "memory_store_write",
                "ndkv_write",
                "runtime_side_effect_execution",
            ],
        }
    }

    pub fn exposes_entrypoint(&self, entrypoint: &str) -> bool {
        self.entrypoints
            .iter()
            .any(|exposed| *exposed == entrypoint)
    }

    pub fn allows_input(&self, input: &str) -> bool {
        self.allowed_inputs.iter().any(|allowed| *allowed == input)
    }

    pub fn produces_output(&self, output: &str) -> bool {
        self.produced_outputs
            .iter()
            .any(|produced| *produced == output)
    }

    pub fn forbids_capability(&self, capability: &str) -> bool {
        self.forbidden_capabilities
            .iter()
            .any(|forbidden| *forbidden == capability)
    }

    pub fn schema_sources_within_boundary(&self, schema: &NextRoundDecisionReportSchema) -> bool {
        schema.fields.iter().all(|field| {
            field.source.starts_with("NextRoundDecision")
                || field.source.starts_with("LiveStatusBundleReport")
                || field.source.starts_with("SelfEvolutionReadinessReport")
        })
    }

    pub fn stays_pure_data_boundary(&self) -> bool {
        self.schema_name == "next_round_decision_report_v1"
            && self.exposes_entrypoint("NextRoundDecisionEvidence::from_reports")
            && self.exposes_entrypoint("NextRoundDecisionGate::evaluate")
            && self.exposes_entrypoint("NextRoundDecisionReport::from_gate_and_evidence")
            && self.allows_input("LiveStatusBundleReport")
            && self.allows_input("SelfEvolutionReadinessReport")
            && !self.allows_input("DaemonHandle")
            && !self.allows_input("ServiceClient")
            && !self.allows_input("CliExecutor")
            && !self.allows_input("PromptReplayer")
            && !self.allows_input("MemoryStore")
            && self.produces_output("NextRoundDecisionReport")
            && [
                "dispatch_work",
                "prompt_replay",
                "process_start",
                "daemon_control",
                "service_call",
                "cli_execution",
                "old_thread_read",
                "completed_window_follow_up_reuse",
                "model_call",
                "chat_stream",
                "memory_store_write",
                "ndkv_write",
                "runtime_side_effect_execution",
            ]
            .iter()
            .all(|capability| self.forbids_capability(capability))
    }
}

