#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RollbackResumeGate {
    pub stage: RootAdapterRolloutStage,
}

impl RollbackResumeGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self { stage }
    }

    pub fn evaluate(&self, evidence: &RollbackResumeEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced || evidence.resume_gate == "none" {
            return GateDecision::pass();
        }

        let mut decision = match evidence.resume_gate {
            "chain_readiness_gate" if evidence.chain_ready => GateDecision::pass(),
            "chain_readiness_gate" => GateDecision::block("chain readiness gate has not passed"),
            "runtime_backend_health_check" if evidence.backend_8686_reachable == Some(true) => {
                GateDecision::pass()
            }
            "runtime_backend_health_check" => {
                GateDecision::block("runtime backend 8686 health check has not passed")
            }
            "stream_continuity_validation" if evidence.stream_continuity_passed => {
                GateDecision::pass()
            }
            "stream_continuity_validation" => {
                GateDecision::block("stream continuity validation has not passed")
            }
            "runtime_response_gate" if evidence.runtime_response_passed => GateDecision::pass(),
            "runtime_response_gate" => GateDecision::block("runtime response gate has not passed"),
            "model_quality_review" if evidence.model_quality_review_passed => GateDecision::pass(),
            "model_quality_review" => GateDecision::block("model quality review has not passed"),
            "planned_validation_command" if evidence.validation_command_passed => {
                GateDecision::pass()
            }
            "planned_validation_command" => {
                GateDecision::block("planned validation command has not passed")
            }
            "manual_failure_classification" if evidence.manual_classification_done => {
                GateDecision::pass()
            }
            "manual_failure_classification" => {
                GateDecision::block("manual failure classification is still pending")
            }
            other => GateDecision::block(format!("unknown rollback resume gate {other}")),
        };

        if !evidence.steam_case_matrix_passed {
            decision = decision.merge(GateDecision::block(
                "Steam case matrix has not passed before unattended resume",
            ));
        }
        if !evidence.validation_command_coverage_passed {
            decision = decision.merge(GateDecision::block(
                "validation command coverage has not passed before unattended resume",
            ));
        }
        if !evidence.adapter_report_field_coverage_passed {
            decision = decision.merge(GateDecision::block(
                "adapter report field coverage has not passed before unattended resume",
            ));
        }

        decision
    }
}

