impl RollbackResumeReport {
    pub fn from_gate_and_evidence(
        gate: &RollbackResumeGate,
        evidence: &RollbackResumeEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            resume_gate: evidence.resume_gate,
            chain_ready: evidence.chain_ready,
            backend_8686_reachable: evidence.backend_8686_reachable,
            stream_continuity_passed: evidence.stream_continuity_passed,
            runtime_response_passed: evidence.runtime_response_passed,
            model_quality_review_passed: evidence.model_quality_review_passed,
            validation_command_passed: evidence.validation_command_passed,
            steam_case_matrix_passed: evidence.steam_case_matrix_passed,
            validation_command_coverage_passed: evidence.validation_command_coverage_passed,
            adapter_report_field_coverage_passed: evidence.adapter_report_field_coverage_passed,
            manual_classification_done: evidence.manual_classification_done,
            resume_blocked: decision.blocked,
            allow_unattended_rounds: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_evidence_for_stage(
        evidence: &RollbackResumeEvidence,
        stage: RootAdapterRolloutStage,
    ) -> Self {
        let gate = RollbackResumeGate::for_stage(stage);
        Self::from_gate_and_evidence(&gate, evidence)
    }
}

