#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ValidationCommandCoverageEvidence {
    pub observations: Vec<ValidationObservation>,
    pub rust_check_checked: bool,
    pub rust_check_passed: bool,
    pub strict_coverage_requested: bool,
    pub coverage_tooling_evidence: Vec<String>,
    pub coverage_report_evidence: Vec<String>,
}

impl ValidationCommandCoverageEvidence {
    pub fn from_observations<I>(observations: I) -> Self
    where
        I: IntoIterator<Item = ValidationObservation>,
    {
        Self {
            observations: observations.into_iter().collect(),
            rust_check_checked: false,
            rust_check_passed: false,
            strict_coverage_requested: false,
            coverage_tooling_evidence: Vec::new(),
            coverage_report_evidence: Vec::new(),
        }
    }

    pub fn with_rust_check(mut self, checked: bool, passed: bool) -> Self {
        self.rust_check_checked = checked;
        self.rust_check_passed = passed;
        self
    }

    pub fn with_strict_coverage_requested(mut self, requested: bool) -> Self {
        self.strict_coverage_requested = requested;
        self
    }

    pub fn with_strict_coverage_request_from_helper_stage(
        self,
        helper_stage: &HelperStageContractSummary,
    ) -> Self {
        self.with_strict_coverage_requested(helper_stage_requests_strict_coverage_control(
            helper_stage,
        ))
    }

    pub fn with_coverage_tooling_evidence<I, S>(mut self, evidence: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        self.coverage_tooling_evidence = evidence
            .into_iter()
            .map(Into::into)
            .filter(|value| !value.trim().is_empty())
            .collect();
        self
    }

    pub fn with_coverage_report_evidence<I, S>(mut self, evidence: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        self.coverage_report_evidence = evidence
            .into_iter()
            .map(Into::into)
            .filter(|value| !value.trim().is_empty())
            .collect();
        self
    }

    pub fn command_lines(&self) -> Vec<String> {
        self.observations
            .iter()
            .filter_map(|observation| {
                observation
                    .outcome
                    .as_ref()
                    .map(|outcome| outcome.command_line.clone())
            })
            .collect()
    }

    pub fn strict_coverage_is_requested(&self) -> bool {
        self.strict_coverage_requested
            || self
                .observations
                .iter()
                .filter_map(|observation| observation.outcome.as_ref())
                .any(|outcome| validation_command_mentions_strict_coverage(&outcome.command_line))
    }

    pub fn coverage_tooling_or_report_evidence_present(&self) -> bool {
        self.coverage_tooling_evidence
            .iter()
            .any(|value| !value.trim().is_empty())
            || self
                .coverage_report_evidence
                .iter()
                .any(|value| !value.trim().is_empty())
    }

    pub fn phase_names(&self) -> Vec<&'static str> {
        self.observations
            .iter()
            .map(|observation| verification_phase_name(&observation.phase))
            .collect()
    }

    pub fn status_codes_present(&self) -> usize {
        self.observations
            .iter()
            .filter(|observation| {
                observation
                    .outcome
                    .as_ref()
                    .is_some_and(|outcome| outcome.status_code.is_some())
            })
            .count()
    }

    pub fn output_tail_captured(&self) -> usize {
        self.observations
            .iter()
            .filter(|observation| {
                observation.outcome.as_ref().is_some_and(|outcome| {
                    !outcome.stdout_tail.is_empty() || !outcome.stderr_tail.is_empty()
                })
            })
            .count()
    }

    pub fn passed_commands(&self) -> usize {
        self.observations
            .iter()
            .filter(|observation| observation.checked && observation.passed)
            .count()
    }

    pub fn matching_phase_count(&self, required_phase: &VerificationPhase) -> usize {
        self.observations
            .iter()
            .filter(|observation| validation_phase_matches(&observation.phase, required_phase))
            .count()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ValidationCommandCoverageGate {
    pub stage: RootAdapterRolloutStage,
    pub min_commands: usize,
    pub required_phase: VerificationPhase,
    pub require_status_code: bool,
    pub require_output_tail: bool,
    pub require_all_commands_passed: bool,
    pub require_rust_check_passed: bool,
    pub require_strict_coverage_evidence: bool,
}

impl ValidationCommandCoverageGate {
    pub fn for_stage(stage: RootAdapterRolloutStage) -> Self {
        Self {
            stage,
            min_commands: 1,
            required_phase: VerificationPhase::PostRound,
            require_status_code: true,
            require_output_tail: true,
            require_all_commands_passed: true,
            require_rust_check_passed: stage == RootAdapterRolloutStage::Enforced,
            require_strict_coverage_evidence: stage == RootAdapterRolloutStage::Enforced,
        }
    }

    pub fn evaluate(&self, evidence: &ValidationCommandCoverageEvidence) -> GateDecision {
        if self.stage != RootAdapterRolloutStage::Enforced {
            return GateDecision::pass();
        }

        let mut decision = GateDecision::pass();
        if evidence.observations.len() < self.min_commands {
            decision = decision.merge(GateDecision::block(format!(
                "validation commands {} below minimum {}",
                evidence.observations.len(),
                self.min_commands
            )));
        }

        let matching_phase = evidence.matching_phase_count(&self.required_phase);
        if matching_phase < self.min_commands {
            decision = decision.merge(GateDecision::block(format!(
                "validation commands in required phase {} below minimum {}",
                matching_phase, self.min_commands
            )));
        }

        if self.require_status_code && evidence.status_codes_present() < evidence.observations.len()
        {
            decision = decision.merge(GateDecision::block(format!(
                "validation status codes present {}/{}",
                evidence.status_codes_present(),
                evidence.observations.len()
            )));
        }

        if self.require_output_tail && evidence.output_tail_captured() < evidence.observations.len()
        {
            decision = decision.merge(GateDecision::block(format!(
                "validation output tails captured {}/{}",
                evidence.output_tail_captured(),
                evidence.observations.len()
            )));
        }

        if self.require_all_commands_passed
            && evidence.passed_commands() < evidence.observations.len()
        {
            decision = decision.merge(GateDecision::block(format!(
                "validation commands passed {}/{}",
                evidence.passed_commands(),
                evidence.observations.len()
            )));
        }

        if self.require_rust_check_passed {
            if !evidence.rust_check_checked {
                decision =
                    decision.merge(GateDecision::block("rust-check command was not checked"));
            } else if !evidence.rust_check_passed {
                decision = decision.merge(GateDecision::block("rust-check command failed"));
            }
        }

        if self.require_strict_coverage_evidence
            && evidence.strict_coverage_is_requested()
            && !evidence.coverage_tooling_or_report_evidence_present()
        {
            decision = decision.merge(GateDecision::block(
                "strict coverage requested without coverage tooling or coverage report evidence",
            ));
        }

        decision
    }
}

