#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ValidationCommandCoverageReport {
    pub stage: &'static str,
    pub command_lines: Vec<String>,
    pub phases: Vec<&'static str>,
    pub status_codes_present: usize,
    pub output_tail_captured: usize,
    pub passed_commands: usize,
    pub rust_check_checked: bool,
    pub rust_check_passed: bool,
    pub strict_coverage_requested: bool,
    pub coverage_tooling_evidence: Vec<String>,
    pub coverage_report_evidence: Vec<String>,
    pub coverage_tooling_or_report_evidence_present: bool,
    pub coverage_blocked: bool,
    pub coverage_failure_kind: &'static str,
    pub model_quality_failure_counted: bool,
    pub failure_reasons: Vec<String>,
    pub allow_next_round: bool,
}

impl ValidationCommandCoverageReport {
    pub fn from_gate_and_evidence(
        gate: &ValidationCommandCoverageGate,
        evidence: &ValidationCommandCoverageEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            command_lines: evidence.command_lines(),
            phases: evidence.phase_names(),
            status_codes_present: evidence.status_codes_present(),
            output_tail_captured: evidence.output_tail_captured(),
            passed_commands: evidence.passed_commands(),
            rust_check_checked: evidence.rust_check_checked,
            rust_check_passed: evidence.rust_check_passed,
            strict_coverage_requested: evidence.strict_coverage_is_requested(),
            coverage_tooling_evidence: evidence.coverage_tooling_evidence.clone(),
            coverage_report_evidence: evidence.coverage_report_evidence.clone(),
            coverage_tooling_or_report_evidence_present: evidence
                .coverage_tooling_or_report_evidence_present(),
            coverage_blocked: decision.blocked,
            coverage_failure_kind: if decision.blocked {
                "validation_command_coverage"
            } else {
                "none"
            },
            model_quality_failure_counted: false,
            allow_next_round: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_observations_and_gate<I>(
        observations: I,
        rust_check_checked: bool,
        rust_check_passed: bool,
        gate: &ValidationCommandCoverageGate,
    ) -> Self
    where
        I: IntoIterator<Item = ValidationObservation>,
    {
        let evidence = ValidationCommandCoverageEvidence::from_observations(observations)
            .with_rust_check(rust_check_checked, rust_check_passed);
        Self::from_gate_and_evidence(gate, &evidence)
    }
}

