#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StrictUnattendedSupervisorEvidence {
    pub supervisor_status_observed: bool,
    pub daemon_running: bool,
    pub strict_unattended_evolution_enabled: bool,
    pub configured_validation_enabled: bool,
    pub stale_pid_detected: bool,
    pub starts_process: bool,
    pub sends_prompt: bool,
    pub touches_remote: bool,
}

impl StrictUnattendedSupervisorEvidence {
    pub fn from_status(
        supervisor_status_observed: bool,
        daemon_running: bool,
        strict_unattended_evolution_enabled: bool,
        configured_validation_enabled: bool,
    ) -> Self {
        Self {
            supervisor_status_observed,
            daemon_running,
            strict_unattended_evolution_enabled,
            configured_validation_enabled,
            stale_pid_detected: false,
            starts_process: false,
            sends_prompt: false,
            touches_remote: false,
        }
    }

    pub fn with_stale_pid_detected(mut self, stale_pid_detected: bool) -> Self {
        self.stale_pid_detected = stale_pid_detected;
        self
    }

    pub fn with_side_effect_flags(
        mut self,
        starts_process: bool,
        sends_prompt: bool,
        touches_remote: bool,
    ) -> Self {
        self.starts_process = starts_process;
        self.sends_prompt = sends_prompt;
        self.touches_remote = touches_remote;
        self
    }

    pub fn check_only(&self) -> bool {
        !self.starts_process && !self.sends_prompt && !self.touches_remote
    }

    pub fn failure_reasons(&self) -> Vec<String> {
        let mut reasons = Vec::new();
        if !self.supervisor_status_observed {
            reasons.push("strict unattended supervisor status was not observed".to_owned());
        }
        if !self.daemon_running {
            reasons.push("strict unattended daemon is not running".to_owned());
        }
        if !self.strict_unattended_evolution_enabled {
            reasons.push("strict unattended evolution flag is not enabled".to_owned());
        }
        if !self.configured_validation_enabled {
            reasons.push("configured validation is not enabled".to_owned());
        }
        if self.stale_pid_detected {
            reasons.push("strict unattended daemon status reports a stale pid".to_owned());
        }
        if self.starts_process {
            reasons.push(
                "supervisor evidence started a process instead of remaining check-only".to_owned(),
            );
        }
        if self.sends_prompt {
            reasons.push("supervisor evidence sent a prompt".to_owned());
        }
        if self.touches_remote {
            reasons.push("supervisor evidence touched remote runtime state".to_owned());
        }
        reasons
    }

    pub fn allow_next_round(&self) -> bool {
        self.failure_reasons().is_empty()
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StrictUnattendedAcceptanceReport {
    pub supervisor_status_observed: bool,
    pub daemon_running: bool,
    pub strict_unattended_evolution_enabled: bool,
    pub configured_validation_enabled: bool,
    pub supervisor_check_only: bool,
    pub stale_pid_detected: bool,
    pub starts_process: bool,
    pub sends_prompt: bool,
    pub touches_remote: bool,
    pub supervisor_allow_next_round: bool,
    pub report_refresh_allow_next_round: bool,
    pub adapter_closure_allow_next_round: bool,
    pub validation_allow_next_round: bool,
    pub rollback_resume_allow_unattended_rounds: bool,
    pub self_improve_regression_allow_unattended_continuation: bool,
    pub readiness_can_schedule_next_round: bool,
    pub self_evolution_allow_unattended_claim: bool,
    pub allow_next_round: bool,
    pub failure_reasons: Vec<String>,
}

impl StrictUnattendedAcceptanceReport {
    pub fn from_reports(
        supervisor: &StrictUnattendedSupervisorEvidence,
        report_refresh: &RunModeReportRefreshAcceptanceReport,
        adapter_closure: &AdapterClosureReport,
        validation: &ValidationCommandCoverageReport,
        rollback_resume: &RollbackResumeReport,
        regression: &SelfEvolutionRegressionReport,
        readiness: &SelfEvolutionReadinessReport,
        self_evolution: &SelfEvolutionUnattendedPrerequisiteReport,
    ) -> Self {
        let mut failure_reasons = supervisor.failure_reasons();

        if !report_refresh.allow_next_round {
            failure_reasons.extend(report_refresh.failure_reasons.iter().cloned());
        }
        if !adapter_closure.allow_next_round {
            failure_reasons.extend(adapter_closure.ledger_gate_report.failure_reasons.clone());
            failure_reasons.extend(
                adapter_closure
                    .validation_command_coverage
                    .failure_reasons
                    .clone(),
            );
            failure_reasons.extend(adapter_closure.readiness.failure_reasons.clone());
            if adapter_closure.rollback.required {
                failure_reasons.push(format!(
                    "adapter closure requires rollback via {}",
                    adapter_closure.rollback.resume_gate
                ));
            }
        }
        if !validation.allow_next_round {
            failure_reasons.extend(validation.failure_reasons.iter().cloned());
        }
        if !rollback_resume.allow_unattended_rounds {
            failure_reasons.extend(rollback_resume.failure_reasons.iter().cloned());
        }
        if !regression.allow_unattended_continuation {
            failure_reasons.extend(regression.failure_reasons.iter().cloned());
        }
        if !readiness.can_schedule_next_round {
            failure_reasons.extend(readiness.failure_reasons.iter().cloned());
        }
        if !self_evolution.allow_unattended_self_evolution_claim {
            failure_reasons.extend(self_evolution.failure_reasons.iter().cloned());
        }

        failure_reasons.sort();
        failure_reasons.dedup();

        let supervisor_allow_next_round = supervisor.allow_next_round();
        let allow_next_round = supervisor_allow_next_round
            && report_refresh.allow_next_round
            && adapter_closure.allow_next_round
            && validation.allow_next_round
            && rollback_resume.allow_unattended_rounds
            && regression.allow_unattended_continuation
            && readiness.can_schedule_next_round
            && self_evolution.allow_unattended_self_evolution_claim;

        Self {
            supervisor_status_observed: supervisor.supervisor_status_observed,
            daemon_running: supervisor.daemon_running,
            strict_unattended_evolution_enabled: supervisor.strict_unattended_evolution_enabled,
            configured_validation_enabled: supervisor.configured_validation_enabled,
            supervisor_check_only: supervisor.check_only(),
            stale_pid_detected: supervisor.stale_pid_detected,
            starts_process: supervisor.starts_process,
            sends_prompt: supervisor.sends_prompt,
            touches_remote: supervisor.touches_remote,
            supervisor_allow_next_round,
            report_refresh_allow_next_round: report_refresh.allow_next_round,
            adapter_closure_allow_next_round: adapter_closure.allow_next_round,
            validation_allow_next_round: validation.allow_next_round,
            rollback_resume_allow_unattended_rounds: rollback_resume.allow_unattended_rounds,
            self_improve_regression_allow_unattended_continuation: regression
                .allow_unattended_continuation,
            readiness_can_schedule_next_round: readiness.can_schedule_next_round,
            self_evolution_allow_unattended_claim: self_evolution
                .allow_unattended_self_evolution_claim,
            allow_next_round,
            failure_reasons,
        }
    }
}

