            && self.requires_prior_report("adapter_closure_report_v1")
            && self.requires_prior_report("validation_command_coverage_report_v1")
            && self.requires_prior_report("rollback_resume_report_v1")
            && self.requires_prior_report("self_evolution_regression_report_v1")
            && self.requires_prior_report("readiness_next_round_v1")
            && self.requires_prior_report("self_evolution_unattended_prerequisites_report_v1")
