#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerWindowReplacementEvidence {
    pub worker_window_id: String,
    pub evidence_ids: Vec<String>,
    pub paused: bool,
    pub polluted: bool,
    pub stale: bool,
    pub clean_room_replacement_required: bool,
    pub old_thread_read_attempted: bool,
    pub side_effects_observed: bool,
}

impl WorkerWindowReplacementEvidence {
    pub fn clean(worker_window_id: impl Into<String>) -> Self {
        Self {
            worker_window_id: worker_window_id.into(),
            evidence_ids: Vec::new(),
            paused: false,
            polluted: false,
            stale: false,
            clean_room_replacement_required: false,
            old_thread_read_attempted: false,
            side_effects_observed: false,
        }
    }

    pub fn with_evidence_ids<I, S>(mut self, evidence_ids: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        self.evidence_ids = evidence_ids.into_iter().map(Into::into).collect();
        self
    }

    pub fn with_status(
        mut self,
        paused: bool,
        polluted: bool,
        stale: bool,
        clean_room_replacement_required: bool,
    ) -> Self {
        self.paused = paused;
        self.polluted = polluted;
        self.stale = stale;
        self.clean_room_replacement_required =
            clean_room_replacement_required || paused || polluted || stale;
        self
    }

    pub fn with_old_thread_read_attempted(mut self, old_thread_read_attempted: bool) -> Self {
        self.old_thread_read_attempted = old_thread_read_attempted;
        self
    }

    pub fn with_side_effects_observed(mut self, side_effects_observed: bool) -> Self {
        self.side_effects_observed = side_effects_observed;
        self
    }

    pub fn no_old_thread_reads(&self) -> bool {
        !self.old_thread_read_attempted
    }

    pub fn no_side_effects(&self) -> bool {
        !self.side_effects_observed
    }

    pub fn evidence_ids_only(&self) -> bool {
        !self.evidence_ids.is_empty()
            && self.evidence_ids.iter().all(|evidence_id| {
                let lower = evidence_id.to_ascii_lowercase();
                ![
                    "old_thread_payload",
                    "old-window-payload",
                    "chat_transcript",
                    "raw_context",
                    "prompt_text",
                    "filesystem_path",
                ]
                .iter()
                .any(|forbidden| lower.contains(forbidden))
            })
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerWindowReplacementGate {
    pub require_no_paused: bool,
    pub require_no_polluted: bool,
    pub require_no_stale: bool,
    pub require_no_old_thread_reads: bool,
    pub require_no_side_effects: bool,
    pub require_evidence_ids_only: bool,
}

impl WorkerWindowReplacementGate {
    pub fn strict() -> Self {
        Self {
            require_no_paused: true,
            require_no_polluted: true,
            require_no_stale: true,
            require_no_old_thread_reads: true,
            require_no_side_effects: true,
            require_evidence_ids_only: true,
        }
    }

    pub fn evaluate(&self, evidence: &WorkerWindowReplacementEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_no_paused && evidence.paused {
            decision = decision.merge(GateDecision::block(
                "worker window is paused and requires clean-room replacement",
            ));
        }
        if self.require_no_polluted && evidence.polluted {
            decision = decision.merge(GateDecision::block(
                "worker window is polluted and requires clean-room replacement",
            ));
        }
        if self.require_no_stale && evidence.stale {
            decision = decision.merge(GateDecision::block(
                "worker window is stale and requires clean-room replacement",
            ));
        }
        if self.require_no_old_thread_reads && !evidence.no_old_thread_reads() {
            decision = decision.merge(GateDecision::block(
                "worker window replacement evidence attempted an old-thread read",
            ));
        }
        if self.require_no_side_effects && !evidence.no_side_effects() {
            decision = decision.merge(GateDecision::block(
                "worker window replacement evidence observed side effects",
            ));
        }
        if self.require_evidence_ids_only && !evidence.evidence_ids_only() {
            decision = decision.merge(GateDecision::block(
                "worker window replacement report must carry evidence ids only",
            ));
        }
        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerWindowReplacementReport {
    pub worker_window_id: String,
    pub evidence_ids: Vec<String>,
    pub paused: bool,
    pub polluted: bool,
    pub stale: bool,
    pub clean_room_replacement_required: bool,
    pub no_old_thread_reads: bool,
    pub no_side_effects: bool,
    pub evidence_ids_only: bool,
    pub allow_worker_continuation: bool,
    pub failure_reasons: Vec<String>,
}

impl WorkerWindowReplacementReport {
    pub fn from_gate_and_evidence(
        gate: &WorkerWindowReplacementGate,
        evidence: &WorkerWindowReplacementEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);
        Self {
            worker_window_id: evidence.worker_window_id.clone(),
            evidence_ids: evidence.evidence_ids.clone(),
            paused: evidence.paused,
            polluted: evidence.polluted,
            stale: evidence.stale,
            clean_room_replacement_required: evidence.clean_room_replacement_required
                || decision.blocked,
            no_old_thread_reads: evidence.no_old_thread_reads(),
            no_side_effects: evidence.no_side_effects(),
            evidence_ids_only: evidence.evidence_ids_only(),
            allow_worker_continuation: !decision.blocked
                && !evidence.clean_room_replacement_required,
            failure_reasons: decision.reasons,
        }
    }
}

