#[derive(Debug, Clone, PartialEq, Eq)]
pub struct StatusDrivenSelfEvolutionClosureGate {
    pub require_memory_startup_admission_safe: bool,
    pub require_worker_replacement: bool,
    pub require_clean_room_assignment_allowed: bool,
    pub require_no_old_thread_reads: bool,
    pub require_no_live_writes: bool,
    pub require_no_runtime_side_effects: bool,
    pub require_report_only_continuation: bool,
    pub require_evidence_ids_only: bool,
}

impl StatusDrivenSelfEvolutionClosureGate {
    pub fn strict() -> Self {
        Self {
            require_memory_startup_admission_safe: true,
            require_worker_replacement: true,
            require_clean_room_assignment_allowed: true,
            require_no_old_thread_reads: true,
            require_no_live_writes: true,
            require_no_runtime_side_effects: true,
            require_report_only_continuation: true,
            require_evidence_ids_only: true,
        }
    }

    pub fn evaluate(&self, evidence: &StatusDrivenSelfEvolutionClosureEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_memory_startup_admission_safe && !evidence.memory_startup_admission_safe {
            decision = decision.merge(GateDecision::block(
                "memory startup admission is not safe for status-driven closure",
            ));
        }
        if self.require_worker_replacement && !evidence.worker_replacement_required {
            decision = decision.merge(GateDecision::block(
                "status-driven closure requires worker replacement",
            ));
        }
        if self.require_clean_room_assignment_allowed && !evidence.clean_room_assignment_allowed {
            decision = decision.merge(GateDecision::block("clean-room assignment is not allowed"));
        }
        if self.require_no_old_thread_reads && !evidence.no_old_thread_reads() {
            decision = decision.merge(GateDecision::block(
                "status-driven closure evidence attempted an old-thread read",
            ));
        }
        if self.require_no_live_writes && !evidence.no_live_writes() {
            decision = decision.merge(GateDecision::block(
                "status-driven closure evidence attempted a live write",
            ));
        }
        if self.require_no_runtime_side_effects && !evidence.no_runtime_side_effects() {
            decision = decision.merge(GateDecision::block(
                "status-driven closure evidence observed runtime side effects",
            ));
        }
        if self.require_report_only_continuation && !evidence.report_only_continuation {
            decision = decision.merge(GateDecision::block(
                "status-driven closure must remain report-only continuation",
            ));
        }
        if self.require_evidence_ids_only && !evidence.evidence_ids_only() {
            decision = decision.merge(GateDecision::block(
                "status-driven closure report must carry evidence ids only",
            ));
        }
        decision
    }
}

