#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CleanRoomHandoffGate {
    pub require_memory_startup_admission_input_present: bool,
    pub require_memory_startup_admission_safe: bool,
    pub require_agent_replacement_plan_input_present: bool,
    pub require_agent_replacement_plan_clean_room_required: bool,
    pub require_source_json_retained: bool,
    pub require_source_json_not_parsed_as_prompt_or_live_write: bool,
    pub require_no_old_thread_reads: bool,
    pub require_side_effects_all_false: bool,
    pub require_report_only_continuation: bool,
    pub require_evidence_ids_only: bool,
}

impl CleanRoomHandoffGate {
    pub fn strict() -> Self {
        Self {
            require_memory_startup_admission_input_present: true,
            require_memory_startup_admission_safe: true,
            require_agent_replacement_plan_input_present: true,
            require_agent_replacement_plan_clean_room_required: true,
            require_source_json_retained: true,
            require_source_json_not_parsed_as_prompt_or_live_write: true,
            require_no_old_thread_reads: true,
            require_side_effects_all_false: true,
            require_report_only_continuation: true,
            require_evidence_ids_only: true,
        }
    }

    pub fn evaluate(&self, evidence: &CleanRoomHandoffEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();
        if self.require_memory_startup_admission_input_present
            && !evidence.memory_startup_admission_input_present
        {
            decision = decision.merge(GateDecision::block(
                "memory startup admission input is missing",
            ));
        }
        if self.require_memory_startup_admission_safe && !evidence.memory_startup_admission_safe {
            decision = decision.merge(GateDecision::block(
                "memory startup admission is not safe for clean-room handoff",
            ));
        }
        if self.require_agent_replacement_plan_input_present
            && !evidence.agent_replacement_plan_input_present
        {
            decision = decision.merge(GateDecision::block(
                "agent clean-room replacement plan input is missing",
            ));
        }
        if self.require_agent_replacement_plan_clean_room_required
            && !evidence.agent_replacement_plan_clean_room_required
        {
            decision = decision.merge(GateDecision::block(
                "agent replacement plan does not require clean-room replacement",
            ));
        }
        if self.require_source_json_retained && !evidence.source_json_retained() {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff source JSON was not retained",
            ));
        }
        if self.require_source_json_not_parsed_as_prompt_or_live_write
            && !evidence.source_json_not_parsed_as_prompt_or_live_write()
        {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff source JSON was parsed as prompt or live write",
            ));
        }
        if self.require_no_old_thread_reads && !evidence.no_old_thread_reads() {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff evidence attempted an old-thread read",
            ));
        }
        if self.require_side_effects_all_false && !evidence.side_effects_all_false() {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff side effects must all remain false",
            ));
        }
        if self.require_report_only_continuation && !evidence.report_only_continuation {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff must remain report-only continuation",
            ));
        }
        if self.require_evidence_ids_only && !evidence.evidence_ids_only() {
            decision = decision.merge(GateDecision::block(
                "clean-room handoff report must carry evidence ids only",
            ));
        }
        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CleanRoomHandoffReport {
    pub evidence_ids: Vec<String>,
    pub memory_startup_admission_input_present: bool,
    pub memory_startup_admission_safe: bool,
    pub agent_replacement_plan_input_present: bool,
    pub agent_replacement_plan_clean_room_required: bool,
    pub source_json_input_names: Vec<String>,
    pub source_json_retained: bool,
    pub source_json_not_parsed_as_prompt_or_live_write: bool,
    pub side_effects_all_false: bool,
    pub no_old_thread_reads: bool,
    pub evidence_ids_only: bool,
    pub report_only_continuation: bool,
    pub allow_report_only_continuation: bool,
    pub allow_runtime_continuation: bool,
    pub failure_reasons: Vec<String>,
}

impl CleanRoomHandoffReport {
    pub fn from_gate_and_evidence(
        gate: &CleanRoomHandoffGate,
        evidence: &CleanRoomHandoffEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);
        Self {
            evidence_ids: evidence.evidence_ids.clone(),
            memory_startup_admission_input_present: evidence.memory_startup_admission_input_present,
            memory_startup_admission_safe: evidence.memory_startup_admission_safe,
            agent_replacement_plan_input_present: evidence.agent_replacement_plan_input_present,
            agent_replacement_plan_clean_room_required: evidence
                .agent_replacement_plan_clean_room_required,
            source_json_input_names: evidence
                .source_json
                .iter()
                .map(|source| source.input_name.clone())
                .collect(),
            source_json_retained: evidence.source_json_retained(),
            source_json_not_parsed_as_prompt_or_live_write: evidence
                .source_json_not_parsed_as_prompt_or_live_write(),
            side_effects_all_false: evidence.side_effects_all_false(),
            no_old_thread_reads: evidence.no_old_thread_reads(),
            evidence_ids_only: evidence.evidence_ids_only(),
            report_only_continuation: evidence.report_only_continuation,
            allow_report_only_continuation: !decision.blocked,
            allow_runtime_continuation: false,
            failure_reasons: decision.reasons,
        }
    }
}

