impl SelfImproveProposalMemoryAdmissionRequestReport {
    pub fn from_readiness_report(
        report: &SelfImproveProposalMemoryAdmissionReadinessReport,
    ) -> Self {
        let request_items = report
            .readiness_items
            .iter()
            .map(SelfImproveProposalMemoryAdmissionRequestItem::from_readiness_item)
            .collect::<Vec<_>>();
        let request_count = request_items
            .iter()
            .filter(|item| item.ready_for_memory_admission)
            .count();
        let first_candidate = request_items.first();

        Self {
            target_count: report.target_count,
            request_count,
            blocked_count: report.target_count.saturating_sub(request_count),
            first_candidate_id: first_candidate.map(|item| item.proposal_id.clone()),
            first_candidate_ready: first_candidate
                .is_some_and(|item| item.ready_for_memory_admission),
            all_ready_targets_requested: report.target_count > 0
                && report.all_closed_targets_ready
                && request_count == report.target_count,
            writer_required: request_count > 0,
            report_only: true,
            candidate_only: true,
            auto_apply: false,
            memory_store_write_allowed: false,
            ndkv_write_allowed: false,
            request_items,
        }
    }
}

