impl SelfImproveProposalMemoryAdmissionWriterPlanReport {
    pub fn from_request_and_decision(
        request: &SelfImproveProposalMemoryAdmissionRequestReport,
        decision: &SelfImproveProposalMemoryAdmissionDecisionReport,
    ) -> Self {
        let writer_plan_ready = decision.admission_writer_preflight_passed
            && request.request_count > 0
            && request.blocked_count == 0
            && request.all_ready_targets_requested
            && request.writer_required
            && request.report_only
            && request.candidate_only
            && !request.auto_apply
            && !request.memory_store_write_allowed
            && !request.ndkv_write_allowed
            && !decision.admission_write_authorized;
        let plan_items = request
            .request_items
            .iter()
            .map(|item| {
                SelfImproveProposalMemoryAdmissionWriterPlanItem::from_request_item(
                    item,
                    writer_plan_ready,
                )
            })
            .collect::<Vec<_>>();
        let ready_plan_count = plan_items
            .iter()
            .filter(|item| item.ready_for_writer_invocation)
            .count();
        let mut failure_reasons = decision.failure_reasons.clone();
        if request.request_count == 0 {
            failure_reasons.push("writer plan has no requested candidates".to_owned());
        }
        if decision.admission_write_authorized {
            failure_reasons.push(
                "writer plan input already authorized writes before explicit writer".to_owned(),
            );
        }
        failure_reasons.sort();
        failure_reasons.dedup();

        Self {
            target_count: request.target_count,
            request_count: request.request_count,
            writer_plan_item_count: plan_items.len(),
            ready_plan_count,
            blocked_count: plan_items.len().saturating_sub(ready_plan_count),
            first_plan_item_id: plan_items.first().map(|item| item.proposal_id.clone()),
            writer_plan_ready,
            explicit_writer_invocation_required: writer_plan_ready,
            experiment_required: writer_plan_ready,
            rollback_required: writer_plan_ready,
            validation_required: writer_plan_ready,
            admission_write_authorized: false,
            failure_reasons,
            report_only: true,
            candidate_only: true,
            auto_apply: false,
            memory_store_write_allowed: false,
            ndkv_write_allowed: false,
            plan_items,
        }
    }
}

impl SelfImproveProposalMemoryAdmissionWriterDryRunReport {
    pub fn from_writer_plan(plan: &SelfImproveProposalMemoryAdmissionWriterPlanReport) -> Self {
        let dry_run_ready = plan.writer_plan_ready
            && plan.ready_plan_count > 0
            && plan.blocked_count == 0
            && plan.explicit_writer_invocation_required
            && plan.experiment_required
            && plan.rollback_required
            && plan.validation_required
            && plan.report_only
            && plan.candidate_only
            && !plan.auto_apply
            && !plan.memory_store_write_allowed
            && !plan.ndkv_write_allowed
            && !plan.admission_write_authorized;
        let dry_run_items = plan
            .plan_items
            .iter()
            .map(|item| {
                SelfImproveProposalMemoryAdmissionWriterDryRunItem::from_writer_plan_item(
                    item,
                    dry_run_ready,
                )
            })
            .collect::<Vec<_>>();
        let ready_dry_run_count = dry_run_items
            .iter()
            .filter(|item| item.ready_for_dry_run)
            .count();
        let mut failure_reasons = plan.failure_reasons.clone();
        if plan.writer_plan_item_count == 0 {
            failure_reasons.push("writer dry-run has no writer plan items".to_owned());
        }
        if !plan.writer_plan_ready {
            failure_reasons.push("writer dry-run requires ready writer plan".to_owned());
        }
        if plan.admission_write_authorized {
            failure_reasons
                .push("writer dry-run input already authorized writes before dry-run".to_owned());
        }
        failure_reasons.sort();
        failure_reasons.dedup();

        Self {
            target_count: plan.target_count,
            request_count: plan.request_count,
            writer_plan_item_count: plan.writer_plan_item_count,
            dry_run_item_count: dry_run_items.len(),
            ready_dry_run_count,
            blocked_count: dry_run_items.len().saturating_sub(ready_dry_run_count),
            first_dry_run_item_id: dry_run_items.first().map(|item| item.proposal_id.clone()),
            dry_run_ready,
            explicit_writer_invocation_required: dry_run_ready,
            dry_run_required: dry_run_ready,
            experiment_required: dry_run_ready,
            rollback_required: dry_run_ready,
            validation_required: dry_run_ready,
            admission_write_authorized: false,
            failure_reasons,
            report_only: true,
            candidate_only: true,
            auto_apply: false,
            memory_store_write_allowed: false,
            ndkv_write_allowed: false,
            dry_run_items,
        }
    }
}

