impl SelfImproveProposalMemoryAdmissionCommitRecordStageReport {
    pub fn from_dry_run_receipt(
        report: &SelfImproveProposalMemoryAdmissionWriterDryRunReceiptReport,
    ) -> Self {
        let commit_record_stage_ready = report.dry_run_receipt_ready
            && report.succeeded_receipt_count > 0
            && report.blocked_count == 0
            && report.receipt_item_count == report.succeeded_receipt_count
            && report.explicit_writer_invocation_required
            && report.validation_required
            && report.rollback_required
            && report.report_only
            && report.candidate_only
            && !report.auto_apply
            && !report.commit_allowed
            && !report.admission_write_authorized
            && !report.memory_store_write_allowed
            && !report.ndkv_write_allowed;
        let commit_record_items = report
            .receipt_items
            .iter()
            .map(|item| {
                SelfImproveProposalMemoryAdmissionCommitRecordStageItem::from_receipt_item(
                    item,
                    commit_record_stage_ready,
                )
            })
            .collect::<Vec<_>>();
        let staged_commit_record_count = commit_record_items
            .iter()
            .filter(|item| item.commit_record_staged)
            .count();
        let mut failure_reasons = report.failure_reasons.clone();
        if report.receipt_item_count == 0 {
            failure_reasons.push("commit record staging has no dry-run receipts".to_owned());
        }
        if !report.dry_run_receipt_ready {
            failure_reasons
                .push("commit record staging requires ready dry-run receipt report".to_owned());
        }
        if report.receipt_item_count != report.succeeded_receipt_count || report.blocked_count > 0 {
            failure_reasons
                .push("commit record staging requires all dry-run receipts to succeed".to_owned());
        }
        if report.commit_allowed || report.admission_write_authorized {
            failure_reasons.push(
                "commit record staging input already authorized writes before commit approval"
                    .to_owned(),
            );
        }
        if report.auto_apply {
            failure_reasons.push("commit record staging input attempted auto apply".to_owned());
        }
        if report.memory_store_write_allowed {
            failure_reasons
                .push("commit record staging input allowed memory store writes".to_owned());
        }
        if report.ndkv_write_allowed {
            failure_reasons.push("commit record staging input allowed ndkv writes".to_owned());
        }
        failure_reasons.sort();
        failure_reasons.dedup();

        Self {
            target_count: report.target_count,
            request_count: report.request_count,
            receipt_item_count: report.receipt_item_count,
            commit_record_item_count: commit_record_items.len(),
            staged_commit_record_count,
            blocked_count: commit_record_items
                .len()
                .saturating_sub(staged_commit_record_count),
            first_commit_record_item_id: commit_record_items
                .first()
                .map(|item| item.proposal_id.clone()),
            commit_record_stage_ready,
            explicit_writer_invocation_required: commit_record_stage_ready,
            validation_required: commit_record_stage_ready,
            rollback_required: commit_record_stage_ready,
            commit_allowed: false,
            admission_write_authorized: false,
            failure_reasons,
            report_only: true,
            candidate_only: true,
            auto_apply: false,
            memory_store_write_allowed: false,
            ndkv_write_allowed: false,
            commit_record_items,
        }
    }
}

