impl SelfImproveProposalMemoryAdmissionWriterDryRunReceiptItem {
    pub fn from_dry_run_item(
        item: &SelfImproveProposalMemoryAdmissionWriterDryRunItem,
        dry_run_receipt_ready: bool,
    ) -> Self {
        let dry_run_succeeded = dry_run_receipt_ready
            && item.ready_for_dry_run
            && item.dry_run_required
            && item.validation_required
            && item.report_only
            && item.candidate_only
            && !item.auto_apply
            && !item.memory_store_write_allowed
            && !item.ndkv_write_allowed
            && !item.write_authorized
            && !item.admission_write_authorized
            && item.blocked_reasons.is_empty();
        let mut blocked_reasons = item.blocked_reasons.clone();
        if !dry_run_succeeded {
            if !dry_run_receipt_ready {
                blocked_reasons.push("writer_dry_run_receipt_preflight_not_passed".to_owned());
            }
            if !item.ready_for_dry_run {
                blocked_reasons.push("writer_dry_run_item_not_ready".to_owned());
            }
            if !item.dry_run_required {
                blocked_reasons.push("writer_dry_run_item_missing_dry_run_requirement".to_owned());
            }
            if !item.validation_required {
                blocked_reasons.push("writer_dry_run_item_missing_validation".to_owned());
            }
            if item.write_authorized || item.admission_write_authorized {
                blocked_reasons.push("writer_dry_run_item_already_authorized_write".to_owned());
            }
            if item.auto_apply {
                blocked_reasons.push("writer_dry_run_item_attempted_auto_apply".to_owned());
            }
            if item.memory_store_write_allowed {
                blocked_reasons.push("writer_dry_run_item_memory_store_write_allowed".to_owned());
            }
            if item.ndkv_write_allowed {
                blocked_reasons.push("writer_dry_run_item_ndkv_write_allowed".to_owned());
            }
        }
        blocked_reasons.sort();
        blocked_reasons.dedup();
        let preview_memory_record_id = format!(
            "memory-admission-preview:{}",
            writer_plan_slug(&item.proposal_id)
        );
        let idempotency_key = format!(
            "memory-admission-dry-run:{}:{}",
            item.experiment_id,
            writer_plan_slug(&item.proposal_id)
        );
        let content_digest = writer_receipt_content_digest(item);

        Self {
            proposal_id: item.proposal_id.clone(),
            source_round: item.source_round,
            dry_run_succeeded,
            planned_writer_action: if dry_run_succeeded {
                "record_explicit_memory_admission_writer_dry_run_receipt".to_owned()
            } else {
                "hold_until_writer_dry_run_receipt_preflight_passes".to_owned()
            },
            preview_memory_record_id,
            idempotency_key,
            content_digest,
            evidence_ids: item.evidence_ids.clone(),
            experiment_id: item.experiment_id.clone(),
            rollback_anchor_ids: item.rollback_anchor_ids.clone(),
            validation_required: dry_run_succeeded,
            rollback_required: dry_run_succeeded,
            write_authorized: false,
            admission_write_authorized: false,
            blocked_reasons,
            report_only: true,
            candidate_only: true,
            auto_apply: false,
            memory_store_write_allowed: false,
            ndkv_write_allowed: false,
        }
    }
}

fn writer_plan_experiment_id(source_round: Option<u64>, proposal_id: &str) -> String {
    format!(
        "self-improve-memory-admission-r{}-{}",
        source_round.unwrap_or_default(),
        writer_plan_slug(proposal_id)
    )
}

fn writer_plan_rollback_anchor_ids(
    item: &SelfImproveProposalMemoryAdmissionRequestItem,
) -> Vec<String> {
    let mut anchors = vec![
        format!("pre_admission_snapshot:{}", item.proposal_id),
        format!("request_bundle:{}", item.proposal_id),
    ];
    anchors.extend(item.evidence_ids.iter().cloned());
    anchors.sort();
    anchors.dedup();
    anchors
}

fn writer_plan_slug(value: &str) -> String {
    let slug = value
        .chars()
        .filter(|character| character.is_ascii_alphanumeric())
        .map(|character| character.to_ascii_lowercase())
        .take(32)
        .collect::<String>();
    if slug.is_empty() {
        "candidate".to_owned()
    } else {
        slug
    }
}

fn writer_receipt_content_digest(
    item: &SelfImproveProposalMemoryAdmissionWriterDryRunItem,
) -> String {
    let mut hash = 0xcbf29ce484222325u64;
    for byte in item.proposal_id.bytes() {
        hash = (hash ^ byte as u64).wrapping_mul(0x100000001b3);
    }
    for byte in item.experiment_id.bytes() {
        hash = (hash ^ byte as u64).wrapping_mul(0x100000001b3);
    }
    for evidence_id in &item.evidence_ids {
        for byte in evidence_id.bytes() {
            hash = (hash ^ byte as u64).wrapping_mul(0x100000001b3);
        }
    }
    format!("fnv1a64:{hash:016x}")
}

