#[derive(Debug, Clone, PartialEq)]
pub struct SteamRoundAcceptanceGate {
    pub require_stream_continuity: bool,
    pub require_runtime_response: bool,
    pub require_validation_observation: bool,
    pub require_next_round_readiness: bool,
}

impl SteamRoundAcceptanceGate {
    pub fn strict() -> Self {
        Self {
            require_stream_continuity: true,
            require_runtime_response: true,
            require_validation_observation: true,
            require_next_round_readiness: true,
        }
    }

    pub fn evaluate(&self, evidence: &SteamRoundAcceptanceEvidence) -> GateDecision {
        let mut decision = GateDecision::pass();

        if self.require_stream_continuity && !evidence.stream.passed() {
            decision = decision.merge(GateDecision::block(format!(
                "steam case {} stream failed: {}",
                evidence.case_id,
                evidence
                    .stream
                    .failure_reason()
                    .unwrap_or_else(|| "unknown stream failure".to_owned())
            )));
        }

        if self.require_runtime_response {
            decision =
                decision.merge(RuntimeResponseGate::strict().evaluate(&evidence.ledger_record));
        }

        if self.require_validation_observation {
            if !evidence.validation.checked {
                decision = decision.merge(GateDecision::block(format!(
                    "steam case {} validation observation was not checked",
                    evidence.case_id
                )));
            } else if !evidence.validation.passed {
                decision = decision.merge(GateDecision::block(format!(
                    "steam case {} validation observation failed",
                    evidence.case_id
                )));
            }
            decision = decision.merge(ValidationGate::strict().evaluate(&evidence.ledger_record));
        }

        if self.require_next_round_readiness {
            decision = decision.merge(evidence.readiness_snapshot.next_round_decision());
        }

        decision
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SteamRoundAcceptanceReportSchema {
    pub fields: Vec<ReportSchemaField>,
}

impl SteamRoundAcceptanceReportSchema {
    pub fn steam_round_v1() -> Self {
        Self {
            fields: vec![
                ReportSchemaField {
                    name: "steam_round.case_id",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "SteamRoundAcceptanceEvidence::case_id",
                },
                ReportSchemaField {
                    name: "steam_round.stream_passed",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "StreamContinuityCheck::passed",
                },
                ReportSchemaField {
                    name: "steam_round.validation_checked",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "ValidationObservation::checked",
                },
                ReportSchemaField {
                    name: "steam_round.validation_passed",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "ValidationObservation::passed",
                },
                ReportSchemaField {
                    name: "steam_round.runtime_tokens",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "LedgerRecord::runtime_tokens",
                },
                ReportSchemaField {
                    name: "steam_round.runtime_model",
                    stage: ReportSchemaStage::ReportOnly,
                    source: "LedgerRecord::runtime_model",
                },
                ReportSchemaField {
                    name: "steam_round.acceptance_blocked",
                    stage: ReportSchemaStage::Enforced,
                    source: "SteamRoundAcceptanceGate::evaluate",
                },
                ReportSchemaField {
                    name: "steam_round.failure_reasons",
                    stage: ReportSchemaStage::Enforced,
                    source: "SteamRoundAcceptanceGate::evaluate reasons",
                },
                ReportSchemaField {
                    name: "steam_round.can_schedule_next_round",
                    stage: ReportSchemaStage::Enforced,
                    source: "SelfEvolutionReadinessSnapshot::can_schedule_next_round",
                },
            ],
        }
    }

    pub fn field_names(&self) -> Vec<&'static str> {
        self.fields.iter().map(|field| field.name).collect()
    }

    pub fn fields_for_stage(&self, stage: RootAdapterRolloutStage) -> Vec<&ReportSchemaField> {
        match stage {
            RootAdapterRolloutStage::ShadowOnly => Vec::new(),
            RootAdapterRolloutStage::ReportOnly => self
                .fields
                .iter()
                .filter(|field| field.stage == ReportSchemaStage::ReportOnly)
                .collect(),
            RootAdapterRolloutStage::Enforced => self.fields.iter().collect(),
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
