#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SteamCaseCoverageReport {
    pub stage: &'static str,
    pub case_count: usize,
    pub min_cases: usize,
    pub case_ids: Vec<String>,
    pub case_kinds: Vec<&'static str>,
    pub endpoints: Vec<String>,
    pub required_case_kinds: Vec<&'static str>,
    pub required_final_json_fields: Vec<&'static str>,
    pub missing_required_case_kinds: Vec<&'static str>,
    pub missing_required_fields: Vec<String>,
    pub stream_passed_cases: usize,
    pub validation_passed_cases: usize,
    pub business_cycle_passed_cases: usize,
    pub coverage_blocked: bool,
    pub failure_reasons: Vec<String>,
    pub allow_enforced_adapter: bool,
}

impl SteamCaseCoverageReport {
    pub fn from_gate_and_evidence(
        gate: &SteamCaseCoverageGate,
        evidence: &SteamCaseCoverageEvidence,
    ) -> Self {
        let decision = gate.evaluate(evidence);

        Self {
            stage: gate.stage.as_str(),
            case_count: evidence.case_count(),
            min_cases: gate.min_cases,
            case_ids: evidence.case_ids(),
            case_kinds: evidence.case_kinds(),
            endpoints: evidence.endpoints(),
            required_case_kinds: gate
                .required_case_kinds
                .iter()
                .map(SteamCaseKind::as_str)
                .collect(),
            required_final_json_fields: gate.required_final_json_fields.clone(),
            missing_required_case_kinds: evidence
                .missing_required_case_kinds(&gate.required_case_kinds),
            missing_required_fields: evidence
                .missing_required_fields(&gate.required_final_json_fields),
            stream_passed_cases: evidence.stream_passed_cases(),
            validation_passed_cases: evidence.validation_passed_cases(),
            business_cycle_passed_cases: evidence.business_cycle_passed_cases(),
            coverage_blocked: decision.blocked,
            allow_enforced_adapter: !decision.blocked,
            failure_reasons: decision.reasons,
        }
    }

    pub fn from_rows_and_gate<I>(rows: I, gate: &SteamCaseCoverageGate) -> Self
    where
        I: IntoIterator<Item = SteamCaseCoverageRow>,
    {
        let evidence = SteamCaseCoverageEvidence::from_rows(rows);
        Self::from_gate_and_evidence(gate, &evidence)
    }
}

