    #[test]
    fn context_rot_trend_gate_allows_clean_or_improved_window() {
        let points = vec![
            ContextRotTrendPoint::new(
                10,
                ContextRotSignal::clean()
                    .with_noisy_records(2)
                    .with_duplicate_outputs(1)
                    .with_max_noise_penalty(0.2),
            ),
            ContextRotTrendPoint::new(
                11,
                ContextRotSignal::clean()
                    .with_noisy_records(1)
                    .with_max_noise_penalty(0.1),
            )
            .with_remediation_applied(true),
            ContextRotTrendPoint::new(12, ContextRotSignal::clean()),
        ];
        let summary = ContextRotTrendWindowSummary::from_points(&points);
        let gate = ContextRotTrendGate {
            max_consecutive_noisy_rounds: 2,
            max_consecutive_duplicate_rounds: 1,
            ..ContextRotTrendGate::strict()
        };
        let decision = gate.evaluate(&summary);
        let report = ContextRotTrendReport::from_summary_and_decision(&summary, &decision);
        let points_report = ContextRotTrendReport::from_points_and_gate(&points, &gate);

        assert!(!decision.blocked);
        assert_eq!(points_report, report);
        assert_eq!(report.rounds, 3);
        assert_eq!(report.first_round, Some(10));
        assert_eq!(report.last_round, Some(12));
        assert_eq!(report.latest_noisy_records, 0);
        assert_eq!(report.latest_duplicate_outputs, 0);
        assert_eq!(report.noisy_records_delta, -2);
        assert_eq!(report.duplicate_outputs_delta, -1);
        assert_eq!(report.max_consecutive_noisy_rounds, 2);
        assert_eq!(report.max_consecutive_duplicate_rounds, 1);
        assert_eq!(report.remediation_applied_rounds, 1);
        assert!(report.remediation_improved_noise);
        assert!(report.remediation_improved_duplicates);
        assert!(report.allow_unattended_continuation);
    }

    #[test]
    fn context_rot_trend_gate_blocks_consecutive_noise_duplicates_and_failed_remediation() {
        let points = vec![
            ContextRotTrendPoint::new(
                20,
                ContextRotSignal::clean()
                    .with_noisy_records(1)
                    .with_duplicate_outputs(1)
                    .with_max_noise_penalty(0.1),
            ),
            ContextRotTrendPoint::new(
                21,
                ContextRotSignal::clean()
                    .with_noisy_records(2)
                    .with_duplicate_outputs(1)
                    .with_max_noise_penalty(0.2),
            )
            .with_remediation_applied(true),
            ContextRotTrendPoint::new(
                22,
                ContextRotSignal::clean()
                    .with_noisy_records(3)
                    .with_duplicate_outputs(2)
                    .with_max_noise_penalty(0.3),
            ),
        ];
        let summary = ContextRotTrendWindowSummary::from_points(&points);
        let decision = ContextRotTrendGate::strict().evaluate(&summary);
        let report = ContextRotTrendReport::from_summary_and_decision(&summary, &decision);

        assert!(decision.blocked);
        assert!(report.trend_blocked);
        assert!(!report.allow_unattended_continuation);
        assert_eq!(report.max_consecutive_noisy_rounds, 3);
        assert_eq!(report.max_consecutive_duplicate_rounds, 3);
        assert_eq!(report.noisy_records_delta, 2);
        assert_eq!(report.duplicate_outputs_delta, 1);
        assert!(!report.remediation_improved_noise);
        assert!(!report.remediation_improved_duplicates);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("latest noisy records"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("consecutive noisy rounds"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("duplicate-output"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("did not improve noise trend"))
        );
    }

