    #[test]
    fn adapter_context_rot_trend_boundary_contract_matches_norion_test_plan() {
        let contract = AdapterContextRotTrendBoundaryContract::context_rot_trend_v1();
        let plan = norion_test::AdapterContextRotTrendBoundaryPlan::context_rot_trend_boundary(
            "context-rot-trend-boundary",
            norion_test::AdapterAcceptanceStage::Enforced,
        );
        let entrypoints = contract
            .entrypoints
            .iter()
            .map(|entrypoint| entrypoint.to_string())
            .collect::<Vec<_>>();
        let allowed_inputs = contract
            .allowed_inputs
            .iter()
            .map(|input| input.to_string())
            .collect::<Vec<_>>();
        let produced_outputs = contract
            .produced_outputs
            .iter()
            .map(|output| output.to_string())
            .collect::<Vec<_>>();
        let forbidden_capabilities = contract
            .forbidden_capabilities
            .iter()
            .map(|capability| capability.to_string())
            .collect::<Vec<_>>();

        assert_eq!(plan.eval_entrypoints, entrypoints);
        assert_eq!(plan.allowed_inputs, allowed_inputs);
        assert_eq!(plan.produced_outputs, produced_outputs);
        assert_eq!(plan.forbidden_capabilities, forbidden_capabilities);
        assert!(contract.exposes_entrypoint("ContextRotTrendWindowSummary::from_points"));
        assert!(contract.exposes_entrypoint("ContextRotTrendGate::evaluate"));
        assert!(contract.exposes_entrypoint("ContextRotTrendReport::from_points_and_gate"));
        assert!(contract.allows_input("ContextRotSignal"));
        assert!(contract.allows_input("ContextRotTrendPoint"));
        assert!(contract.allows_input("ContextRotTrendGate"));
        assert!(!contract.allows_input("FilesystemScanner"));
        assert!(!contract.allows_input("JsonlReader"));
        assert!(contract.produces_output("ContextRotTrendWindowSummary"));
        assert!(contract.produces_output("GateDecision"));
        assert!(contract.produces_output("ContextRotTrendReport"));
        assert!(contract.stays_pure_data_boundary());
        assert!(contract.forbids_capability("jsonl_io"));
        assert!(contract.forbids_capability("filesystem_scan"));
        assert!(contract.forbids_capability("quarantine_action_execution"));
        assert!(contract.forbids_capability("clean_gist_write"));
        assert!(contract.forbids_capability("duplicate_output_delete"));
        assert!(contract.forbids_capability("model_call"));
        assert!(plan.stays_pure_data_boundary());
        assert!(!plan.may_block_current_runner());
        assert!(plan.preserves_legacy_runner);
    }

