    #[test]
    fn experiment_expansion_safety_lifts_scheduling_reports_without_runner_io() {
        let flag = ExperimentFlag::enabled("multi-model-pool", "runtime-team", 5);
        let validation_gate =
            ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let validation_report = ValidationCommandCoverageReport::from_observations_and_gate(
            [ValidationObservation::skipped(VerificationPhase::PostRound)],
            false,
            false,
            &validation_gate,
        );
        let steam_gate = SteamCaseCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let steam_report = SteamCaseCoverageReport::from_rows_and_gate(
            [SteamCaseCoverageRow::business_cycle("planning-only")],
            &steam_gate,
        );
        let readiness_snapshot =
            SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced)
                .with_validation_command_coverage_decision(validation_command_decision_from_report(
                    &validation_report,
                ))
                .with_steam_case_matrix_decision(steam_case_coverage_decision_from_report(
                    &steam_report,
                ));
        let readiness_report = SelfEvolutionReadinessReport::from_snapshot(&readiness_snapshot);
        let rollback_report = RollbackReport::from_plan(&readiness_snapshot.rollback_plan(), None);
        let rollback_resume_report = RollbackResumeReport::from_evidence_for_stage(
            &RollbackResumeEvidence::for_resume_gate(rollback_report.resume_gate),
            RootAdapterRolloutStage::Enforced,
        );
        let evidence = ExperimentExpansionSafetyEvidence::ready(vec![flag])
            .with_scheduling_reports(
                &readiness_report,
                &rollback_report,
                &rollback_resume_report,
                &steam_report,
                &validation_report,
            );
        let gate = ExperimentExpansionSafetyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ExperimentExpansionSafetyReport::from_gate_and_evidence(&gate, &evidence);

        assert!(report.rollback_report_present);
        assert!(!report.rollback_resume_passed);
        assert!(!report.readiness_passed);
        assert!(!report.steam_case_matrix_passed);
        assert!(!report.validation_command_coverage_passed);
        assert!(report.expansion_blocked);
        assert!(!report.allow_experiment_expansion);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("rollback resume")
                || reason.contains("Steam case matrix")
                || reason.contains("validation command coverage")
        }));
        assert!(readiness_report.rollback_required);
        assert!(rollback_report.required);
        assert!(validation_report.coverage_blocked);
        assert!(steam_report.coverage_blocked);
    }

