    fn experiment_expansion_safety_detects_operational_quality_confusion() {
        let flag = ExperimentFlag::enabled("multi-model-pool", "runtime-team", 5);
        let evidence = ExperimentExpansionSafetyEvidence::ready(vec![flag])
            .with_root_adapter_failure_kind(RootAdapterFailureKind::ChainNotReady)
            .with_reported_model_quality_failures(1);
        let gate = ExperimentExpansionSafetyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ExperimentExpansionSafetyReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.root_adapter_failure_kind, "chain_not_ready");
        assert_eq!(report.reported_model_quality_failures, 1);
        assert_eq!(report.classified_model_quality_failures, 0);
        assert!(report.expansion_blocked);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("reported 1 quality failure") && reason.contains("classified 0")
        }));
    }

