    #[test]
    fn experiment_expansion_safety_schema_sources_match_norion_test_plan() {
        let schema = ExperimentExpansionSafetyReportSchema::experiment_expansion_safety_v1();
        let plan = norion_test::ExperimentExpansionSafetyReportPlan::experiment_expansion_safety(
            "experiment-expansion-source-contract",
            norion_test::AdapterAcceptanceStage::Enforced,
        );
        let source_for = |field_name: &str| {
            schema
                .fields
                .iter()
                .find(|field| field.name == field_name)
                .map(|field| field.source)
                .expect("schema field source")
        };

        for field_name in [
            "experiment_expansion.readiness_passed",
            "experiment_expansion.rollback_report_present",
            "experiment_expansion.rollback_resume_passed",
            "experiment_expansion.steam_case_matrix_passed",
            "experiment_expansion.validation_command_coverage_passed",
        ] {
            assert!(plan.uses_operational_report_source(source_for(field_name)));
        }

        assert_eq!(
            source_for("experiment_expansion.readiness_passed"),
            "SelfEvolutionReadinessReport::can_schedule_next_round"
        );
        assert_eq!(
            source_for("experiment_expansion.rollback_report_present"),
            "RollbackReport::present"
        );
        assert_eq!(
            source_for("experiment_expansion.rollback_resume_passed"),
            "RollbackResumeReport::allow_unattended_rounds"
        );
        assert_eq!(
            source_for("experiment_expansion.steam_case_matrix_passed"),
            "SteamCaseCoverageReport::allow_enforced_adapter"
        );
        assert_eq!(
            source_for("experiment_expansion.validation_command_coverage_passed"),
            "ValidationCommandCoverageReport::allow_next_round"
        );
        assert!(!plan.uses_operational_report_source("JsonlLedgerReader::scan"));
        assert!(!plan.uses_operational_report_source("ValidationCommandExecutor::spawn"));
        assert!(plan.stays_pure_data_boundary());
    }

