    #[test]
    fn experiment_switch_matrix_allows_reported_passing_enabled_flags() {
        let pool_flag = ExperimentFlag::enabled("multi-model-pool", "runtime-team", 5);
        let tester_flag = ExperimentFlag::enabled("parallel-testers", "quality-team", 5);
        let disabled_flag = ExperimentFlag::disabled("summarizer-shadow", "docs-team");
        let gate = ExperimentExpansionSafetyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let pool_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![pool_flag.clone()]),
        );
        let tester_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![tester_flag.clone()]),
        );
        let evidence = ExperimentSwitchMatrixEvidence::from_flags_and_reports(
            vec![pool_flag, tester_flag, disabled_flag],
            vec![pool_report, tester_report],
        );
        let matrix_gate = ExperimentSwitchMatrixGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ExperimentSwitchMatrixReport::from_gate_and_evidence(&matrix_gate, &evidence);

        assert_eq!(
            report.enabled_flag_names,
            vec!["multi-model-pool", "parallel-testers"]
        );
        assert_eq!(
            report.reported_enabled_flag_names,
            vec!["multi-model-pool", "parallel-testers"]
        );
        assert!(report.missing_enabled_flag_reports.is_empty());
        assert!(report.duplicate_enabled_flag_reports.is_empty());
        assert!(report.unknown_enabled_flag_reports.is_empty());
        assert_eq!(report.expansion_report_count, 2);
        assert!(report.all_enabled_reported);
        assert!(report.exactly_one_report_per_enabled_flag);
        assert!(report.all_expansion_reports_passed);
        assert!(!report.switch_matrix_blocked);
        assert!(report.allow_experiment_switch_expansion);
    }

    #[test]
    fn experiment_switch_matrix_helper_lifts_expansion_reports_without_runner_io() {
        let pool_flag = ExperimentFlag::enabled("multi-model-pool", "runtime-team", 5);
        let tester_flag = ExperimentFlag::enabled("parallel-testers", "quality-team", 5);
        let disabled_flag = ExperimentFlag::disabled("summarizer-shadow", "docs-team");
        let expansion_gate =
            ExperimentExpansionSafetyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let pool_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &expansion_gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![pool_flag.clone()]),
        );
        let blocked_tester_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &expansion_gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![tester_flag.clone()])
                .with_validation_command_coverage_passed(false),
        );
        let disabled_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &expansion_gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![disabled_flag.clone()]),
        );
        let matrix_gate = ExperimentSwitchMatrixGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ExperimentSwitchMatrixReport::from_flags_and_reports(
            &matrix_gate,
            vec![pool_flag, tester_flag, disabled_flag],
            vec![pool_report, blocked_tester_report, disabled_report],
        );
        let schema = ExperimentSwitchMatrixReportSchema::experiment_switch_matrix_v1();
        let source_for = |name: &str| {
            schema
                .fields
                .iter()
                .find(|field| field.name == name)
                .map(|field| field.source)
                .unwrap()
        };

        assert_eq!(report.expansion_report_count, 3);
        assert!(report.missing_enabled_flag_reports.is_empty());
        assert_eq!(
            report.unknown_enabled_flag_reports,
            vec!["summarizer-shadow"]
        );
        assert_eq!(report.blocked_expansion_reports, vec!["parallel-testers"]);
        assert!(report.all_enabled_reported);
        assert!(!report.exactly_one_report_per_enabled_flag);
        assert!(!report.all_expansion_reports_passed);
        assert!(report.switch_matrix_blocked);
        assert!(!report.allow_experiment_switch_expansion);
        assert_eq!(
            source_for("experiment_switch.reported_enabled_flag_names"),
            "ExperimentExpansionSafetyReport::enabled_flag_names"
        );
        assert_eq!(
            source_for("experiment_switch.blocked_expansion_reports"),
            "ExperimentExpansionSafetyReport::expansion_blocked"
        );
        assert_eq!(
            source_for("experiment_switch.all_expansion_reports_passed"),
            "ExperimentExpansionSafetyReport::allow_experiment_expansion"
        );
        for field in schema.fields {
            assert!(!field.source.contains("Jsonl"));
            assert!(!field.source.contains("Runner"));
            assert!(!field.source.contains("Executor"));
            assert!(!field.source.contains("http_sse"));
            assert!(!field.source.contains("model_call"));
            assert!(!field.source.contains("process_spawn"));
        }
    }

    #[test]
    fn experiment_switch_matrix_blocks_missing_or_blocked_enabled_flags() {
        let pool_flag = ExperimentFlag::enabled("multi-model-pool", "runtime-team", 5);
        let tester_flag = ExperimentFlag::enabled("parallel-testers", "quality-team", 5);
        let gate = ExperimentExpansionSafetyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let blocked_report = ExperimentExpansionSafetyReport::from_gate_and_evidence(
            &gate,
            &ExperimentExpansionSafetyEvidence::ready(vec![pool_flag.clone()])
                .with_context_rot_trend_passed(false),
        );
        let evidence = ExperimentSwitchMatrixEvidence::from_flags_and_reports(
            vec![pool_flag, tester_flag],
            vec![blocked_report],
        );
        let matrix_gate = ExperimentSwitchMatrixGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ExperimentSwitchMatrixReport::from_gate_and_evidence(&matrix_gate, &evidence);

        assert_eq!(
            report.missing_enabled_flag_reports,
            vec!["parallel-testers"]
        );
        assert!(report.duplicate_enabled_flag_reports.is_empty());
        assert!(report.unknown_enabled_flag_reports.is_empty());
        assert_eq!(report.blocked_expansion_reports, vec!["multi-model-pool"]);
        assert!(!report.all_enabled_reported);
        assert!(!report.exactly_one_report_per_enabled_flag);
        assert!(!report.all_expansion_reports_passed);
        assert!(report.switch_matrix_blocked);
        assert!(!report.allow_experiment_switch_expansion);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("missing expansion reports") && reason.contains("parallel-testers")
        }));
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("experiment expansion reports blocked")
                && reason.contains("multi-model-pool")
        }));
    }

