    #[test]
    fn last_failure_policy_can_be_relaxed() {
        let records = vec![
            LedgerRecord::success(1, 24, "google/gemma"),
            LedgerRecord::failure(2, "operator stopped after report")
                .with_final_present(true)
                .with_feedback(1),
        ];
        let summary = LedgerSummary::from_records(&records);
        let gate = ReportGate {
            min_success_rate: 0.5,
            min_feedback_total: Some(1),
            require_last_success: false,
            max_missing_final_failures: 0,
            max_runtime_response_failures: 0,
            ..ReportGate::strict()
        };

        assert_eq!(summary.last_success, Some(false));
        assert!(!gate.evaluate(&summary).blocked);
    }

    #[test]
    fn rollback_reason_is_stable_for_report_gate_failures() {
        let records = vec![LedgerRecord::success(1, 0, "google/gemma").with_feedback(0)];
        let summary = LedgerSummary::from_records(&records);
        let decision = ReportGate::strict().evaluate(&summary);
        let rollback = RollbackPlan::from_decision(&decision);

        assert!(rollback.required);
        assert_eq!(
            rollback.reason,
            "feedback_applied 0 below minimum 1; runtime response failures 1 above maximum 0"
        );
    }

