    #[test]
    fn model_pool_development_attribution_names_per_worker_claim_blockers() {
        let workers = vec![
            ModelWorkerRecord::new("planner-1", ModelRole::Planner, "gemma-planner")
                .with_runtime(800, 64)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true),
            ModelWorkerRecord::new("reviewer-1", ModelRole::Reviewer, "gemma-reviewer")
                .with_runtime(900, 80)
                .with_success(true)
                .with_feedback(0)
                .with_validation(true, false)
                .with_output_quality(true, true),
            ModelWorkerRecord::new("tester-1", ModelRole::Tester, "gemma-tester")
                .with_runtime(0, 0)
                .with_success(false)
                .with_validation(false, false)
                .with_primary_blocked(true),
        ];
        let evidence = ModelPoolDevelopmentAttributionEvidence::from_workers_and_failures(
            workers,
            [RootAdapterFailureKind::None],
        );
        let summary = ModelPoolDevelopmentAttributionSummary::from_evidence(&evidence);
        let gate =
            ModelPoolDevelopmentAttributionGate::apple_silicon(RootAdapterRolloutStage::Enforced);
        let report = ModelPoolDevelopmentAttributionReport::from_gate_and_summary(&gate, &summary);

        assert_eq!(
            report.worker_development_claim_allowed,
            vec![true, false, false]
        );
        assert!(report.worker_claim_blockers[1].contains(&"feedback_not_applied"));
        assert!(report.worker_claim_blockers[1].contains(&"validation_not_passed"));
        assert!(report.worker_claim_blockers[1].contains(&"duplicate_output"));
        assert!(report.worker_claim_blockers[1].contains(&"noisy_output"));
        assert!(report.worker_claim_blockers[2].contains(&"worker_not_successful"));
        assert!(report.worker_claim_blockers[2].contains(&"missing_latency_ms"));
        assert!(report.worker_claim_blockers[2].contains(&"missing_runtime_tokens"));
        assert!(report.worker_claim_blockers[2].contains(&"validation_not_checked"));
        assert!(report.worker_claim_blockers[2].contains(&"blocked_primary_12b"));
        assert!(report.attribution_blocked);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("worker claim blockers")
                && reason.contains("reviewer-1")
                && reason.contains("tester-1")
        }));
    }

    #[test]
    fn model_pool_development_attribution_blocks_prompt_gate_outage_without_quality_failure() {
        let workers = vec![
            ModelWorkerRecord::new("planner-1", ModelRole::Planner, "gemma-planner")
                .with_runtime(900, 64)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true)
                .with_failure_kind(RootAdapterFailureKind::ChainNotReady),
            ModelWorkerRecord::new("reviewer-1", ModelRole::Reviewer, "gemma-reviewer")
                .with_runtime(900, 64)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true)
                .with_failure_kind(RootAdapterFailureKind::ChainNotReady),
            ModelWorkerRecord::new("tester-1", ModelRole::Tester, "gemma-tester")
                .with_runtime(900, 64)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true)
                .with_failure_kind(RootAdapterFailureKind::ChainNotReady),
        ];
        let root_evidence = RootAdapterFailureEvidence {
            backend_8686_reachable: Some(false),
            prompt_gate_blocked: true,
            final_json_present: false,
            runtime_model_present: false,
            runtime_tokens: None,
            business_cycle_passed: None,
            error: Some("prompt-gate blocked while backend 8686 was down".to_owned()),
        };
        let root_kind = classify_root_adapter_failure(&root_evidence);
        let evidence = ModelPoolDevelopmentAttributionEvidence::from_workers_and_failures(
            workers,
            [root_kind],
        );
        let summary = ModelPoolDevelopmentAttributionSummary::from_evidence(&evidence);
        let gate =
            ModelPoolDevelopmentAttributionGate::apple_silicon(RootAdapterRolloutStage::Enforced);
        let report = ModelPoolDevelopmentAttributionReport::from_gate_and_summary(&gate, &summary);

        assert_eq!(root_kind, RootAdapterFailureKind::ChainNotReady);
        assert_eq!(
            report.failure_kinds,
            vec!["chain_not_ready", "chain_not_ready", "chain_not_ready"]
        );
        assert_eq!(report.chain_not_ready_count, 1);
        assert_eq!(report.model_unavailable_count, 0);
        assert_eq!(report.operational_readiness_failures, 1);
        assert_eq!(report.model_quality_failure_count, 0);
        assert_eq!(report.reported_model_quality_failures, 0);
        assert!(report.worker_claim_blockers[0].contains(&"operational_readiness_failure"));
        assert!(!report.worker_claim_blockers[0].contains(&"model_quality_failure"));
        assert!(report.attribution_blocked);
        assert!(!report.allow_development_claim);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("without counting as model quality failure") })
        );
    }

