    #[test]
    fn model_pool_development_attribution_schema_names_worker_metrics_and_claim_gate() {
        let schema =
            ModelPoolDevelopmentAttributionReportSchema::model_pool_development_attribution_v1();
        let names = schema.field_names();
        let report_only_names = schema
            .fields_for_stage(RootAdapterRolloutStage::ReportOnly)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforced_names = schema
            .fields_for_stage(RootAdapterRolloutStage::Enforced)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();

        assert!(names.contains(&"model_pool_attribution.latency_ms"));
        assert!(names.contains(&"model_pool_attribution.runtime_tokens"));
        assert!(names.contains(&"model_pool_attribution.success"));
        assert!(names.contains(&"model_pool_attribution.validation_checked"));
        assert!(names.contains(&"model_pool_attribution.validation_passed"));
        assert!(names.contains(&"model_pool_attribution.duplicate_output"));
        assert!(names.contains(&"model_pool_attribution.noisy_output"));
        assert!(names.contains(&"model_pool_attribution.blocked_primary_12b"));
        assert!(names.contains(&"model_pool_attribution.failure_kinds"));
        assert!(names.contains(&"model_pool_attribution.worker_development_claim_allowed"));
        assert!(names.contains(&"model_pool_attribution.worker_claim_blockers"));
        assert!(report_only_names.contains(&"model_pool_attribution.failure_kinds"));
        assert!(
            report_only_names.contains(&"model_pool_attribution.worker_development_claim_allowed")
        );
        assert!(report_only_names.contains(&"model_pool_attribution.worker_claim_blockers"));
        assert!(
            report_only_names.contains(&"model_pool_attribution.operational_readiness_failures")
        );
        assert!(report_only_names.contains(&"model_pool_attribution.chain_not_ready_count"));
        assert!(report_only_names.contains(&"model_pool_attribution.model_unavailable_count"));
        assert!(!report_only_names.contains(&"model_pool_attribution.allow_development_claim"));
        assert!(enforced_names.contains(&"model_pool_attribution.attribution_blocked"));
        assert!(enforced_names.contains(&"model_pool_attribution.allow_development_claim"));
    }

    fn clean_apple_silicon_development_effect_evidence(
        root_adapter_failure: RootAdapterFailureKind,
    ) -> AppleSiliconDevelopmentEffectEvidence {
        let workers = vec![
            ModelWorkerRecord::new("planner-1", ModelRole::Planner, "gemma-planner")
                .with_runtime(900, 80)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true),
            ModelWorkerRecord::new("reviewer-1", ModelRole::Reviewer, "gemma-reviewer")
                .with_runtime(800, 72)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true),
            ModelWorkerRecord::new("tester-1", ModelRole::Tester, "gemma-tester")
                .with_runtime(850, 76)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true),
        ];

        let attribution_evidence =
            ModelPoolDevelopmentAttributionEvidence::from_workers_and_failures(
                workers.clone(),
                [root_adapter_failure],
            );
        let attribution_summary =
            ModelPoolDevelopmentAttributionSummary::from_evidence(&attribution_evidence);
        let attribution_gate =
            ModelPoolDevelopmentAttributionGate::apple_silicon(RootAdapterRolloutStage::Enforced);
        let attribution_report = ModelPoolDevelopmentAttributionReport::from_gate_and_summary(
            &attribution_gate,
            &attribution_summary,
        );

        let budget_gate = ModelPoolBudgetFairnessGate::apple_silicon_development();
        let budget_summary =
            ModelPoolBudgetFairnessSummary::from_workers(&workers, &budget_gate.roles());
        let budget_decision = budget_gate.evaluate(&budget_summary);
        let budget_report = ModelPoolBudgetFairnessReport::from_summary_and_decision(
            &budget_summary,
            &budget_decision,
        );

        let window_records = vec![
            ModelPoolDevelopmentWindowRecord {
                round: 10,
                feedback_delta: 1,
                latency_multiplier: 1.0,
                token_multiplier: 1.0,
                pool_gate_blocked: false,
                development_gate_blocked: false,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
            ModelPoolDevelopmentWindowRecord {
                round: 11,
                feedback_delta: 1,
                latency_multiplier: 1.0,
                token_multiplier: 1.0,
                pool_gate_blocked: false,
                development_gate_blocked: false,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
            ModelPoolDevelopmentWindowRecord {
                round: 12,
                feedback_delta: 1,
                latency_multiplier: 1.0,
                token_multiplier: 1.0,
                pool_gate_blocked: false,
                development_gate_blocked: false,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
        ];
        let window_summary = ModelPoolDevelopmentWindowSummary::from_records(&window_records);
        let window_gate = AppleSiliconDevelopmentWindowGate::conservative();
        let window_report =
            ModelPoolDevelopmentWindowReport::from_gate_and_summary(&window_gate, &window_summary);

        let baseline_records = vec![
            AppleSiliconBaselineComparisonRecord {
                round: 10,
                baseline_12b_feedback_applied: 1,
                pool_feedback_applied_total: 2,
                baseline_12b_latency_ms: 2000,
                pool_latency_ms_total: 2400,
                baseline_12b_runtime_tokens: 128,
                pool_runtime_tokens_total: 192,
                baseline_12b_success: true,
                pool_success: true,
                baseline_12b_validation_passed: true,
                pool_validation_passed: true,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
            AppleSiliconBaselineComparisonRecord {
                round: 11,
                baseline_12b_feedback_applied: 1,
                pool_feedback_applied_total: 2,
                baseline_12b_latency_ms: 2000,
                pool_latency_ms_total: 2300,
                baseline_12b_runtime_tokens: 128,
                pool_runtime_tokens_total: 192,
                baseline_12b_success: true,
                pool_success: true,
                baseline_12b_validation_passed: true,
                pool_validation_passed: true,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
            AppleSiliconBaselineComparisonRecord {
                round: 12,
                baseline_12b_feedback_applied: 1,
                pool_feedback_applied_total: 2,
                baseline_12b_latency_ms: 2000,
                pool_latency_ms_total: 2200,
                baseline_12b_runtime_tokens: 128,
                pool_runtime_tokens_total: 192,
                baseline_12b_success: true,
                pool_success: true,
                baseline_12b_validation_passed: true,
                pool_validation_passed: true,
                duplicate_outputs: 0,
                noisy_outputs: 0,
                primary_12b_blockers: 0,
                root_adapter_failure_kind: root_adapter_failure.as_code(),
            },
        ];
        let baseline_gate =
            AppleSiliconBaselineComparisonGate::conservative(RootAdapterRolloutStage::Enforced);
        let baseline_summary =
            AppleSiliconBaselineComparisonSummary::from_records(&baseline_records, 1.5, 2.0);
        let baseline_report = AppleSiliconBaselineComparisonReport::from_gate_and_summary(
            &baseline_gate,
            &baseline_summary,
        );

        AppleSiliconDevelopmentEffectEvidence::from_reports(
            attribution_report,
            budget_report,
            window_report,
            baseline_report,
            root_adapter_failure,
        )
    }

