    #[test]
    fn model_worker_gate_report_allows_clean_development_claim() {
        let workers = vec![
            ModelWorkerRecord::new("planner-1", ModelRole::Planner, "gemma-small")
                .with_runtime(800, 64)
                .with_success(true)
                .with_feedback(2)
                .with_validation(true, true),
            ModelWorkerRecord::new("tester-1", ModelRole::Tester, "gemma-test")
                .with_runtime(900, 64)
                .with_success(true)
                .with_feedback(1)
                .with_validation(true, true),
        ];
        let summary = ModelPoolSummary::from_workers(&workers);
        let pool_decision = ModelPoolGate::strict().evaluate(&summary);
        let effect =
            ModelPoolDevelopmentEffect::from_baseline_and_pool(2000, 128, true, true, 1, &summary);
        let development_decision = AppleSiliconDevelopmentGate {
            max_latency_multiplier: 1.5,
            max_token_multiplier: 2.0,
            ..AppleSiliconDevelopmentGate::conservative()
        }
        .evaluate(&effect);
        let report = ModelWorkerGateReport::from_workers_and_decisions(
            RootAdapterRolloutStage::Enforced,
            &workers,
            &pool_decision,
            &development_decision,
            RootAdapterFailureKind::None,
        );

        assert_eq!(report.worker_ids, vec!["planner-1", "tester-1"]);
        assert_eq!(report.roles, vec!["planner", "tester"]);
        assert_eq!(report.latency_ms, vec![800, 900]);
        assert_eq!(report.runtime_tokens, vec![64, 64]);
        assert_eq!(report.success, vec![true, true]);
        assert_eq!(report.validation_checked, vec![true, true]);
        assert_eq!(report.validation_passed, vec![true, true]);
        assert_eq!(report.failure_kinds, vec!["none", "none"]);
        assert_eq!(report.development_claim_allowed, vec![true, true]);
        assert!(
            report
                .claim_blockers
                .iter()
                .all(|blockers| blockers.is_empty())
        );
        assert!(report.allow_development_claim);
        assert!(!report.operational_readiness_blocked);
        assert!(!report.model_quality_failure_counted);
        assert!(report.failure_reasons.is_empty());
    }

    #[test]
    fn model_worker_gate_report_blocks_pass_without_validation_check_as_coverage() {
        let workers = vec![
            ModelWorkerRecord::new("planner-1", ModelRole::Planner, "gemma-small")
                .with_runtime(800, 64)
                .with_success(true)
                .with_feedback(2)
                .with_validation(false, true),
        ];
        let summary = ModelPoolSummary::from_workers(&workers);
        let pool_decision = ModelPoolGate::strict().evaluate(&summary);
        let effect =
            ModelPoolDevelopmentEffect::from_baseline_and_pool(1000, 128, true, true, 1, &summary);
        let development_decision = AppleSiliconDevelopmentGate::conservative().evaluate(&effect);
        let report = ModelWorkerGateReport::from_workers_and_decisions(
            RootAdapterRolloutStage::Enforced,
            &workers,
            &pool_decision,
            &development_decision,
            RootAdapterFailureKind::None,
        );

        assert_eq!(report.validation_checked, vec![false]);
        assert_eq!(report.validation_passed, vec![true]);
        assert_eq!(report.development_claim_allowed, vec![false]);
        assert!(report.claim_blockers[0].contains(&"validation_not_checked"));
        assert!(!report.claim_blockers[0].contains(&"model_quality_failure"));
        assert!(!report.model_quality_failure_counted);
        assert!(!report.allow_development_claim);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("model worker validation checked 0/1")
                || reason.contains("model worker claim blockers")
        }));
    }

    #[test]
    fn model_worker_gate_report_never_counts_prompt_gate_outage_as_quality() {
        let workers = vec![
            ModelWorkerRecord::new("high-quality-1", ModelRole::HighQuality, "gemma-12b")
                .with_runtime(1000, 128)
                .with_success(true)
                .with_feedback(2)
                .with_validation(true, true)
                .with_failure_kind(RootAdapterFailureKind::ChainNotReady),
        ];
        let summary = ModelPoolSummary::from_workers(&workers);
        let pool_decision = ModelPoolGate::strict().evaluate(&summary);
        let effect =
            ModelPoolDevelopmentEffect::from_baseline_and_pool(1000, 128, true, true, 1, &summary);
        let development_decision = AppleSiliconDevelopmentGate::conservative().evaluate(&effect);
        let root_evidence = RootAdapterFailureEvidence {
            backend_8686_reachable: Some(false),
            prompt_gate_blocked: true,
            final_json_present: false,
            runtime_model_present: false,
            runtime_tokens: None,
            business_cycle_passed: None,
            error: Some("prompt-gate blocked while backend 8686 was down".to_owned()),
        };
        let root_kind = classify_root_adapter_failure(&root_evidence);
        let report = ModelWorkerGateReport::from_workers_and_decisions(
            RootAdapterRolloutStage::Enforced,
            &workers,
            &pool_decision,
            &development_decision,
            root_kind,
        );

        assert_eq!(root_kind, RootAdapterFailureKind::ChainNotReady);
        assert_eq!(report.failure_kinds, vec!["chain_not_ready"]);
        assert_eq!(report.root_adapter_failure_kind, "chain_not_ready");
        assert_eq!(report.development_claim_allowed, vec![false]);
        assert!(report.claim_blockers[0].contains(&"operational_readiness_failure"));
        assert!(!report.claim_blockers[0].contains(&"model_quality_failure"));
        assert!(report.operational_readiness_blocked);
        assert!(!report.model_quality_failure_counted);
        assert!(!report.allow_development_claim);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("without counting as model quality failure"))
        );
    }

