    #[test]
    fn worker_root_failure_consistency_blocks_operational_quality_confusion() {
        let workers = vec![
            ModelWorkerRecord::new("legacy-12b", ModelRole::HighQuality, "gemma-12b")
                .with_runtime(1000, 128)
                .with_success(false)
                .with_feedback(0)
                .with_validation(true, false)
                .with_failure_kind(RootAdapterFailureKind::ModelQualityFailure),
        ];
        let gate = WorkerRootFailureConsistencyGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = WorkerRootFailureConsistencyEvidence::from_worker_records(
            true,
            &workers,
            RootAdapterFailureKind::ChainNotReady,
        );
        let report = WorkerRootFailureConsistencyReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.worker_failure_kinds, vec!["model_quality_failure"]);
        assert_eq!(report.root_adapter_failure_kind, "chain_not_ready");
        assert!(!report.single_worker_consistent);
        assert!(report.operational_quality_confusion);
        assert!(report.consistency_blocked);
        assert!(!report.allow_enforcement);
        assert!(
            report.failure_reasons.iter().any(|reason| {
                reason.contains("single-worker root/worker failure-kind mismatch")
            })
        );
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("operational readiness failure")
                && reason.contains("model_quality_failure")
        }));
    }

