    #[test]
    fn eval_report_bundle_gate_report_schema_stages_presence_and_blocking_fields() {
        let schema = EvalReportBundleGateReportSchema::report_bundle_gate_v1();
        let names = schema.field_names();
        let report_only_names = schema
            .fields_for_stage(RootAdapterRolloutStage::ReportOnly)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforced_names = schema
            .fields_for_stage(RootAdapterRolloutStage::Enforced)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();

        assert!(names.contains(&"report_bundle.expected_schema_names"));
        assert!(names.contains(&"report_bundle.missing_schema_names"));
        assert!(names.contains(&"report_bundle.adapter_report_field_coverage_passed"));
        assert!(report_only_names.contains(&"report_bundle.observed_schema_names"));
        assert!(report_only_names.contains(&"report_bundle.adapter_report_field_coverage_passed"));
        assert!(!report_only_names.contains(&"report_bundle.bundle_blocked"));
        assert!(enforced_names.contains(&"report_bundle.bundle_blocked"));
        assert!(enforced_names.contains(&"report_bundle.failure_reasons"));
        assert!(enforced_names.contains(&"report_bundle.complete"));
    }

