    #[test]
    fn eval_report_bundle_gate_blocks_missing_adapter_report_field_coverage_when_enforced() {
        let manifest = EvalReportBundleManifest::for_stage(RootAdapterRolloutStage::Enforced);
        let plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let report_fields = plan
            .required_report_fields()
            .into_iter()
            .filter(|field| {
                *field != "context_rot_trend.latest_noisy_records"
                    && *field != "context_rot_remediation.allow_experiment_rollout"
            })
            .collect::<Vec<_>>();
        let emission_report = AdapterReportEmissionReport::from_gate_plan_and_evidence(
            &AdapterReportEmissionGate::for_stage(RootAdapterRolloutStage::Enforced),
            &plan,
            &AdapterReportEmissionEvidence::from_observed_with_report_fields(
                plan.report_names(),
                plan.future_events(),
                report_fields,
            ),
        );
        let evidence = EvalReportBundleEvidence::from_schema_names(manifest.schema_names.clone())
            .with_adapter_report_field_coverage_from_report(&emission_report);
        let report = EvalReportBundleGateReport::from_manifest_and_evidence(&manifest, &evidence);

        assert!(!emission_report.field_coverage_passed());
        assert!(
            emission_report
                .missing_report_fields
                .contains(&"context_rot_trend.latest_noisy_records")
        );
        assert!(
            emission_report
                .missing_report_fields
                .contains(&"context_rot_remediation.allow_experiment_rollout")
        );
        assert_eq!(emission_report.missing_report_fields.len(), 2);
        assert!(
            !emission_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("model_quality_failure"))
        );
        assert!(report.missing_schema_names.is_empty());
        assert!(!report.adapter_report_field_coverage_passed);
        assert!(report.bundle_blocked);
        assert!(!report.complete);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report field coverage"))
        );
        assert!(
            !report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("model_quality_failure"))
        );
    }

    #[test]
    fn eval_report_bundle_gate_projects_from_adapter_emission_report_without_scanning() {
        let manifest = EvalReportBundleManifest::for_stage(RootAdapterRolloutStage::Enforced);
        let plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let emission_report = AdapterReportEmissionReport::from_gate_plan_and_evidence(
            &AdapterReportEmissionGate::for_stage(RootAdapterRolloutStage::Enforced),
            &plan,
            &AdapterReportEmissionEvidence::from_observed_with_report_fields(
                manifest.schema_names.clone(),
                plan.future_events(),
                plan.required_report_fields(),
            ),
        );
        let evidence =
            EvalReportBundleEvidence::from_adapter_report_emission_report(&emission_report);
        let direct_report =
            EvalReportBundleGateReport::from_manifest_and_evidence(&manifest, &evidence);
        let projected_report =
            EvalReportBundleGateReport::from_manifest_and_adapter_report_emission_report(
                &manifest,
                &emission_report,
            );

        assert_eq!(direct_report, projected_report);
        assert_eq!(
            evidence.observed_schema_names,
            emission_report.observed_report_schema_names
        );
        assert!(evidence.adapter_report_field_coverage_passed);
        assert!(projected_report.missing_schema_names.is_empty());
        assert!(projected_report.complete);
        assert!(!projected_report.bundle_blocked);
    }

