    #[test]
    fn eval_schema_drift_gate_blocks_manifest_bundle_or_checklist_mismatch() {
        let gate = EvalSchemaDriftGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = EvalSchemaDriftEvidence {
            stage: RootAdapterRolloutStage::Enforced,
            manifest_schema_names: vec!["ledger_gate_report_v1", "schema_drift_report_v1"],
            bundle_schema_names: vec!["ledger_gate_report_v1", "extra_report_v1"],
            checklist_schema_names: vec!["ledger_gate_report_v1", "ledger_gate_report_v1"],
            manifest_report_field_names: vec![
                "apple_silicon_effect.worker_ids",
                "apple_silicon_effect.runtime_tokens",
            ],
            adapter_emission_report_field_names: vec![
                "apple_silicon_effect.runtime_tokens",
                "apple_silicon_effect.runtime_tokens",
                "apple_silicon_effect.extra_debug_field",
            ],
        };
        let report = EvalSchemaDriftReport::from_gate_and_evidence(&gate, &evidence);

        assert!(report.drift_blocked);
        assert!(!report.allow_runner_wiring);
        assert!(
            report
                .bundle_missing_schema_names
                .contains(&"schema_drift_report_v1".to_owned())
        );
        assert!(
            report
                .bundle_extra_schema_names
                .contains(&"extra_report_v1".to_owned())
        );
        assert!(
            report
                .checklist_missing_schema_names
                .contains(&"schema_drift_report_v1".to_owned())
        );
        assert!(
            report
                .duplicate_schema_names
                .contains(&"ledger_gate_report_v1".to_owned())
        );
        assert!(
            report
                .missing_report_field_names
                .contains(&"apple_silicon_effect.worker_ids".to_owned())
        );
        assert!(
            report
                .extra_report_field_names
                .contains(&"apple_silicon_effect.extra_debug_field".to_owned())
        );
        assert!(
            report
                .duplicate_report_field_names
                .contains(&"apple_silicon_effect.runtime_tokens".to_owned())
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("report bundle missing manifest schemas"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report field contract missing fields"))
        );
    }

    #[test]
    fn eval_schema_drift_gate_blocks_missing_context_rot_report_field_contracts() {
        let gate = EvalSchemaDriftGate::for_stage(RootAdapterRolloutStage::Enforced);
        let mut evidence =
            EvalSchemaDriftEvidence::from_current_contracts(RootAdapterRolloutStage::Enforced);
        evidence
            .adapter_emission_report_field_names
            .retain(|field| {
                *field != "context_rot_trend.latest_noisy_records"
                    && *field != "context_rot_remediation.allow_experiment_rollout"
            });
        let report = EvalSchemaDriftReport::from_gate_and_evidence(&gate, &evidence);

        assert!(report.drift_blocked);
        assert!(!report.allow_runner_wiring);
        assert!(
            report
                .missing_report_field_names
                .contains(&"context_rot_trend.latest_noisy_records".to_owned())
        );
        assert!(
            report
                .missing_report_field_names
                .contains(&"context_rot_remediation.allow_experiment_rollout".to_owned())
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report field contract missing fields"))
        );
        assert!(
            !report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("model_quality_failure"))
        );
    }

