    #[test]
    fn adapter_promotion_window_blocks_short_or_incomplete_observation() {
        let gate = AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = AdapterPromotionWindowEvidence {
            observed_report_only_runs: 2,
            complete_bundle_runs: 1,
            ..AdapterPromotionWindowEvidence::stable_report_only_window(2)
        };
        let report = AdapterPromotionWindowReport::from_gate_and_evidence(&gate, &evidence);

        assert!(report.promotion_blocked);
        assert!(!report.allow_enforcement);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("observation window too short"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("complete report bundle"))
        );
    }

    #[test]
    fn adapter_promotion_window_does_not_promote_single_report_only_observation() {
        let evidence = AdapterPromotionWindowEvidence::stable_report_only_window(1);
        let report_only_gate =
            AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::ReportOnly);
        let enforced_gate =
            AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::Enforced);

        let report_only =
            AdapterPromotionWindowReport::from_gate_and_evidence(&report_only_gate, &evidence);
        let enforced =
            AdapterPromotionWindowReport::from_gate_and_evidence(&enforced_gate, &evidence);

        assert_eq!(report_only.observed_report_only_runs, 1);
        assert!(!report_only.promotion_blocked);
        assert!(report_only.allow_enforcement);
        assert_eq!(enforced.observed_report_only_runs, 1);
        assert!(enforced.promotion_blocked);
        assert!(!enforced.allow_enforcement);
        assert!(enforced.failure_reasons.iter().any(|reason| {
            reason.contains("report-only observation window too short") && reason.contains("1 < 3")
        }));
    }

    #[test]
    fn adapter_promotion_window_blocks_unstable_apple_silicon_effect() {
        let gate = AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = AdapterPromotionWindowEvidence::stable_report_only_window(3)
            .with_apple_silicon_development_effect_passed_runs(2);
        let report = AdapterPromotionWindowReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.apple_silicon_development_effect_passed_runs, 2);
        assert_eq!(report.min_apple_silicon_development_effect_passed_runs, 3);
        assert!(report.promotion_blocked);
        assert!(!report.allow_enforcement);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("Apple Silicon development-effect")
                && reason.contains("observations too low")
        }));
    }

