    #[test]
    fn adapter_promotion_window_keeps_readiness_and_availability_out_of_quality_failure() {
        let gate = AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = AdapterPromotionWindowEvidence::stable_report_only_window(3)
            .with_chain_not_ready_runs(1)
            .with_model_unavailable_runs(1)
            .with_worker_operational_readiness_failure_runs(1);
        let report = AdapterPromotionWindowReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.model_quality_failure_runs, 0);
        assert_eq!(report.chain_not_ready_runs, 1);
        assert_eq!(report.model_unavailable_runs, 1);
        assert_eq!(report.worker_operational_readiness_failure_runs, 1);
        assert_eq!(report.worker_model_quality_failure_runs, 0);
        assert!(report.promotion_blocked);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("chain readiness"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("model availability"))
        );
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("worker operational readiness")
                && reason.contains("without counting as model quality failure")
        }));
        assert!(
            !report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("model quality failures observed"))
        );
    }

