        assert!(names.contains(&"ledger.rust_check_passed"));
        assert!(names.contains(&"ledger.rust_check_feedback_applied_total"));
        assert!(names.contains(&"ledger.runtime_response_failures"));
        assert!(names.contains(&"ledger.missing_final_failures"));
