    #[test]
    fn ledger_gate_report_projects_hygiene_stream_and_last_success_failures() {
        let records = vec![
            LedgerRecord::success(1, 128, "google/gemma").with_rust_check(true, true, 2),
            LedgerRecord::success(3, 96, "google/gemma").with_final_present(false),
            LedgerRecord::failure(3, "stream truncated before done event"),
        ];
        let summary = LedgerSummary::from_records(&records);
        let gate = ReportGate::strict();
        let decision = gate.evaluate(&summary);
        let report = LedgerGateReport::from_summary_and_decision(&summary, &decision);
        let gate_report = LedgerGateReport::from_summary_and_gate(&summary, &gate);
        let records_report = LedgerGateReport::from_records_and_gate(&records, &gate);
        let adapter_report = LedgerGateReport::from_summary_and_failure_reasons(
            &summary,
            &["adapter preserved wording".to_owned()],
        );

        assert_eq!(gate_report, report);
        assert_eq!(records_report, report);
        assert_eq!(report.total_rounds, 3);
        assert_eq!(report.rust_check_checked, 1);
        assert_eq!(report.rust_check_passed, 1);
        assert_eq!(report.rust_check_feedback_applied_total, 2);
        assert_eq!(report.duplicate_rounds, 1);
        assert_eq!(report.round_gaps, 1);
        assert_eq!(report.stream_truncations, 1);
        assert_eq!(report.missing_final_failures, 2);
        assert_eq!(report.last_success, Some(false));
        assert!(report.gate_blocked);
        assert!(!report.allow_next_round);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("duplicate round"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("latest round did not succeed"))
        );
        assert!(adapter_report.gate_blocked);
        assert_eq!(
            adapter_report.failure_reasons,
            vec!["adapter preserved wording".to_owned()]
        );
    }

