    #[test]
    fn run_mode_report_refresh_acceptance_blocks_without_copying_ledger_failure_reasons() {
        let records = vec![LedgerRecord::failure(
            1,
            "validation failed before report refresh",
        )];
        let ledger_gate = LedgerGateReport::from_records_and_gate(&records, &ReportGate::strict());
        let freshness_status = ReportFreshnessStatus::from_runner_status(1, 0, false, 0);
        let freshness =
            ReportFreshnessReport::from_status_and_ledger_gate(&freshness_status, &ledger_gate);
        let remote_status = RemoteRuntimeAccelerationStatus::from_runner_pool_status(6, 5, 4, " ");
        let remote_runtime = RemoteRuntimeAccelerationReport::from_status(&remote_status);
        let manifest = EvalReportBundleManifest::for_stage(RootAdapterRolloutStage::Enforced);
        let bundle = EvalReportBundleGateReport::from_manifest_and_evidence(
            &manifest,
            &EvalReportBundleEvidence::from_schema_names(["model_worker_v1"]),
        );
        let acceptance = RunModeReportRefreshAcceptanceReport::from_reports(
            &freshness,
            &remote_runtime,
            &bundle,
        );

        assert!(freshness.allow_report_refresh);
        assert!(!freshness.ledger_gate_allow_next_round);
        assert!(acceptance.report_refresh_allowed);
        assert!(!acceptance.ledger_gate_allow_next_round);
        assert!(!acceptance.remote_runtime_acceleration_ready);
        assert!(!acceptance.report_bundle_complete);
        assert!(!acceptance.allow_next_round);
        assert!(
            acceptance
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("ledger gate did not allow next round"))
        );
        assert!(
            acceptance
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("healthy workers 5/6"))
        );
        assert!(
            acceptance
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("report bundle missing required schemas"))
        );
        assert!(
            !acceptance
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("validation failed before report refresh"))
        );
    }

    #[test]
    fn run_mode_report_refresh_acceptance_matches_norion_test_plan_boundary() {
        let bundle_schema = EvalReportBundleGateReportSchema::report_bundle_gate_v1();
        let schema =
            RunModeReportRefreshAcceptanceReportSchema::run_mode_report_refresh_acceptance_v1();
        let plan = norion_test::RunModeReportRefreshAcceptancePlan::run_mode_report_refresh(
            "run-mode-report-refresh-acceptance",
            norion_test::AdapterAcceptanceStage::Enforced,
        );
        let schema_fields = schema
            .field_names()
            .iter()
            .map(|field| field.to_string())
            .collect::<Vec<_>>();
        let report_only_fields = schema
            .fields_for_stage(RootAdapterRolloutStage::ReportOnly)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforced_fields = schema
            .fields
            .iter()
            .filter(|field| field.stage == ReportSchemaStage::Enforced)
            .map(|field| field.name)
            .collect::<Vec<_>>();

        assert_eq!(
            plan.report_schema_name,
            "run_mode_report_refresh_acceptance_report_v1"
        );
        assert_eq!(plan.produced_report_fields, schema_fields);
        assert!(report_only_fields.contains(&"run_mode_report_refresh.report_refresh_allowed"));
        assert!(
            report_only_fields.contains(&"run_mode_report_refresh.ledger_gate_allow_next_round")
        );
        assert!(
            report_only_fields
                .contains(&"run_mode_report_refresh.remote_runtime_acceleration_ready")
        );
        assert!(report_only_fields.contains(&"run_mode_report_refresh.report_bundle_complete"));
        assert_eq!(
            EvalReportBundleGateReportSchema::downstream_projection_field_mappings(),
            norion_test::EvalReportBundleGateReportPlan::downstream_projection_field_mappings()
        );
        for (bundle_field, downstream_field) in
            EvalReportBundleGateReportSchema::downstream_projection_field_mappings()
        {
            assert!(
                bundle_schema.field_names().contains(&bundle_field),
                "missing bundle source field {bundle_field}"
            );
            assert!(
                schema.field_names().contains(&downstream_field),
                "missing run-mode downstream field {downstream_field}"
            );
        }
        assert!(
            bundle_schema
                .field_names()
                .contains(&"report_bundle.failure_reasons")
        );
        assert!(
            !EvalReportBundleGateReportSchema::downstream_projection_field_mappings()
                .iter()
                .any(|(bundle_field, downstream_field)| {
                    *bundle_field == "report_bundle.failure_reasons"
                        || *downstream_field
                            == "run_mode_report_refresh.report_bundle_failure_reasons"
                })
        );
        assert!(enforced_fields.contains(&"run_mode_report_refresh.allow_next_round"));
        assert!(enforced_fields.contains(&"run_mode_report_refresh.failure_reasons"));
        assert!(plan.requires_input_report("ReportFreshnessReport"));
        assert!(plan.requires_input_report("RemoteRuntimeAccelerationReport"));
        assert!(plan.requires_input_report("EvalReportBundleGateReport"));
        assert!(plan.produces_report_field("run_mode_report_refresh.allow_next_round"));
        assert!(plan.stays_pure_data_boundary());
        assert!(plan.preserves_legacy_runner);
        assert!(!plan.may_block_current_runner());
        assert!(plan.forbids_capability("jsonl_io"));
        assert!(plan.forbids_capability("daemon_control"));
        assert!(plan.forbids_capability("remote_mac_call"));
        assert!(plan.forbids_capability("model_call"));
    }

