    #[test]
    fn feedback_self_improve_report_projects_summary_and_gate_decision() {
        let records = vec![
            LedgerRecord::success(1, 128, "google/gemma").with_feedback(1),
            LedgerRecord::success(2, 96, "google/gemma")
                .with_feedback(0)
                .with_self_improve(true, false),
        ];
        let summary = LedgerSummary::from_records(&records);
        let gate = ReportGate::strict();
        let decision = gate.evaluate(&summary);
        let report = FeedbackSelfImproveReport::from_summary_and_decision(&summary, &decision);
        let gate_report = FeedbackSelfImproveReport::from_summary_and_gate(&summary, &gate);
        let records_report = FeedbackSelfImproveReport::from_records_and_gate(&records, &gate);

        assert_eq!(gate_report, report);
        assert_eq!(records_report, report);
        assert_eq!(report.total_applied, 1);
        assert_eq!(report.items, 2);
        assert_eq!(report.validation_checked, 2);
        assert_eq!(report.validation_passed, 2);
        assert_eq!(report.self_improve_checked, 2);
        assert_eq!(report.self_improve_passed, 1);
        assert_eq!(report.self_improve_pass_rate, 0.5);
        assert!(report.closed_loop_blocked);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("self_improve pass rate"))
        );
    }

