    #[test]
    fn self_evolution_unattended_prerequisites_project_operational_gate_reports() {
        let readiness_snapshot =
            SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced)
                .with_rollback_resume_decision(GateDecision::block(
                    "rollback resume gate has not passed",
                ));
        let readiness_report = SelfEvolutionReadinessReport::from_snapshot(&readiness_snapshot);
        let context_rot_signal = ContextRotSignal::clean()
            .with_noisy_records(1)
            .with_quarantine_candidates(1)
            .with_duplicate_outputs(1);
        let trend_report = ContextRotTrendReport::from_points_and_gate(
            &[ContextRotTrendPoint::new(7, context_rot_signal.clone())],
            &ContextRotTrendGate::strict(),
        );
        let remediation_report = ContextRotRemediationReport::from_gate_and_signal(
            &ContextRotRemediationGate::for_stage(RootAdapterRolloutStage::Enforced),
            &context_rot_signal,
        );
        let rollback_resume_report = RollbackResumeReport::from_gate_and_evidence(
            &RollbackResumeGate::for_stage(RootAdapterRolloutStage::Enforced),
            &RollbackResumeEvidence::all_clear_for_resume_gate("runtime_backend_health_check"),
        );
        let steam_report = SteamCaseCoverageReport::from_rows_and_gate(
            [SteamCaseCoverageRow::business_cycle("planning-only")
                .with_case_kind(SteamCaseKind::Planning)],
            &SteamCaseCoverageGate::for_stage(RootAdapterRolloutStage::Enforced),
        );
        let validation_report = ValidationCommandCoverageReport::from_observations_and_gate(
            [ValidationObservation::from_outcome(
                VerificationPhase::PostRound,
                norion_test::CommandOutcome {
                    command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                        .to_owned(),
                    status_code: Some(1),
                    elapsed_ms: 42,
                    stdout_tail: String::new(),
                    stderr_tail: "test failed".to_owned(),
                },
            )],
            true,
            false,
            &ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced),
        );
        let evidence = SelfEvolutionUnattendedPrerequisiteEvidence::all_passed()
            .with_operational_gate_reports(
                &readiness_report,
                &trend_report,
                &remediation_report,
                &rollback_resume_report,
                &steam_report,
                &validation_report,
            );
        let gate =
            SelfEvolutionUnattendedPrerequisiteGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report =
            SelfEvolutionUnattendedPrerequisiteReport::from_gate_and_evidence(&gate, &evidence);

        assert!(!report.readiness_next_round_passed);
        assert!(!report.context_rot_trend_passed);
        assert!(!report.context_rot_remediation_passed);
        assert!(report.rollback_resume_passed);
        assert!(!report.steam_case_matrix_passed);
        assert!(!report.validation_command_coverage_passed);
        assert!(report.prerequisite_blocked);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("readiness next-round gate did not pass"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("Context Rot trend"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("Context Rot remediation"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("Steam case matrix"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("validation command coverage") })
        );
    }

