    #[test]
    fn self_evolution_unattended_prerequisite_schema_stages_inputs_and_claim() {
        let schema =
            SelfEvolutionUnattendedPrerequisiteReportSchema::self_evolution_unattended_prerequisites_v1();
        let names = schema.field_names();
        let report_only_names = schema
            .fields_for_stage(RootAdapterRolloutStage::ReportOnly)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforced_names = schema
            .fields_for_stage(RootAdapterRolloutStage::Enforced)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let source_for = |name| {
            schema
                .fields
                .iter()
                .find(|field| field.name == name)
                .map(|field| field.source)
        };

        assert!(names.contains(&"self_evolution_unattended.continuity_passed"));
        assert!(names.contains(&"self_evolution_unattended.regression_passed"));
        assert!(names.contains(&"self_evolution_unattended.readiness_next_round_passed"));
        assert!(names.contains(&"self_evolution_unattended.advice_continuation_observed"));
        assert!(names.contains(&"self_evolution_unattended.advice_continuation_passed"));
        assert!(names.contains(&"self_evolution_unattended.context_rot_trend_passed"));
        assert!(names.contains(&"self_evolution_unattended.context_rot_remediation_passed"));
        assert!(names.contains(&"self_evolution_unattended.rollback_resume_passed"));
        assert!(names.contains(&"self_evolution_unattended.steam_case_matrix_passed"));
        assert!(names.contains(&"self_evolution_unattended.validation_command_coverage_passed"));
        assert!(names.contains(&"self_evolution_unattended.promotion_window_passed"));
        assert!(names.contains(&"self_evolution_unattended.adapter_report_field_coverage_passed"));
        assert!(
            names.contains(&"self_evolution_unattended.apple_silicon_development_effect_passed")
        );
        assert_eq!(
            source_for("self_evolution_unattended.readiness_next_round_passed"),
            Some("SelfEvolutionReadinessReport::can_schedule_next_round")
        );
        assert_eq!(
            source_for("self_evolution_unattended.advice_continuation_passed"),
            Some("AdviceContinuationReport::allow_continuation")
        );
        assert_eq!(
            source_for("self_evolution_unattended.context_rot_trend_passed"),
            Some("ContextRotTrendReport::allow_unattended_continuation")
        );
        assert_eq!(
            source_for("self_evolution_unattended.context_rot_remediation_passed"),
            Some("ContextRotRemediationReport::allow_experiment_rollout")
        );
        assert_eq!(
            source_for("self_evolution_unattended.rollback_resume_passed"),
            Some("RollbackResumeReport::allow_unattended_rounds")
        );
        assert_eq!(
            source_for("self_evolution_unattended.steam_case_matrix_passed"),
            Some("SteamCaseCoverageReport::allow_enforced_adapter")
        );
        assert_eq!(
            source_for("self_evolution_unattended.validation_command_coverage_passed"),
            Some("ValidationCommandCoverageReport::allow_next_round")
        );
        assert_eq!(
            source_for("self_evolution_unattended.promotion_window_passed"),
            Some("AdapterPromotionWindowReport::allow_enforcement")
        );
        assert_eq!(
            source_for("self_evolution_unattended.adapter_report_field_coverage_passed"),
            Some("AdapterReportEmissionReport::field_coverage_passed")
        );
        assert_eq!(
            source_for("self_evolution_unattended.apple_silicon_development_effect_passed"),
            Some("AppleSiliconDevelopmentEffectReport::allow_development_effect_claim")
        );
        assert!(report_only_names.contains(&"self_evolution_unattended.rollback_resume_passed"));
        assert!(
            report_only_names.contains(&"self_evolution_unattended.advice_continuation_passed")
        );
        assert!(!report_only_names.contains(&"self_evolution_unattended.prerequisite_blocked"));
        assert!(enforced_names.contains(&"self_evolution_unattended.prerequisite_blocked"));
        assert!(
            enforced_names
                .contains(&"self_evolution_unattended.allow_unattended_self_evolution_claim")
        );
        assert!(enforced_names.contains(&"self_evolution_unattended.failure_reasons"));
    }

    #[test]
    fn self_evolution_unattended_source_contract_matches_norion_test_plan() {
        let schema =
            SelfEvolutionUnattendedPrerequisiteReportSchema::self_evolution_unattended_prerequisites_v1();
        let plan =
            norion_test::SelfEvolutionUnattendedPrerequisiteReportPlan::unattended_prerequisites(
                "self-evolution-unattended-source-contract",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let schema_sources = schema
            .fields
            .iter()
            .filter(|field| {
                field.name.ends_with("_passed")
                    && field.name != "self_evolution_unattended.continuity_passed"
                    && field.name != "self_evolution_unattended.regression_passed"
            })
            .map(|field| field.source.to_owned())
            .collect::<Vec<_>>();

        assert_eq!(schema_sources, plan.operational_report_sources);
        assert!(plan.stays_pure_data_boundary());
        assert!(!plan.uses_operational_report_source(
            "ValidationCommandCoverageReport::allow_enforced_adapter"
        ));
        assert!(plan.forbids_capability("jsonl_io"));
        assert!(plan.forbids_capability("validation_command_spawn"));
        assert!(plan.forbids_capability("runner_state"));
    }

