    #[test]
    fn context_rot_acceptance_contract_reports_dirty_signal_before_blocking() {
        let signal = ContextRotSignal::clean()
            .with_noisy_records(1)
            .with_max_noise_penalty(0.25)
            .with_duplicate_outputs(1);
        let contract = ContextRotAcceptanceContract::report_only();
        let advisory_report = contract.advisory_report(&signal);
        let blocking_report = contract.blocking_report(&signal);

        assert!(contract.advisory_decision(&signal).blocked);
        assert!(!contract.blocking_decision(&signal).blocked);
        assert!(advisory_report.gate_blocked);
        assert!(!blocking_report.gate_blocked);
        assert_eq!(advisory_report.noisy_records, 1);
        assert!(blocking_report.failure_reasons.is_empty());
        assert!(
            contract
                .report_fields_for_stage()
                .iter()
                .all(|field| field.stage == ReportSchemaStage::ReportOnly)
        );
    }

    #[test]
    fn context_rot_acceptance_contract_blocks_dirty_enforced_rollout() {
        let signal = ContextRotSignal::clean().with_repairable_legacy_metadata_lessons(2);
        let flag = ExperimentFlag::enabled("parallel-workers", "runtime-team", 5);
        let contract = ContextRotAcceptanceContract::enforced();
        let blocking = contract.blocking_decision(&signal);
        let blocking_report = contract.blocking_report(&signal);
        let rollout = contract.experiment_rollout_decision(&flag, &signal);

        assert!(blocking.blocked);
        assert!(blocking_report.gate_blocked);
        assert_eq!(blocking_report.failure_reasons, blocking.reasons);
        assert!(
            blocking
                .reasons
                .iter()
                .any(|reason| reason.contains("repairable legacy metadata lessons"))
        );
        assert!(rollout.blocked);
        assert!(
            rollout
                .reasons
                .iter()
                .any(|reason| reason.contains("requires clean Context Rot gate"))
        );
        assert!(
            contract
                .report_fields_for_stage()
                .iter()
                .any(|field| field.name == "context_rot.gate_blocked")
        );
    }

