    #[test]
    fn adapter_context_rot_remediation_boundary_contract_matches_norion_test_plan() {
        let contract = AdapterContextRotRemediationBoundaryContract::context_rot_remediation_v1();
        let plan =
            norion_test::AdapterContextRotRemediationBoundaryPlan::context_rot_remediation_boundary(
                "context-rot-remediation-boundary",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let allowed_inputs = contract
            .allowed_inputs
            .iter()
            .map(|input| input.to_string())
            .collect::<Vec<_>>();
        let produced_outputs = contract
            .produced_outputs
            .iter()
            .map(|output| output.to_string())
            .collect::<Vec<_>>();
        let forbidden_capabilities = contract
            .forbidden_capabilities
            .iter()
            .map(|capability| capability.to_string())
            .collect::<Vec<_>>();

        assert_eq!(plan.eval_entrypoint, contract.entrypoint);
        assert_eq!(plan.allowed_inputs, allowed_inputs);
        assert_eq!(plan.produced_outputs, produced_outputs);
        assert_eq!(plan.forbidden_capabilities, forbidden_capabilities);
        assert!(contract.allows_input("ContextRotSignal"));
        assert!(contract.allows_input("ContextRotRemediationEvidence"));
        assert!(contract.allows_input("ContextRotRemediationGate"));
        assert!(!contract.allows_input("FilesystemScanner"));
        assert!(contract.produces_output("ContextRotRemediationReport"));
        assert!(contract.stays_pure_data_boundary());
        assert!(contract.forbids_capability("filesystem_scan"));
        assert!(contract.forbids_capability("quarantine_action_execution"));
        assert!(contract.forbids_capability("clean_gist_write"));
        assert!(contract.forbids_capability("duplicate_output_delete"));
        assert!(contract.forbids_capability("model_call"));
        assert!(plan.stays_pure_data_boundary());
        assert!(!plan.may_block_current_runner());
        assert!(plan.preserves_legacy_runner);
    }

