    #[test]
    fn rollback_resume_gate_blocks_until_chain_ready_after_prompt_gate_failure() {
        let gate = RollbackResumeGate::for_stage(RootAdapterRolloutStage::Enforced);
        let evidence = RollbackResumeEvidence::for_resume_gate("chain_readiness_gate");
        let report = RollbackResumeReport::from_gate_and_evidence(&gate, &evidence);
        let stage_report = RollbackResumeReport::from_evidence_for_stage(
            &evidence,
            RootAdapterRolloutStage::Enforced,
        );

        assert_eq!(stage_report, report);
        assert_eq!(report.resume_gate, "chain_readiness_gate");
        assert!(report.resume_blocked);
        assert!(!report.allow_unattended_rounds);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("chain readiness"))
        );

        let clear = RollbackResumeEvidence::all_clear_for_resume_gate("chain_readiness_gate");
        assert!(!gate.evaluate(&clear).blocked);
    }

