    #[test]
    fn steam_round_acceptance_gate_merges_stream_runtime_validation_and_readiness() {
        let stream = StreamContinuityCheck {
            saw_done: false,
            saw_error: false,
            saw_final: true,
            incomplete_buffer_bytes: 0,
            delta_chars: 12,
        };
        let validation = ValidationObservation::from_outcome(
            norion_test::VerificationPhase::PostRound,
            norion_test::CommandOutcome {
                command_line: "cargo test".to_owned(),
                status_code: Some(101),
                elapsed_ms: 10,
                stdout_tail: String::new(),
                stderr_tail: "failed".to_owned(),
            },
        );
        let ledger = LedgerRecord::success(1, 0, "google/gemma").with_validation(true, false);
        let readiness = SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced)
            .with_context_rot_decision(GateDecision::block("noisy records 1 above maximum 0"));
        let evidence =
            SteamRoundAcceptanceEvidence::new("steam-dirty", stream, validation, ledger, readiness);
        let decision = SteamRoundAcceptanceGate::strict().evaluate(&evidence);

        assert!(decision.blocked);
        assert!(
            decision
                .reasons
                .iter()
                .any(|reason| reason.contains("stream truncated before done event"))
        );
        assert!(
            decision
                .reasons
                .iter()
                .any(|reason| reason.contains("runtime_tokens"))
        );
        assert!(
            decision
                .reasons
                .iter()
                .any(|reason| reason.contains("validation observation failed"))
        );
        assert!(
            decision
                .reasons
                .iter()
                .any(|reason| reason.contains("noisy records"))
        );
    }

