    #[test]
    fn steam_round_report_projects_acceptance_decision() {
        let stream = StreamContinuityCheck {
            saw_done: false,
            saw_error: false,
            saw_final: true,
            incomplete_buffer_bytes: 0,
            delta_chars: 12,
        };
        let validation = ValidationObservation::skipped(norion_test::VerificationPhase::PostRound);
        let evidence = SteamRoundAcceptanceEvidence::new(
            "steam-report",
            stream,
            validation,
            LedgerRecord::success(1, 0, "google/gemma"),
            SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced)
                .with_report_decision(GateDecision::block("latest round did not succeed")),
        );
        let report = SteamRoundAcceptanceReport::from_evidence(
            &evidence,
            &SteamRoundAcceptanceGate::strict(),
        );

        assert_eq!(report.case_id, "steam-report");
        assert!(!report.stream_passed);
        assert!(!report.validation_checked);
        assert_eq!(report.runtime_tokens, Some(0));
        assert_eq!(report.runtime_model.as_deref(), Some("google/gemma"));
        assert!(report.acceptance_blocked);
        assert!(!report.can_schedule_next_round);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("stream truncated before done event"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("validation observation was not checked"))
        );
    }

    #[test]
    fn validation_command_coverage_allows_complete_post_round_evidence() {
        let observation = ValidationObservation::from_outcome(
            VerificationPhase::PostRound,
            norion_test::CommandOutcome {
                command_line: "cargo test --manifest-path crates/norion-eval/Cargo.toml".to_owned(),
                status_code: Some(0),
                elapsed_ms: 42,
                stdout_tail: "test result: ok".to_owned(),
                stderr_tail: String::new(),
            },
        );
        let observations = vec![observation];
        let evidence = ValidationCommandCoverageEvidence::from_observations(observations.clone())
            .with_rust_check(true, true);
        let gate = ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ValidationCommandCoverageReport::from_gate_and_evidence(&gate, &evidence);
        let observations_report = ValidationCommandCoverageReport::from_observations_and_gate(
            observations,
            true,
            true,
            &gate,
        );

        assert_eq!(observations_report, report);
        assert_eq!(report.stage, "enforced");
        assert_eq!(report.command_lines.len(), 1);
        assert_eq!(report.phases, vec!["post_round"]);
        assert_eq!(report.status_codes_present, 1);
        assert_eq!(report.output_tail_captured, 1);
        assert_eq!(report.passed_commands, 1);
        assert!(report.rust_check_checked);
        assert!(report.rust_check_passed);
        assert!(!report.strict_coverage_requested);
        assert!(report.coverage_tooling_evidence.is_empty());
        assert!(report.coverage_report_evidence.is_empty());
        assert!(!report.coverage_tooling_or_report_evidence_present);
        assert!(!report.coverage_blocked);
        assert_eq!(report.coverage_failure_kind, "none");
        assert!(!report.model_quality_failure_counted);
        assert!(report.allow_next_round);
    }

