    fn adapter_projection_for_validation_coverage(
        validation_evidence: &ValidationCommandCoverageEvidence,
    ) -> AdapterEvidenceProjection {
        let records = vec![
            LedgerRecord::success(1, 24, "google/gemma")
                .with_rust_check(true, true, 1)
                .with_state_gate(true, true)
                .with_trace_gate(true, true),
            LedgerRecord::success(2, 32, "google/gemma")
                .with_rust_check(true, true, 1)
                .with_state_gate(true, true)
                .with_trace_gate(true, true),
        ];
        let helper_stage = HelperStageContractSummary::from_parts(
            &["verdict: pass / validation_command: cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned()],
            Some("verdict: pass".to_owned()),
            BTreeMap::from([
                ("verdict".to_owned(), "pass".to_owned()),
                (
                    "validation_command".to_owned(),
                    "cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned(),
                ),
            ]),
            vec!["verdict".to_owned(), "validation_command".to_owned()],
            vec![
                "verdict".to_owned(),
                "validation_command".to_owned(),
                "failure_kind".to_owned(),
            ],
        );
        let report_gate = ReportGate {
            min_rounds: 2,
            min_rust_checks: Some(2),
            min_rust_feedback_total: Some(2),
            ..ReportGate::strict()
        };
        let validation_gate =
            ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);

        AdapterEvidenceProjection::from_normalized_evidence(
            &records,
            &report_gate,
            helper_stage,
            validation_evidence,
            &validation_gate,
        )
    }

    #[test]
    fn adapter_projection_keeps_regular_and_strict_coverage_evidence_stable() {
        let regular_observation = ValidationObservation::from_outcome(
            VerificationPhase::PostRound,
            norion_test::CommandOutcome {
                command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                    .to_owned(),
                status_code: Some(0),
                elapsed_ms: 77,
                stdout_tail: "test result: ok".to_owned(),
                stderr_tail: String::new(),
            },
        );
        let regular_evidence =
            ValidationCommandCoverageEvidence::from_observations([regular_observation])
                .with_rust_check(true, true);
        let regular_projection = adapter_projection_for_validation_coverage(&regular_evidence);

        assert!(regular_projection.report_gate_allows_next_round());
        assert!(regular_projection.validation_evidence_allows_next_round());
        assert_eq!(
            regular_projection.validation_command_coverage.command_lines,
            vec!["cargo test -q --manifest-path crates/norion-eval/Cargo.toml"]
        );
        assert!(
            !regular_projection
                .validation_command_coverage
                .strict_coverage_requested
        );
        assert!(
            regular_projection
                .validation_command_coverage
                .coverage_tooling_evidence
                .is_empty()
        );
        assert!(
            regular_projection
                .validation_command_coverage
                .coverage_report_evidence
                .is_empty()
        );
        assert!(
            !regular_projection
                .validation_command_coverage
                .coverage_tooling_or_report_evidence_present
        );
        assert_eq!(
            regular_projection
                .validation_command_coverage
                .coverage_failure_kind,
            "none"
        );

        let strict_observation = ValidationObservation::from_outcome(
            VerificationPhase::PostRound,
            norion_test::CommandOutcome {
                command_line:
                    "cargo test -q --manifest-path crates/norion-eval/Cargo.toml -- --strict-coverage"
                        .to_owned(),
                status_code: Some(0),
                elapsed_ms: 91,
                stdout_tail: "test result: ok".to_owned(),
                stderr_tail: String::new(),
            },
        );
        let strict_evidence =
            ValidationCommandCoverageEvidence::from_observations([strict_observation])
                .with_rust_check(true, true)
                .with_coverage_tooling_evidence(["cargo llvm-cov --fail-under-lines 100"])
                .with_coverage_report_evidence(["target/llvm-cov/lcov.info"]);
        let strict_projection = adapter_projection_for_validation_coverage(&strict_evidence);

        assert!(strict_projection.report_gate_allows_next_round());
        assert!(strict_projection.validation_evidence_allows_next_round());
        assert!(
            strict_projection
                .validation_command_coverage
                .strict_coverage_requested
        );
        assert_eq!(
            strict_projection
                .validation_command_coverage
                .coverage_tooling_evidence,
            vec!["cargo llvm-cov --fail-under-lines 100".to_owned()]
        );
        assert_eq!(
            strict_projection
                .validation_command_coverage
                .coverage_report_evidence,
            vec!["target/llvm-cov/lcov.info".to_owned()]
        );
        assert!(
            strict_projection
                .validation_command_coverage
                .coverage_tooling_or_report_evidence_present
        );
        assert!(
            !strict_projection
                .validation_command_coverage
                .coverage_blocked
        );
        assert_eq!(
            strict_projection
                .validation_command_coverage
                .coverage_failure_kind,
            "none"
        );
    }

