    #[test]
    fn adapter_projection_maps_validation_gap_to_readiness_and_rollback() {
        let records = vec![
            LedgerRecord::success(1, 24, "google/gemma")
                .with_rust_check(true, true, 1)
                .with_state_gate(true, true)
                .with_trace_gate(true, true),
        ];
        let helper_stage = HelperStageContractSummary::from_parts(
            &["verdict: pass / validation_command: cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned()],
            Some("verdict: pass".to_owned()),
            BTreeMap::from([
                ("verdict".to_owned(), "pass".to_owned()),
                (
                    "validation_command".to_owned(),
                    "cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned(),
                ),
            ]),
            vec!["verdict".to_owned(), "validation_command".to_owned()],
            vec!["verdict".to_owned(), "validation_command".to_owned()],
        );
        let validation_evidence = ValidationCommandCoverageEvidence::from_observations([
            ValidationObservation::from_outcome(
                VerificationPhase::PreRound,
                norion_test::CommandOutcome {
                    command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                        .to_owned(),
                    status_code: None,
                    elapsed_ms: 77,
                    stdout_tail: String::new(),
                    stderr_tail: String::new(),
                },
            ),
        ])
        .with_rust_check(false, false);
        let validation_gate =
            ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let projection = AdapterEvidenceProjection::from_normalized_evidence(
            &records,
            &ReportGate::strict(),
            helper_stage,
            &validation_evidence,
            &validation_gate,
        );
        let readiness = projection.readiness_report(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
        );
        let rollback = projection.rollback_report(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
        );

        assert!(projection.report_gate_allows_next_round());
        assert!(!projection.validation_evidence_allows_next_round());
        assert!(readiness.validation_command_coverage_blocked);
        assert!(!readiness.can_schedule_next_round);
        assert!(readiness.rollback_required);
        assert_eq!(rollback.resume_gate, "planned_validation_command");
        assert_eq!(rollback.root_adapter_failure_kind, None);
        assert!(rollback.stop_scheduling_new_rounds);
        assert!(
            readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("validation status codes present"))
        );
    }

    #[test]
    fn adapter_projection_maps_context_rot_reports_to_readiness() {
        let records = vec![
            LedgerRecord::success(1, 24, "google/gemma")
                .with_rust_check(true, true, 1)
                .with_state_gate(true, true)
                .with_trace_gate(true, true),
        ];
        let helper_stage = HelperStageContractSummary::from_parts(
            &["verdict: pass / validation_command: cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned()],
            Some("verdict: pass".to_owned()),
            BTreeMap::from([
                ("verdict".to_owned(), "pass".to_owned()),
                (
                    "validation_command".to_owned(),
                    "cargo test -q --manifest-path crates/norion-eval/Cargo.toml".to_owned(),
                ),
            ]),
            vec!["verdict".to_owned(), "validation_command".to_owned()],
            vec!["verdict".to_owned(), "validation_command".to_owned()],
        );
        let validation_evidence = ValidationCommandCoverageEvidence::from_observations([
            ValidationObservation::from_outcome(
                VerificationPhase::PostRound,
                norion_test::CommandOutcome {
                    command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                        .to_owned(),
                    status_code: Some(0),
                    elapsed_ms: 77,
                    stdout_tail: "test result: ok".to_owned(),
                    stderr_tail: String::new(),
                },
            ),
        ])
        .with_rust_check(true, true);
        let validation_gate =
            ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let projection = AdapterEvidenceProjection::from_normalized_evidence(
            &records,
            &ReportGate::strict(),
            helper_stage,
            &validation_evidence,
            &validation_gate,
        );
        let signal = ContextRotSignal::clean()
            .with_noisy_records(1)
            .with_quarantine_candidates(1)
            .with_duplicate_outputs(1);
        let context_report = ContextRotAcceptanceContract::enforced().blocking_report(&signal);
        let trend_report = ContextRotTrendReport::from_points_and_gate(
            &[ContextRotTrendPoint::new(1, signal.clone())],
            &ContextRotTrendGate::strict(),
        );
        let remediation_report = ContextRotRemediationReport::from_gate_and_signal(
            &ContextRotRemediationGate::for_stage(RootAdapterRolloutStage::Enforced),
            &signal,
        );
        let readiness_via_helper = projection.readiness_report_with_context_reports(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
            Some(&context_report),
            Some(&trend_report),
            Some(&remediation_report),
        );
        let rollback_via_helper = projection.rollback_report_with_context_reports(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
            Some(&context_report),
            Some(&trend_report),
            Some(&remediation_report),
        );
        let snapshot = projection.readiness_snapshot_with_context_reports(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
            Some(&context_report),
            Some(&trend_report),
            Some(&remediation_report),
        );
        let readiness = SelfEvolutionReadinessReport::from_snapshot(&snapshot);
        let rollback = RollbackReport::from_plan(&snapshot.rollback_plan(), None);
        let closure_via_helper = projection.closure_report_with_context_reports(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
            Some(&context_report),
            Some(&trend_report),
            Some(&remediation_report),
        );
        let closure_from_reports = AdapterClosureReport::from_reports(
            RootAdapterRolloutStage::Enforced,
            projection.helper_stage_is_useful(),
            &projection.ledger_gate_report,
            &projection.validation_command_coverage,
            &readiness,
        );

        assert!(projection.report_gate_allows_next_round());
        assert!(projection.validation_evidence_allows_next_round());
        assert_eq!(readiness_via_helper, readiness);
        assert_eq!(rollback_via_helper, rollback);
        assert_eq!(closure_via_helper, closure_from_reports);
        assert!(!snapshot.can_schedule_next_round());
        assert!(readiness.context_rot_trend_blocked);
        assert!(readiness.context_rot_remediation_blocked);
        assert!(readiness.rollback_required);
        assert_eq!(rollback.resume_gate, "planned_validation_command");
        assert!(rollback.stop_scheduling_new_rounds);
        assert!(
            readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("noisy records"))
        );
        assert!(
            readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("Context Rot trend window too short"))
        );
        assert!(
            readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("context rot quarantine incomplete"))
        );
    }

    #[test]
    fn adapter_facing_bundle_keeps_next_round_and_failure_reasons_aligned() {
        let records = vec![
            LedgerRecord::success(10, 128, "google/gemma").with_feedback(3),
            LedgerRecord::success(11, 96, "google/gemma")
                .with_feedback(1)
                .with_validation(true, false)
                .with_self_improve(true, false),
            LedgerRecord::success(12, 96, "google/gemma")
                .with_feedback(0)
                .with_validation(true, false)
                .with_self_improve(true, false),
        ];
        let ledger_report =
            LedgerGateReport::from_records_and_gate(&records, &ReportGate::strict());
        let regression_report = SelfEvolutionRegressionReport::from_records_and_gate(
            &records,
            &SelfEvolutionRegressionGate::strict(),
        );
        let signal = ContextRotSignal::clean()
            .with_noisy_records(1)
            .with_quarantine_candidates(1)
            .with_duplicate_outputs(1);
        let context_report = ContextRotAcceptanceContract::enforced().blocking_report(&signal);
        let trend_report = ContextRotTrendReport::from_points_and_gate(
            &[ContextRotTrendPoint::new(12, signal.clone())],
            &ContextRotTrendGate::strict(),
        );
        let remediation_report = ContextRotRemediationReport::from_gate_and_signal(
            &ContextRotRemediationGate::for_stage(RootAdapterRolloutStage::Enforced),
            &signal,
        );
        let validation_report = ValidationCommandCoverageReport::from_observations_and_gate(
            [ValidationObservation::from_outcome(
                VerificationPhase::PostRound,
                norion_test::CommandOutcome {
                    command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                        .to_owned(),
                    status_code: None,
                    elapsed_ms: 77,
                    stdout_tail: String::new(),
                    stderr_tail: String::new(),
                },
            )],
            true,
            false,
            &ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced),
        );
        let readiness_snapshot =
            SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced)
                .with_ledger_gate_report(&ledger_report)
                .with_context_rot_report(&context_report)
                .with_context_rot_trend_report(&trend_report)
                .with_context_rot_remediation_report(&remediation_report)
                .with_validation_command_coverage_report(&validation_report);
        let readiness_report = SelfEvolutionReadinessReport::from_snapshot(&readiness_snapshot);
        let closure_report = AdapterClosureReport::from_reports(
            RootAdapterRolloutStage::Enforced,
            true,
            &ledger_report,
            &validation_report,
            &readiness_report,
        );
        let unattended_report = SelfEvolutionUnattendedPrerequisiteReport::from_gate_and_evidence(
            &SelfEvolutionUnattendedPrerequisiteGate::for_stage(RootAdapterRolloutStage::Enforced),
            &SelfEvolutionUnattendedPrerequisiteEvidence::all_passed()
                .with_regression_passed(regression_report.allow_unattended_continuation)
                .with_readiness_report(&readiness_report)
                .with_context_rot_trend_passed(trend_report.allow_unattended_continuation)
                .with_context_rot_remediation_passed(remediation_report.allow_experiment_rollout)
                .with_validation_command_coverage_passed(validation_report.allow_next_round),
        );
        let bundle_manifest =
            EvalReportBundleManifest::for_stage(RootAdapterRolloutStage::Enforced);
        let bundle_report = EvalReportBundleGateReport::from_manifest_and_evidence(
            &bundle_manifest,
            &EvalReportBundleEvidence::from_schema_names(bundle_manifest.schema_names.clone())
                .with_adapter_report_field_coverage_passed(true),
        );
        let current_runner_report = CurrentRunnerCompatibilityReport::from_gate_and_evidence(
            &CurrentRunnerCompatibilityGate::for_stage(RootAdapterRolloutStage::Enforced),
            &CurrentRunnerCompatibilityEvidence {
                report_bundle_complete: bundle_report.complete,
                self_evolution_regression_passed: regression_report.allow_unattended_continuation,
                readiness_next_round_passed: readiness_report.can_schedule_next_round,
                self_evolution_unattended_prerequisites_passed: unattended_report
                    .allow_unattended_self_evolution_claim,
                context_rot_trend_passed: trend_report.allow_unattended_continuation,
                context_rot_remediation_passed: remediation_report.allow_experiment_rollout,
                validation_command_coverage_passed: validation_report.allow_next_round,
                ..CurrentRunnerCompatibilityEvidence::all_passed()
            },
        );

        assert!(!ledger_report.allow_next_round);
        assert!(!validation_report.allow_next_round);
        assert!(!regression_report.allow_unattended_continuation);
        assert!(!readiness_report.can_schedule_next_round);
        assert!(!closure_report.allow_next_round);
        assert!(!unattended_report.allow_unattended_self_evolution_claim);
        assert!(!current_runner_report.allow_enforced_wiring);
        assert_eq!(
            closure_report.ledger_gate_report.failure_reasons,
            ledger_report.failure_reasons
        );
        assert_eq!(
            closure_report.validation_command_coverage.failure_reasons,
            validation_report.failure_reasons
        );
        assert_eq!(
            closure_report.readiness.failure_reasons,
            readiness_report.failure_reasons
        );

        for reason in ledger_report
            .failure_reasons
            .iter()
            .chain(context_report.failure_reasons.iter())
            .chain(trend_report.failure_reasons.iter())
            .chain(remediation_report.failure_reasons.iter())
            .chain(validation_report.failure_reasons.iter())
        {
            assert!(
                readiness_report
                    .failure_reasons
                    .iter()
                    .any(|readiness_reason| readiness_reason == reason),
                "readiness report dropped reason: {reason}"
            );
        }
        assert!(
            unattended_report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("self-evolution regression gate did not pass") })
        );
        assert!(
            unattended_report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("readiness next-round gate did not pass") })
        );
        assert!(
            unattended_report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("validation command coverage gate did not pass") })
        );
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("self-evolution regression gate has not passed") })
        );
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("next-round readiness gate has not passed") })
        );
        assert!(
            current_runner_report.failure_reasons.iter().any(|reason| {
                reason.contains("validation command coverage gate has not passed")
            })
        );
        assert!(bundle_report.complete);
        assert!(bundle_report.failure_reasons.is_empty());
    }

    #[test]
    fn adapter_context_rot_reports_keep_report_only_advisory_and_enforced_blocking_separate() {
        let validation_evidence = ValidationCommandCoverageEvidence::from_observations([
            ValidationObservation::from_outcome(
                VerificationPhase::PostRound,
                norion_test::CommandOutcome {
                    command_line: "cargo test -q --manifest-path crates/norion-eval/Cargo.toml"
                        .to_owned(),
                    status_code: Some(0),
                    elapsed_ms: 77,
                    stdout_tail: "test result: ok".to_owned(),
                    stderr_tail: String::new(),
                },
            ),
        ])
        .with_rust_check(true, true);
        let projection = adapter_projection_for_validation_coverage(&validation_evidence);
        let signal = ContextRotSignal::clean()
            .with_noisy_records(1)
            .with_max_noise_penalty(0.2)
            .with_quarantine_candidates(1)
            .with_repairable_legacy_metadata_lessons(1)
            .with_legacy_metadata_without_clean_gist(1)
            .with_duplicate_outputs(1);
        let trend_points = vec![
            ContextRotTrendPoint::new(1, signal.clone()),
            ContextRotTrendPoint::new(2, signal.clone()),
            ContextRotTrendPoint::new(3, signal.clone()),
        ];

        let report_only_contract = ContextRotAcceptanceContract::report_only();
        let advisory_context_report = report_only_contract.advisory_report(&signal);
        let report_only_context_report = report_only_contract.blocking_report(&signal);
        let report_only_trend_summary = ContextRotTrendWindowSummary::from_points(&trend_points);
        let report_only_trend_decision = GateDecision::pass();
        let report_only_trend_report = ContextRotTrendReport::from_summary_and_decision(
            &report_only_trend_summary,
            &report_only_trend_decision,
        );
        let report_only_remediation_report = ContextRotRemediationReport::from_gate_and_signal(
            &ContextRotRemediationGate::for_stage(RootAdapterRolloutStage::ReportOnly),
            &signal,
        );
        let report_only_snapshot = projection.readiness_snapshot_with_context_reports(
            RootAdapterRolloutStage::ReportOnly,
            RootAdapterFailureKind::None,
            Some(&report_only_context_report),
            Some(&report_only_trend_report),
            Some(&report_only_remediation_report),
        );
        let report_only_readiness =
            SelfEvolutionReadinessReport::from_snapshot(&report_only_snapshot);

        assert!(advisory_context_report.gate_blocked);
        assert!(!report_only_context_report.gate_blocked);
        assert_eq!(
            report_only_context_report.noisy_records,
            signal.noisy_records
        );
        assert_eq!(
            report_only_trend_report.latest_noisy_records,
            signal.noisy_records
        );
        assert_eq!(
            report_only_remediation_report.quarantine_candidates,
            signal.quarantine_candidates
        );
        assert!(report_only_snapshot.can_schedule_next_round());
        assert!(!report_only_snapshot.context_rot_decision.blocked);
        assert!(!report_only_snapshot.context_rot_trend_decision.blocked);
        assert!(
            !report_only_snapshot
                .context_rot_remediation_decision
                .blocked
        );
        assert!(report_only_readiness.can_schedule_next_round);
        assert!(!report_only_readiness.context_rot_trend_blocked);
        assert!(!report_only_readiness.context_rot_remediation_blocked);
        assert!(report_only_readiness.failure_reasons.is_empty());

        let enforced_context_report =
            ContextRotAcceptanceContract::enforced().blocking_report(&signal);
        let enforced_trend_report = ContextRotTrendReport::from_points_and_gate(
            &trend_points,
            &ContextRotTrendGate::strict(),
        );
        let enforced_remediation_report = ContextRotRemediationReport::from_gate_and_signal(
            &ContextRotRemediationGate::for_stage(RootAdapterRolloutStage::Enforced),
            &signal,
        );
        let enforced_snapshot = projection.readiness_snapshot_with_context_reports(
            RootAdapterRolloutStage::Enforced,
            RootAdapterFailureKind::None,
            Some(&enforced_context_report),
            Some(&enforced_trend_report),
            Some(&enforced_remediation_report),
        );
        let enforced_readiness = SelfEvolutionReadinessReport::from_snapshot(&enforced_snapshot);

        assert_eq!(
            enforced_context_report.noisy_records,
            report_only_context_report.noisy_records
        );
        assert_eq!(
            enforced_trend_report.latest_duplicate_outputs,
            report_only_trend_report.latest_duplicate_outputs
        );
        assert_eq!(
            enforced_remediation_report.duplicate_outputs,
            report_only_remediation_report.duplicate_outputs
        );
        assert!(!enforced_snapshot.can_schedule_next_round());
        assert!(enforced_snapshot.context_rot_decision.blocked);
        assert!(enforced_snapshot.context_rot_trend_decision.blocked);
        assert!(enforced_snapshot.context_rot_remediation_decision.blocked);
        assert!(!enforced_readiness.can_schedule_next_round);
        assert!(enforced_readiness.context_rot_trend_blocked);
        assert!(enforced_readiness.context_rot_remediation_blocked);
        assert!(enforced_readiness.rollback_required);
        assert!(
            enforced_readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("noisy records"))
        );
        assert!(
            enforced_readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("latest noisy records"))
        );
        assert!(
            enforced_readiness
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("context rot quarantine incomplete"))
        );
    }

