    #[test]
    fn self_improve_proposal_acceptance_summary_separates_advisory_from_business_improvement() {
        let gate = SelfImproveProposalAcceptanceGate::strict();
        let accepted = SelfImproveProposalAcceptanceReport::from_gate_and_evidence(
            &gate,
            &SelfImproveProposalEvidence::clean_candidate(
                324,
                ["r46-validated-improvement"],
                "cargo test -q --manifest-path crates/norion-eval/Cargo.toml",
                "Accepted validated business improvement.",
                SelfImproveMemoryAdmissionCandidate::accepted(
                    "memory-admission-r46-accepted",
                    vec!["validated and admitted".to_owned()],
                ),
            ),
        );
        let advisory = SelfImproveProposalAcceptanceReport::from_gate_and_evidence(
            &gate,
            &SelfImproveProposalEvidence::clean_candidate(
                325,
                ["r46-advisory-suggestion"],
                "cargo test -q --manifest-path crates/norion-test/Cargo.toml",
                "Clean suggestion still waiting for admission.",
                SelfImproveMemoryAdmissionCandidate::quarantined(
                    "memory-admission-r46-quarantined",
                    vec!["report-only candidate".to_owned()],
                ),
            ),
        );
        let repair = SelfImproveProposalAcceptanceReport::from_gate_and_evidence(
            &gate,
            &SelfImproveProposalEvidence::clean_candidate(
                326,
                ["r46-unvalidated-accepted"],
                "cargo test -q --manifest-path tools/evolution-loop/Cargo.toml",
                "Accepted-looking suggestion without validation.",
                SelfImproveMemoryAdmissionCandidate::accepted(
                    "memory-admission-r46-needs-validation",
                    vec!["accepted flag exists but validation is missing".to_owned()],
                ),
            )
            .with_validation(false, false),
        );

        let summary = SelfImproveProposalAcceptanceSummaryReport::from_reports(&[
            accepted,
            advisory.clone(),
            repair,
        ]);

        assert_eq!(summary.projected_report_count, 3);
        assert_eq!(summary.memory_admission_accepted_count, 2);
        assert_eq!(summary.evidence_backed_business_improvement_count, 1);
        assert_eq!(summary.advisory_only_count, 1);
        assert_eq!(summary.allow_promotion_count, 2);
        assert_eq!(summary.require_repair_count, 1);
        assert_eq!(summary.accepted_without_business_evidence_count, 1);
        assert!(!summary.only_advisory_or_repair());
        assert!(
            SelfImproveProposalAcceptanceSummaryReport::from_reports(&[advisory])
                .only_advisory_or_repair()
        );
    }

