    #[test]
    fn self_improve_proposal_action_assignment_targets_advisory_candidates() {
        let gate = SelfImproveProposalAcceptanceGate::strict();
        let advisory = SelfImproveProposalAcceptanceReport::from_gate_and_evidence(
            &gate,
            &SelfImproveProposalEvidence::clean_candidate(
                392,
                ["ledger.round.392.helper_stage_contract.review.change_request"],
                "helper_stage_contract.test-gate.validation_command",
                "Update validation command evidence.",
                SelfImproveMemoryAdmissionCandidate::quarantined(
                    "self-improve-r392-helper-contract",
                    vec!["report-only candidate".to_owned()],
                ),
            )
            .with_validation(true, true)
            .with_validation_command_source(
                "helper_stage_contract.test-gate.validation_command",
                true,
            ),
        );
        let summary = SelfImproveProposalAcceptanceSummaryReport::from_reports(&[advisory.clone()]);
        let plan = SelfImproveProposalActionPlan::from_summary(1, &summary);

        let assignment =
            SelfImproveProposalActionAssignment::from_reports_and_plan(&[advisory], &plan);

        assert!(assignment.action_required);
        assert_eq!(
            assignment.primary_action,
            "convert_advisory_to_evidence_backed_business_improvement"
        );
        assert_eq!(assignment.target_count, 1);
        assert!(assignment.requires_checked_passed_validation_and_accepted_memory_admission);
        let target = assignment.targets.first().unwrap();
        assert_eq!(target.proposal_id, "self-improve-r392-helper-contract");
        assert_eq!(target.source_round, Some(392));
        assert_eq!(target.current_memory_admission_decision, "quarantined");
        assert!(target.advisory_only);
        assert!(!target.require_repair);
        assert!(target.validation_checked);
        assert!(target.validation_passed);
        assert!(!target.memory_admission_accepted);
        assert!(!target.evidence_backed_business_improvement);
        assert_eq!(
            target.missing_requirements,
            vec![
                "accepted_memory_admission".to_owned(),
                "evidence_backed_business_improvement".to_owned()
            ]
        );
        let first_target = assignment.first_target_digest().unwrap();
        assert_eq!(first_target.proposal_id, target.proposal_id);
        assert_eq!(first_target.source_round, Some(392));
        assert_eq!(first_target.evidence_ids, target.evidence_ids);
        assert_eq!(
            first_target.current_memory_admission_decision,
            "quarantined"
        );
        assert!(first_target.validation_checked);
        assert!(first_target.validation_passed);
        assert!(!first_target.memory_admission_accepted);
        assert!(!first_target.evidence_backed_business_improvement);
        assert!(first_target.advisory_only);
        assert!(!first_target.require_repair);
        assert_eq!(
            first_target.missing_requirements,
            target.missing_requirements
        );
    }

