    #[test]
    fn self_improve_proposal_action_closure_marks_code_action_closed_without_admission() {
        let gate = SelfImproveProposalAcceptanceGate::strict();
        let advisory = SelfImproveProposalAcceptanceReport::from_gate_and_evidence(
            &gate,
            &SelfImproveProposalEvidence::clean_candidate(
                392,
                ["ledger.round.392.helper_stage_contract.review.change_request"],
                "helper_stage_contract.test-gate.validation_command",
                "Update validation command to include --no-fail-fast.",
                SelfImproveMemoryAdmissionCandidate::quarantined(
                    "self-improve-r392-helper-contract",
                    vec!["report-only candidate".to_owned()],
                ),
            )
            .with_validation(true, true)
            .with_validation_command_source(
                "helper_stage_contract.test-gate.validation_command",
                true,
            ),
        );
        let summary = SelfImproveProposalAcceptanceSummaryReport::from_reports(&[advisory.clone()]);
        let plan = SelfImproveProposalActionPlan::from_summary(1, &summary);
        let assignment =
            SelfImproveProposalActionAssignment::from_reports_and_plan(&[advisory], &plan);
        let evidence = vec![SelfImproveProposalActionClosureEvidence {
            proposal_id: "self-improve-r392-helper-contract".to_owned(),
            source_round: Some(392),
            closure_kind: "test_gate_no_fail_fast".to_owned(),
            code_evidence_present: true,
            code_evidence_ids: vec![
                "tools/evolution-loop/src/pool_stage_call.rs::DEFAULT_TEST_GATE_VALIDATION_COMMAND"
                    .to_owned(),
                "tools/evolution-loop/src/helper_stage_repair.rs::VALIDATION_COMMAND".to_owned(),
            ],
            validation_evidence_present: true,
            validation_evidence_ids: vec![
                "cargo test -q --manifest-path tools/evolution-loop/Cargo.toml test_gate"
                    .to_owned(),
            ],
            validation_passed: true,
            memory_store_write_attempted: false,
            ndkv_write_attempted: false,
            notes: vec!["validation command now includes --no-fail-fast".to_owned()],
        }];

        let report = SelfImproveProposalActionClosureReport::from_assignment_and_evidence(
            &assignment,
            &evidence,
        );

        assert_eq!(report.target_count, 1);
        assert_eq!(report.closed_target_count, 1);
        assert_eq!(report.open_target_count, 0);
        assert!(report.first_target_closed);
        assert!(report.all_targets_closed());
        assert_eq!(
            report.first_target_closure_kind.as_deref(),
            Some("test_gate_no_fail_fast")
        );
        assert!(report.first_target_still_requires_memory_admission);
        let item = report.closure_items.first().unwrap();
        assert!(item.closed);
        assert!(item.still_requires_memory_admission);
        assert_eq!(
            item.missing_requirements,
            vec![
                "accepted_memory_admission".to_owned(),
                "evidence_backed_business_improvement".to_owned()
            ]
        );
    }

