        assert!(contract.forbids_capability("http_sse"));
        assert!(contract.forbids_capability("process_spawn"));
        assert!(contract.forbids_capability("model_call"));
        assert!(!contract.allows_input("EvolutionLoopRunner"));
        assert!(!contract.allows_input("JsonlLedgerReader"));
        assert!(!contract.allows_input("ValidationCommandExecutor"));
