    fn clean_validation_command_coverage_report() -> ValidationCommandCoverageReport {
        let outcome = norion_test::CommandOutcome {
            command_line:
                "cargo test --manifest-path crates/norion-eval/Cargo.toml --strict-coverage"
                    .to_owned(),
            status_code: Some(0),
            elapsed_ms: 42,
            stdout_tail: "coverage report generated".to_owned(),
            stderr_tail: String::new(),
        };
        let evidence = ValidationCommandCoverageEvidence::from_observations([
            ValidationObservation::from_outcome(VerificationPhase::PostRound, outcome),
        ])
        .with_rust_check(true, true)
        .with_coverage_tooling_evidence(["cargo llvm-cov"])
        .with_coverage_report_evidence(["target/coverage/lcov.info"]);

        ValidationCommandCoverageReport::from_gate_and_evidence(
            &ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced),
            &evidence,
        )
    }

    fn clean_strict_unattended_acceptance_inputs() -> (
        StrictUnattendedSupervisorEvidence,
        RunModeReportRefreshAcceptanceReport,
        AdapterClosureReport,
        ValidationCommandCoverageReport,
        RollbackResumeReport,
        SelfEvolutionRegressionReport,
        SelfEvolutionReadinessReport,
        SelfEvolutionUnattendedPrerequisiteReport,
    ) {
        let supervisor = StrictUnattendedSupervisorEvidence::from_status(true, true, true, true);
        let report_refresh = RunModeReportRefreshAcceptanceReport {
            report_refresh_allowed: true,
            ledger_gate_allow_next_round: true,
            remote_runtime_acceleration_ready: true,
            report_bundle_complete: true,
            allow_next_round: true,
            failure_reasons: Vec::new(),
        };
        let ledger_records = vec![
            LedgerRecord::success(1, 128, "qwen").with_rust_check(true, true, 1),
            LedgerRecord::success(2, 128, "qwen").with_rust_check(true, true, 1),
            LedgerRecord::success(3, 128, "qwen").with_rust_check(true, true, 1),
        ];
        let ledger_gate_report = LedgerGateReport::from_records_and_gate(
            &ledger_records,
            &ReportGate {
                min_rounds: 3,
                ..ReportGate::strict()
            },
        );
        let validation = clean_validation_command_coverage_report();
        let readiness = SelfEvolutionReadinessReport::from_snapshot(
            &SelfEvolutionReadinessSnapshot::clean(RootAdapterRolloutStage::Enforced),
        );
        let adapter_closure = AdapterClosureReport::from_reports(
            RootAdapterRolloutStage::Enforced,
            true,
            &ledger_gate_report,
            &validation,
            &readiness,
        );
        let rollback_resume = RollbackResumeReport::from_evidence_for_stage(
            &RollbackResumeEvidence::all_clear_for_resume_gate("none"),
            RootAdapterRolloutStage::Enforced,
        );
        let regression = SelfEvolutionRegressionReport::from_records_and_gate(
            &ledger_records,
            &SelfEvolutionRegressionGate::strict(),
        );
        let self_evolution = SelfEvolutionUnattendedPrerequisiteReport::from_gate_and_evidence(
            &SelfEvolutionUnattendedPrerequisiteGate::for_stage(RootAdapterRolloutStage::Enforced),
            &SelfEvolutionUnattendedPrerequisiteEvidence::all_passed(),
        );

        (
            supervisor,
            report_refresh,
            adapter_closure,
            validation,
            rollback_resume,
            regression,
            readiness,
            self_evolution,
        )
    }

    #[test]
    fn strict_unattended_acceptance_report_schema_stages_allow_and_failure_surface() {
        let schema = StrictUnattendedAcceptanceReportSchema::strict_unattended_acceptance_v1();
        let names = schema.field_names();
        let report_only_names = schema
            .fields_for_stage(RootAdapterRolloutStage::ReportOnly)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforced_names = schema
            .fields_for_stage(RootAdapterRolloutStage::Enforced)
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();

        assert!(names.contains(&"strict_unattended_acceptance.supervisor_status_observed"));
        assert!(names.contains(&"strict_unattended_acceptance.daemon_running"));
        assert!(
            names.contains(&"strict_unattended_acceptance.strict_unattended_evolution_enabled")
        );
        assert!(names.contains(&"strict_unattended_acceptance.configured_validation_enabled"));
        assert!(names.contains(&"strict_unattended_acceptance.supervisor_check_only"));
        assert!(names.contains(&"strict_unattended_acceptance.adapter_closure_allow_next_round"));
        assert!(names.contains(&"strict_unattended_acceptance.validation_allow_next_round"));
        assert!(
            names.contains(&"strict_unattended_acceptance.rollback_resume_allow_unattended_rounds")
        );
        assert!(names.contains(
            &"strict_unattended_acceptance.self_improve_regression_allow_unattended_continuation"
        ));
        assert!(names.contains(&"strict_unattended_acceptance.readiness_can_schedule_next_round"));
        assert!(names.contains(&"strict_unattended_acceptance.failure_reasons"));
        assert!(report_only_names.contains(&"strict_unattended_acceptance.starts_process"));
        assert!(!report_only_names.contains(&"strict_unattended_acceptance.allow_next_round"));
        assert!(enforced_names.contains(&"strict_unattended_acceptance.allow_next_round"));
        assert!(enforced_names.contains(&"strict_unattended_acceptance.failure_reasons"));
    }

    #[test]
    fn strict_unattended_acceptance_report_allows_when_all_evidence_backed_gates_allow() {
        let (
            supervisor,
            report_refresh,
            adapter_closure,
            validation,
            rollback_resume,
            regression,
            readiness,
            self_evolution,
        ) = clean_strict_unattended_acceptance_inputs();

        let report = StrictUnattendedAcceptanceReport::from_reports(
            &supervisor,
            &report_refresh,
            &adapter_closure,
            &validation,
            &rollback_resume,
            &regression,
            &readiness,
            &self_evolution,
        );

        assert!(report.supervisor_status_observed);
        assert!(report.daemon_running);
        assert!(report.strict_unattended_evolution_enabled);
        assert!(report.configured_validation_enabled);
        assert!(report.supervisor_check_only);
        assert!(!report.starts_process);
        assert!(!report.sends_prompt);
        assert!(!report.touches_remote);
        assert!(report.supervisor_allow_next_round);
        assert!(report.report_refresh_allow_next_round);
        assert!(report.adapter_closure_allow_next_round);
        assert!(report.validation_allow_next_round);
        assert!(report.rollback_resume_allow_unattended_rounds);
        assert!(report.self_improve_regression_allow_unattended_continuation);
        assert!(report.readiness_can_schedule_next_round);
        assert!(report.self_evolution_allow_unattended_claim);
        assert!(report.allow_next_round);
        assert!(report.failure_reasons.is_empty());
    }

    #[test]
    fn strict_unattended_acceptance_report_collects_failure_reasons_without_helper_prose() {
        let (
            supervisor,
            mut report_refresh,
            adapter_closure,
            validation,
            mut rollback_resume,
            mut regression,
            readiness,
            mut self_evolution,
        ) = clean_strict_unattended_acceptance_inputs();
        let supervisor = supervisor
            .with_stale_pid_detected(true)
            .with_side_effect_flags(true, true, true);
        report_refresh.allow_next_round = false;
        report_refresh
            .failure_reasons
            .push("report refresh ledger_lag 1 above maximum 0".to_owned());
        rollback_resume.allow_unattended_rounds = false;
        rollback_resume
            .failure_reasons
            .push("validation command coverage has not passed before unattended resume".to_owned());
        regression.allow_unattended_continuation = false;
        regression
            .failure_reasons
            .push("self-evolution self_improve pass rate 0.667 below minimum 1.000".to_owned());
        self_evolution.allow_unattended_self_evolution_claim = false;
        self_evolution.failure_reasons.push(
            "validation command coverage gate did not pass before unattended self-evolution claim"
                .to_owned(),
        );

        let report = StrictUnattendedAcceptanceReport::from_reports(
            &supervisor,
            &report_refresh,
            &adapter_closure,
            &validation,
            &rollback_resume,
            &regression,
            &readiness,
            &self_evolution,
        );

        assert!(!report.supervisor_check_only);
        assert!(report.stale_pid_detected);
        assert!(report.starts_process);
        assert!(report.sends_prompt);
        assert!(report.touches_remote);
        assert!(!report.supervisor_allow_next_round);
        assert!(!report.report_refresh_allow_next_round);
        assert!(!report.rollback_resume_allow_unattended_rounds);
        assert!(!report.self_improve_regression_allow_unattended_continuation);
        assert!(!report.self_evolution_allow_unattended_claim);
        assert!(!report.allow_next_round);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("stale pid"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("started a process"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("ledger_lag"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("self_improve pass rate"))
        );
        assert!(
            !report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("helper prose"))
        );
    }

