    #[test]
    fn adapter_closure_schema_document_rejects_runner_capability_drift() {
        let schema = AdapterClosureReportSchema::adapter_closure_v1();
        let contract = AdapterClosurePureDataContract::adapter_closure_v1();
        let document = contract.schema_document(&schema);

        assert!(contract.schema_document_within_boundary(&document, &schema));
        assert!(document.allows_input("LedgerRecord"));
        assert!(document.requires_prior_report("ledger_gate_report_v1"));
        assert!(document.forbids_capability("jsonl_io"));
        assert!(document.forbids_capability("http_sse"));
        assert!(document.forbids_capability("process_spawn"));
        assert!(document.forbids_capability("model_call"));

        let mut runner_input = document.clone();
        runner_input.allowed_inputs.push("EvolutionLoopRunner");
        assert!(!contract.schema_document_within_boundary(&runner_input, &schema));

        let mut runner_entrypoint = document.clone();
        runner_entrypoint
            .entrypoints
            .push("EvolutionLoopRunner::adapter_closure_from_state");
        assert!(!contract.schema_document_within_boundary(&runner_entrypoint, &schema));

        let mut process_entrypoint = document.clone();
        process_entrypoint
            .entrypoints
            .push("ValidationCommandExecutor::spawn_adapter_closure");
        assert!(!contract.schema_document_within_boundary(&process_entrypoint, &schema));

        let mut missing_forbidden_capability = document.clone();
        missing_forbidden_capability
            .forbidden_capabilities
            .retain(|capability| *capability != "http_sse");
        assert!(!contract.schema_document_within_boundary(&missing_forbidden_capability, &schema));

        let mut runner_field = document;
        runner_field
            .field_names
            .push("adapter_closure.runner_state");
        assert!(!contract.schema_document_within_boundary(&runner_field, &schema));
    }

