    fn adapter_closure_schema_drift_blocks_missing_document_field_coverage() {
        let schema = AdapterClosureReportSchema::adapter_closure_v1();
        let contract = AdapterClosurePureDataContract::adapter_closure_v1();
        let document = contract.schema_document(&schema);
        let mut evidence = EvalSchemaDriftEvidence::from_adapter_closure_schema_document(
            RootAdapterRolloutStage::Enforced,
            &document,
        );
        evidence
            .adapter_emission_report_field_names
            .retain(|field| *field != "adapter_closure.allow_next_round");
        let report = EvalSchemaDriftReport::from_gate_and_evidence(
            &EvalSchemaDriftGate::for_stage(RootAdapterRolloutStage::Enforced),
            &evidence,
        );

        assert!(report.drift_blocked);
        assert!(!report.allow_runner_wiring);
        assert!(
            report
                .missing_report_field_names
                .contains(&"adapter_closure.allow_next_round".to_owned())
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| { reason.contains("adapter report field contract missing fields") })
        );
    }

    #[test]
    fn adapter_report_field_coverage_gap_flows_through_pure_data_gates() {
        let missing_field = "adapter_closure.allow_next_round";
        let emission_plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let observed_fields = emission_plan
            .required_report_fields()
            .into_iter()
            .filter(|field| *field != missing_field)
            .collect::<Vec<_>>();
        let emission_report = AdapterReportEmissionReport::from_gate_plan_and_evidence(
            &AdapterReportEmissionGate::for_stage(RootAdapterRolloutStage::Enforced),
            &emission_plan,
            &AdapterReportEmissionEvidence::from_observed_with_report_fields(
                emission_plan.report_names(),
                emission_plan.future_events(),
                observed_fields,
            ),
        );

        let schema = AdapterClosureReportSchema::adapter_closure_v1();
        let contract = AdapterClosurePureDataContract::adapter_closure_v1();
        let closure_document = contract.schema_document(&schema);
        let schema_drift_evidence = EvalSchemaDriftEvidence::from_adapter_closure_schema_document(
            RootAdapterRolloutStage::Enforced,
            &closure_document,
        )
        .with_adapter_report_field_coverage_from_report(&emission_report);
        let schema_drift_report = EvalSchemaDriftReport::from_gate_and_evidence(
            &EvalSchemaDriftGate::for_stage(RootAdapterRolloutStage::Enforced),
            &schema_drift_evidence,
        );

        let bundle_manifest =
            EvalReportBundleManifest::for_stage(RootAdapterRolloutStage::Enforced);
        let bundle_report = EvalReportBundleGateReport::from_manifest_and_evidence(
            &bundle_manifest,
            &EvalReportBundleEvidence::from_schema_names(bundle_manifest.schema_names.clone())
                .with_adapter_report_field_coverage_from_report(&emission_report),
        );
        let current_runner_report = CurrentRunnerCompatibilityReport::from_gate_and_evidence(
            &CurrentRunnerCompatibilityGate::for_stage(RootAdapterRolloutStage::Enforced),
            &CurrentRunnerCompatibilityEvidence {
                legacy_replay_passed: true,
                report_bundle_complete: bundle_report.complete,
                schema_drift_passed: schema_drift_report.allow_runner_wiring,
                adapter_report_emission_passed: !emission_report.emission_blocked,
                adapter_report_field_coverage_passed: emission_report.field_coverage_passed(),
                adapter_fixture_passed: true,
                evolution_loop_tests_passed: true,
                workspace_tests_passed: true,
                ..CurrentRunnerCompatibilityEvidence::crate_only()
            },
        );

        assert_eq!(emission_report.missing_report_fields, vec![missing_field]);
        assert!(!emission_report.field_coverage_passed());
        assert!(
            schema_drift_report
                .missing_report_field_names
                .contains(&missing_field.to_owned())
        );
        assert!(schema_drift_report.drift_blocked);
        assert!(!schema_drift_report.allow_runner_wiring);
        assert!(bundle_report.missing_schema_names.is_empty());
        assert!(!bundle_report.adapter_report_field_coverage_passed);
        assert!(bundle_report.bundle_blocked);
        assert!(!bundle_report.complete);
        assert!(current_runner_report.compatibility_blocked);
        assert!(!current_runner_report.allow_enforced_wiring);
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report emission"))
        );
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report field coverage"))
        );
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("schema drift"))
        );
        assert!(
            current_runner_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("report bundle"))
        );
    }

    #[test]
    fn validation_command_coverage_blocks_missing_command_evidence_before_next_round() {
        let observation = ValidationObservation::from_outcome(
            VerificationPhase::PreRound,
            norion_test::CommandOutcome {
                command_line: "cargo test --manifest-path crates/norion-eval/Cargo.toml".to_owned(),
                status_code: None,
                elapsed_ms: 42,
                stdout_tail: String::new(),
                stderr_tail: String::new(),
            },
        );
        let observations = vec![observation];
        let evidence = ValidationCommandCoverageEvidence::from_observations(observations.clone())
            .with_rust_check(true, false);
        let gate = ValidationCommandCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = ValidationCommandCoverageReport::from_gate_and_evidence(&gate, &evidence);
        let observations_report = ValidationCommandCoverageReport::from_observations_and_gate(
            observations,
            true,
            false,
            &gate,
        );

        assert_eq!(observations_report, report);
        assert!(report.coverage_blocked);
        assert_eq!(report.coverage_failure_kind, "validation_command_coverage");
        assert!(!report.model_quality_failure_counted);
        assert!(!report.allow_next_round);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("required phase"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("status codes present 0/1"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("output tails captured 0/1"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("validation commands passed 0/1"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("rust-check command failed"))
        );
    }

    #[test]
    fn adapter_validation_command_coverage_boundary_contract_matches_norion_test_plan() {
        let contract =
            AdapterValidationCommandCoverageBoundaryContract::validation_command_coverage_v1();
        let plan =
            norion_test::AdapterValidationCommandCoverageBoundaryPlan::validation_command_coverage(
                "validation-command-boundary",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let entrypoints = contract
            .entrypoints
            .iter()
            .map(|entrypoint| entrypoint.to_string())
            .collect::<Vec<_>>();
        let allowed_inputs = contract
            .allowed_inputs
            .iter()
            .map(|input| input.to_string())
            .collect::<Vec<_>>();
        let produced_outputs = contract
            .produced_outputs
            .iter()
            .map(|output| output.to_string())
            .collect::<Vec<_>>();
        let forbidden_capabilities = contract
            .forbidden_capabilities
            .iter()
            .map(|capability| capability.to_string())
            .collect::<Vec<_>>();

        assert_eq!(plan.eval_entrypoints, entrypoints);
        assert_eq!(plan.allowed_inputs, allowed_inputs);
        assert_eq!(plan.produced_outputs, produced_outputs);
        assert_eq!(plan.forbidden_capabilities, forbidden_capabilities);
        assert!(
            contract.exposes_entrypoint("ValidationCommandCoverageEvidence::from_observations")
        );
        assert!(contract.exposes_entrypoint("ValidationCommandCoverageGate::evaluate"));
        assert!(
            contract.exposes_entrypoint("ValidationCommandCoverageReport::from_gate_and_evidence")
        );
        assert!(contract.allows_input("ValidationObservation"));
        assert!(contract.allows_input("CommandOutcome"));
        assert!(contract.allows_input("ValidationCommandCoverageGate"));
        assert!(!contract.allows_input("ValidationCommandExecutor"));
        assert!(!contract.allows_input("EvolutionLoopRunner"));
        assert!(contract.produces_output("ValidationCommandCoverageReport"));
        assert!(contract.forbids_capability("validation_command_spawn"));
        assert!(contract.forbids_capability("validation_command_execution"));
        assert!(contract.forbids_capability("process_spawn"));
        assert!(contract.forbids_capability("model_call"));
        assert!(contract.stays_pure_data_boundary());
        assert!(plan.stays_pure_data_boundary());
        assert!(plan.preserves_legacy_runner);
        assert!(!plan.may_block_current_runner());
    }

