    #[test]
    fn steam_case_coverage_report_allows_complete_business_cycle_matrix() {
        let rows = vec![
            SteamCaseCoverageRow::business_cycle("planning")
                .with_case_kind(SteamCaseKind::Planning),
            SteamCaseCoverageRow::business_cycle("validation")
                .with_case_kind(SteamCaseKind::Validation),
            SteamCaseCoverageRow::business_cycle("rollback")
                .with_case_kind(SteamCaseKind::Rollback),
            SteamCaseCoverageRow::business_cycle("apple-silicon-pool")
                .with_case_kind(SteamCaseKind::AppleSiliconModelPool),
        ];
        let evidence = SteamCaseCoverageEvidence::from_rows(rows.clone());
        let gate = SteamCaseCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = SteamCaseCoverageReport::from_gate_and_evidence(&gate, &evidence);
        let rows_report = SteamCaseCoverageReport::from_rows_and_gate(rows, &gate);

        assert_eq!(rows_report, report);
        assert_eq!(report.stage, "enforced");
        assert_eq!(report.case_count, 4);
        assert_eq!(report.min_cases, 4);
        assert_eq!(
            report.case_kinds,
            vec![
                "planning",
                "validation",
                "rollback",
                "apple_silicon_model_pool"
            ]
        );
        assert_eq!(report.stream_passed_cases, 4);
        assert_eq!(report.validation_passed_cases, 4);
        assert_eq!(report.business_cycle_passed_cases, 4);
        assert!(
            report
                .endpoints
                .contains(&"/v1/business-cycle-stream".to_owned())
        );
        assert!(
            report
                .required_final_json_fields
                .contains(&"business_cycle.passed")
        );
        assert!(
            report
                .required_case_kinds
                .contains(&"apple_silicon_model_pool")
        );
        assert!(report.missing_required_case_kinds.is_empty());
        assert!(report.missing_required_fields.is_empty());
        assert!(!report.coverage_blocked);
        assert!(report.allow_enforced_adapter);
    }

    #[test]
    fn steam_case_coverage_keeps_incomplete_matrix_report_only() {
        let evidence = SteamCaseCoverageEvidence::from_rows([
            SteamCaseCoverageRow::business_cycle("planning")
                .with_case_kind(SteamCaseKind::Planning),
            SteamCaseCoverageRow::business_cycle("planning")
                .with_case_kind(SteamCaseKind::Planning)
                .with_endpoint("/v1/generate")
                .with_stream_passed(false)
                .with_validation(true, false)
                .with_business_cycle_passed(Some(false)),
            SteamCaseCoverageRow::business_cycle("validation")
                .with_case_kind(SteamCaseKind::Validation)
                .with_final_json_fields(["business_cycle.passed", "generate.runtime_model"]),
        ]);
        let gate = SteamCaseCoverageGate::for_stage(RootAdapterRolloutStage::ReportOnly);
        let report = SteamCaseCoverageReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.stage, "report_only");
        assert_eq!(report.case_count, 3);
        assert_eq!(report.min_cases, 4);
        assert_eq!(report.stream_passed_cases, 2);
        assert_eq!(report.validation_passed_cases, 2);
        assert_eq!(report.business_cycle_passed_cases, 2);
        assert!(report.endpoints.contains(&"/v1/generate".to_owned()));
        assert!(report.missing_required_case_kinds.contains(&"rollback"));
        assert!(
            report
                .missing_required_case_kinds
                .contains(&"apple_silicon_model_pool")
        );
        assert!(
            report
                .missing_required_fields
                .contains(&"validation:business_cycle.feedback_applied".to_owned())
        );
        assert!(
            report
                .missing_required_fields
                .contains(&"validation:generate.runtime_tokens".to_owned())
        );
        assert!(!report.coverage_blocked);
        assert!(report.allow_enforced_adapter);
        assert!(report.failure_reasons.is_empty());
    }

    #[test]
    fn steam_case_coverage_blocks_incomplete_or_duplicate_matrix_before_enforcement() {
        let rows = vec![
            SteamCaseCoverageRow::business_cycle("planning")
                .with_case_kind(SteamCaseKind::Planning),
            SteamCaseCoverageRow::business_cycle("planning")
                .with_case_kind(SteamCaseKind::Planning)
                .with_endpoint("/v1/generate")
                .with_stream_passed(false)
                .with_validation(true, false)
                .with_business_cycle_passed(Some(false)),
            SteamCaseCoverageRow::business_cycle("validation")
                .with_case_kind(SteamCaseKind::Validation)
                .with_final_json_fields(["business_cycle.passed", "generate.runtime_model"]),
        ];
        let evidence = SteamCaseCoverageEvidence::from_rows(rows.clone());
        let gate = SteamCaseCoverageGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = SteamCaseCoverageReport::from_gate_and_evidence(&gate, &evidence);
        let rows_report = SteamCaseCoverageReport::from_rows_and_gate(rows, &gate);

        assert_eq!(rows_report, report);
        assert!(report.coverage_blocked);
        assert!(!report.allow_enforced_adapter);
        assert!(
            report
                .missing_required_fields
                .contains(&"validation:business_cycle.feedback_applied".to_owned())
        );
        assert!(report.missing_required_case_kinds.contains(&"rollback"));
        assert!(
            report
                .missing_required_case_kinds
                .contains(&"apple_silicon_model_pool")
        );
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("missing required case kind")
                && reason.contains("apple_silicon_model_pool")
        }));
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("unsupported endpoint"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("duplicated"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("stream continuity passed 2/3"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("steam validation passed 2/3"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("business-cycle final JSON passed 2/3"))
        );
    }

