    #[test]
    fn worker_event_schema_distinguishes_projection_from_enforcement_fields() {
        let schema = WorkerEventSchema::model_worker_v1();
        let projection_names = schema
            .required_for_projection()
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();
        let enforcement_names = schema
            .required_for_enforcement()
            .iter()
            .map(|field| field.name)
            .collect::<Vec<_>>();

        assert_eq!(schema.event_name, "model_worker_v1");
        assert!(projection_names.contains(&"worker_id"));
        assert!(projection_names.contains(&"runtime_tokens"));
        assert!(!projection_names.contains(&"duplicate_output"));
        assert!(enforcement_names.contains(&"worker_id"));
        assert!(enforcement_names.contains(&"duplicate_output"));
        assert!(enforcement_names.contains(&"noisy_output"));
        assert!(enforcement_names.contains(&"blocked_primary_12b"));
        assert!(enforcement_names.contains(&"failure_kind"));
        assert!(schema.fields.iter().any(|field| {
            field.name == "duplicate_output"
                && !field.required_for_projection
                && field.required_for_enforcement
        }));
    }

