    #[test]
    fn apple_silicon_model_pool_outage_attribution_is_not_quality_failure() {
        let contract = RootAdapterAcceptanceContract::enforced();
        let prompt_blocked_and_down = RootAdapterFailureEvidence {
            backend_8686_reachable: Some(false),
            prompt_gate_blocked: true,
            final_json_present: false,
            runtime_model_present: false,
            runtime_tokens: None,
            business_cycle_passed: None,
            error: Some("prompt gate blocked before backend 8686 recovered".to_owned()),
        };
        let backend_down = RootAdapterFailureEvidence {
            prompt_gate_blocked: false,
            ..prompt_blocked_and_down.clone()
        };

        assert_eq!(
            classify_root_adapter_failure(&prompt_blocked_and_down),
            RootAdapterFailureKind::ChainNotReady
        );
        assert_eq!(
            classify_root_adapter_failure(&backend_down),
            RootAdapterFailureKind::ModelUnavailable
        );
        assert!(!contract.model_quality_failure_allowed(&prompt_blocked_and_down));
        assert!(!contract.model_quality_failure_allowed(&backend_down));
    }

