    #[test]
    fn root_adapter_rollback_policy_keeps_infra_and_quality_reasons_separate() {
        let chain = rollback_plan_for_root_adapter_failure(RootAdapterFailureKind::ChainNotReady);
        let unavailable =
            rollback_plan_for_root_adapter_failure(RootAdapterFailureKind::ModelUnavailable);
        let quality =
            rollback_plan_for_root_adapter_failure(RootAdapterFailureKind::ModelQualityFailure);

        assert_eq!(chain.reason, "chain_not_ready");
        assert!(
            chain
                .actions
                .iter()
                .any(|action| action.contains("chain readiness"))
        );
        assert_eq!(unavailable.reason, "model_unavailable");
        assert!(
            unavailable
                .actions
                .iter()
                .any(|action| action.contains("backend 8686"))
        );
        assert_eq!(quality.reason, "model_quality_failure");
        assert!(
            quality
                .actions
                .iter()
                .any(|action| action.contains("model-quality review"))
        );
        assert!(
            !chain
                .actions
                .iter()
                .any(|action| action.contains("model-quality review"))
        );
        assert!(
            !unavailable
                .actions
                .iter()
                .any(|action| action.contains("model-quality review"))
        );
    }

