    #[test]
    fn adapter_rollback_drill_matrix_boundary_contract_matches_norion_test_plan() {
        let contract = AdapterRollbackDrillMatrixBoundaryContract::rollback_drill_matrix_v1();
        let plan =
            norion_test::AdapterRollbackDrillMatrixBoundaryPlan::rollback_drill_matrix_boundary(
                "rollback-drill-boundary",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let entrypoints = contract
            .entrypoints
            .iter()
            .map(|entrypoint| entrypoint.to_string())
            .collect::<Vec<_>>();
        let allowed_inputs = contract
            .allowed_inputs
            .iter()
            .map(|input| input.to_string())
            .collect::<Vec<_>>();
        let produced_outputs = contract
            .produced_outputs
            .iter()
            .map(|output| output.to_string())
            .collect::<Vec<_>>();
        let forbidden_capabilities = contract
            .forbidden_capabilities
            .iter()
            .map(|capability| capability.to_string())
            .collect::<Vec<_>>();

        assert_eq!(plan.eval_entrypoints, entrypoints);
        assert_eq!(plan.allowed_inputs, allowed_inputs);
        assert_eq!(plan.produced_outputs, produced_outputs);
        assert_eq!(plan.forbidden_capabilities, forbidden_capabilities);
        assert!(contract.exposes_entrypoint("RollbackDrillCase::from_failure_kind"));
        assert!(
            contract.exposes_entrypoint("RollbackDrillMatrixEvidence::root_adapter_policy_matrix")
        );
        assert!(contract.exposes_entrypoint("RollbackDrillMatrixGate::evaluate"));
        assert!(contract.exposes_entrypoint("RollbackDrillMatrixReport::from_gate_and_evidence"));
        assert!(contract.allows_input("RootAdapterFailureKind"));
        assert!(contract.allows_input("RollbackDrillCase"));
        assert!(contract.allows_input("RollbackDrillMatrixEvidence"));
        assert!(contract.allows_input("RollbackDrillMatrixGate"));
        assert!(!contract.allows_input("RollbackActionExecutor"));
        assert!(!contract.allows_input("ResumeActionExecutor"));
        assert!(!contract.allows_input("EvolutionLoopRunner"));
        assert!(contract.produces_output("RollbackDrillCase"));
        assert!(contract.produces_output("RollbackDrillMatrixEvidence"));
        assert!(contract.produces_output("GateDecision"));
        assert!(contract.produces_output("RollbackDrillMatrixReport"));
        assert!(contract.stays_pure_data_boundary());
        assert!(contract.forbids_capability("jsonl_io"));
        assert!(contract.forbids_capability("http_sse"));
        assert!(contract.forbids_capability("process_spawn"));
        assert!(contract.forbids_capability("validation_command_spawn"));
        assert!(contract.forbids_capability("model_call"));
        assert!(contract.forbids_capability("rollback_action_execution"));
        assert!(contract.forbids_capability("resume_action_execution"));
        assert!(contract.forbids_capability("runner_state"));
        assert!(plan.stays_pure_data_boundary());
        assert!(!plan.may_block_current_runner());
        assert!(plan.preserves_legacy_runner);
    }

    #[test]
    fn rollback_drill_matrix_keeps_unstable_policy_report_only() {
        let evidence = RollbackDrillMatrixEvidence::from_cases(vec![
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::None)
                .with_rollback_required(true),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ChainNotReady)
                .with_rollback_reason("model_quality_failure"),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ModelUnavailable)
                .with_resume_gate("model_quality_review"),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ModelQualityFailure)
                .with_rollback_actions(Vec::<String>::new()),
        ]);
        let gate = RollbackDrillMatrixGate::for_stage(RootAdapterRolloutStage::ReportOnly);
        let report = RollbackDrillMatrixReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.stage, "report_only");
        assert!(!report.drill_blocked);
        assert!(report.allow_enforced_rollback_policy);
        assert!(report.failure_reasons.is_empty());
        assert!(
            report
                .missing_failure_kinds
                .contains(&"runtime_response_missing")
        );
        assert!(
            report
                .missing_failure_kinds
                .contains(&"stream_or_final_missing")
        );
        assert!(report.missing_failure_kinds.contains(&"unknown"));
        assert!(report.unstable_rollback_reasons.iter().any(|reason| {
            reason.contains("chain_not_ready") && reason.contains("model_quality_failure")
        }));
        assert!(
            report
                .unstable_resume_gates
                .iter()
                .any(|reason| reason.contains("model_unavailable"))
        );
        assert!(
            report
                .empty_action_failure_kinds
                .contains(&"model_quality_failure")
        );
        assert!(report.none_requires_rollback);
    }

    #[test]
    fn rollback_drill_matrix_blocks_unstable_enforced_policy() {
        let evidence = RollbackDrillMatrixEvidence::from_cases(vec![
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::None)
                .with_rollback_required(true),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ChainNotReady)
                .with_rollback_reason("model_quality_failure"),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ModelUnavailable)
                .with_resume_gate("model_quality_review"),
            RollbackDrillCase::from_failure_kind(RootAdapterFailureKind::ModelQualityFailure)
                .with_rollback_actions(Vec::<String>::new()),
        ]);
        let gate = RollbackDrillMatrixGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = RollbackDrillMatrixReport::from_gate_and_evidence(&gate, &evidence);

        assert!(report.drill_blocked);
        assert!(!report.allow_enforced_rollback_policy);
        assert!(
            report
                .missing_failure_kinds
                .contains(&"runtime_response_missing")
        );
        assert!(
            report
                .missing_failure_kinds
                .contains(&"stream_or_final_missing")
        );
        assert!(report.missing_failure_kinds.contains(&"unknown"));
        assert!(
            report
                .unstable_rollback_reasons
                .iter()
                .any(|reason| reason.contains("chain_not_ready"))
        );
        assert!(
            report
                .unstable_resume_gates
                .iter()
                .any(|reason| reason.contains("model_unavailable"))
        );
        assert!(
            report
                .empty_action_failure_kinds
                .contains(&"model_quality_failure")
        );
        assert!(report.none_requires_rollback);
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("missing failure kinds"))
        );
        assert!(
            report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("unstable rollback reasons"))
        );
    }

