    #[test]
    fn adapter_fixture_contract_allows_complete_pre_wiring_fixture_set() {
        let chain = AdapterFixtureCase::new(
            "prompt-gate-blocked",
            RootAdapterFailureEvidence {
                prompt_gate_blocked: true,
                backend_8686_reachable: Some(false),
                final_json_present: false,
                runtime_model_present: false,
                runtime_tokens: None,
                business_cycle_passed: None,
                error: Some("prompt gate blocked".to_owned()),
            },
            RootAdapterFailureKind::ChainNotReady,
        )
        .with_all_projections_checked();
        let unavailable = AdapterFixtureCase::new(
            "backend-8686-down",
            RootAdapterFailureEvidence {
                backend_8686_reachable: Some(false),
                prompt_gate_blocked: false,
                final_json_present: false,
                runtime_model_present: false,
                runtime_tokens: None,
                business_cycle_passed: None,
                error: Some("connect ECONNREFUSED 8686".to_owned()),
            },
            RootAdapterFailureKind::ModelUnavailable,
        )
        .with_all_projections_checked();
        let missing_final = AdapterFixtureCase::new(
            "missing-final",
            RootAdapterFailureEvidence {
                final_json_present: false,
                ..RootAdapterFailureEvidence::clean()
            },
            RootAdapterFailureKind::StreamOrFinalMissing,
        )
        .with_all_projections_checked();
        let missing_runtime = AdapterFixtureCase::new(
            "missing-runtime",
            RootAdapterFailureEvidence {
                runtime_model_present: false,
                runtime_tokens: Some(0),
                ..RootAdapterFailureEvidence::clean()
            },
            RootAdapterFailureKind::RuntimeResponseMissing,
        )
        .with_all_projections_checked();
        let quality = AdapterFixtureCase::new(
            "business-cycle-failed",
            RootAdapterFailureEvidence {
                business_cycle_passed: Some(false),
                ..RootAdapterFailureEvidence::clean()
            },
            RootAdapterFailureKind::ModelQualityFailure,
        )
        .with_all_projections_checked();
        let evidence = AdapterFixtureEvidence::from_cases([
            AdapterFixtureCase::clean_success("clean-success"),
            chain,
            unavailable,
            missing_final,
            missing_runtime,
            quality,
        ]);
        let gate = AdapterFixtureGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report = AdapterFixtureReport::from_gate_and_evidence(&gate, &evidence);

        assert_eq!(report.stage, "enforced");
        assert_eq!(report.case_names.len(), 6);
        assert!(report.required_failure_kinds.contains(&"chain_not_ready"));
        assert!(report.actual_failure_kinds.contains(&"model_unavailable"));
        assert!(report.classification_mismatches.is_empty());
        assert!(report.operational_quality_confusions.is_empty());
        assert!(!report.fixture_blocked);
        assert!(report.allow_runner_wiring);
    }

