    #[test]
    fn current_runner_compatibility_schema_sources_match_report_bit_boundary() {
        let schema = CurrentRunnerCompatibilityReportSchema::current_runner_compatibility_v1();
        let contract =
            AdapterCurrentRunnerCompatibilityBoundaryContract::current_runner_compatibility_v1();
        let plan =
            norion_test::AdapterCurrentRunnerCompatibilityBoundaryPlan::current_runner_compatibility_boundary(
                "current-runner-source-contract",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let source_for = |field_name: &str| {
            schema
                .fields
                .iter()
                .find(|field| field.name == field_name)
                .map(|field| field.source)
                .expect("current-runner schema field source")
        };

        assert_eq!(
            source_for("current_runner.adapter_report_field_coverage_passed"),
            "AdapterReportEmissionReport::field_coverage_passed"
        );
        assert_eq!(
            source_for("current_runner.report_bundle_complete"),
            "AdapterHandoffReport::report_bundle_complete"
        );
        assert_eq!(
            source_for("current_runner.self_evolution_unattended_prerequisites_passed"),
            "AdapterHandoffReport::self_evolution_unattended_prerequisites_passed"
        );
        assert_eq!(
            source_for("current_runner.rollback_resume_passed"),
            "AdapterHandoffReport::rollback_resume_passed"
        );
        assert_eq!(
            source_for("current_runner.adapter_fixture_passed"),
            "AdapterFixtureReport::allow_runner_wiring"
        );
        assert_eq!(
            source_for("current_runner.steam_case_matrix_passed"),
            "AdapterHandoffReport::steam_case_matrix_passed"
        );
        assert_eq!(
            source_for("current_runner.validation_command_coverage_passed"),
            "AdapterHandoffReport::validation_command_coverage_passed"
        );
        assert_eq!(
            source_for("current_runner.handoff_passed"),
            "AdapterHandoffReport::allow_runner_wiring"
        );
        assert!(!contract.allows_input("AdviceContinuationReport"));
        assert_eq!(
            source_for("current_runner.evolution_loop_tests_passed"),
            "AdapterHandoffReport::evolution_loop_passed"
        );
        assert_eq!(
            source_for("current_runner.workspace_tests_passed"),
            "AdapterHandoffReport::workspace_passed"
        );

        for allowed_input in [
            "AdapterReportEmissionReport",
            "AdapterFixtureReport",
            "AdapterHandoffReport",
        ] {
            assert!(contract.allows_input(allowed_input));
            assert!(plan.allows_input(allowed_input));
        }

        assert!(!contract.allows_input("CommandExecutor"));
        assert!(!contract.allows_input("EvolutionLoopRunner"));
        assert!(!contract.allows_input("RunnerSwitcher"));
        assert!(!contract.allows_input("JsonlReader"));
        assert!(contract.stays_pure_data_boundary());
        assert!(plan.stays_pure_data_boundary());
    }

    #[test]
    fn adapter_current_runner_compatibility_boundary_contract_matches_norion_test_plan() {
        let contract =
            AdapterCurrentRunnerCompatibilityBoundaryContract::current_runner_compatibility_v1();
        let plan =
            norion_test::AdapterCurrentRunnerCompatibilityBoundaryPlan::current_runner_compatibility_boundary(
                "current-runner-boundary",
                norion_test::AdapterAcceptanceStage::Enforced,
            );
        let entrypoints = contract
            .entrypoints
            .iter()
            .map(|entrypoint| entrypoint.to_string())
            .collect::<Vec<_>>();
        let allowed_inputs = contract
            .allowed_inputs
            .iter()
            .map(|input| input.to_string())
            .collect::<Vec<_>>();
        let produced_outputs = contract
            .produced_outputs
            .iter()
            .map(|output| output.to_string())
            .collect::<Vec<_>>();
        let forbidden_capabilities = contract
            .forbidden_capabilities
            .iter()
            .map(|capability| capability.to_string())
            .collect::<Vec<_>>();

        assert_eq!(plan.eval_entrypoints, entrypoints);
        assert_eq!(plan.allowed_inputs, allowed_inputs);
        assert_eq!(plan.produced_outputs, produced_outputs);
        assert_eq!(plan.forbidden_capabilities, forbidden_capabilities);
        assert!(contract.exposes_entrypoint("CurrentRunnerCompatibilityEvidence::all_passed"));
        assert!(contract.exposes_entrypoint("CurrentRunnerCompatibilityEvidence::crate_only"));
        assert!(contract.exposes_entrypoint(
            "CurrentRunnerCompatibilityEvidence::with_adapter_report_field_coverage_from_report"
        ));
        assert!(
            contract.exposes_entrypoint(
                "CurrentRunnerCompatibilityEvidence::with_adapter_fixture_report"
            )
        );
        assert!(contract.exposes_entrypoint(
            "CurrentRunnerCompatibilityEvidence::with_handoff_report_pass_bits"
        ));
        assert!(contract.exposes_entrypoint("CurrentRunnerCompatibilityGate::for_stage"));
        assert!(contract.exposes_entrypoint("CurrentRunnerCompatibilityGate::evaluate"));
        assert!(
            contract.exposes_entrypoint("CurrentRunnerCompatibilityReport::from_gate_and_evidence")
        );
        assert!(contract.allows_input("RootAdapterRolloutStage"));
        assert!(contract.allows_input("CurrentRunnerCompatibilityGate"));
        assert!(contract.allows_input("CurrentRunnerCompatibilityEvidence"));
        assert!(contract.allows_input("AdapterReportEmissionReport"));
        assert!(contract.allows_input("AdapterFixtureReport"));
        assert!(contract.allows_input("AdapterHandoffReport"));
        assert!(contract.allows_input("upstream_gate_pass_bits"));
        assert!(contract.allows_input("test_result_pass_bits"));
        assert!(!contract.allows_input("CommandExecutor"));
        assert!(!contract.allows_input("EvolutionLoopRunner"));
        assert!(!contract.allows_input("RunnerSwitcher"));
        assert!(!contract.allows_input("JsonlReader"));
        assert!(contract.produces_output("CurrentRunnerCompatibilityEvidence"));
        assert!(contract.produces_output("GateDecision"));
        assert!(contract.produces_output("CurrentRunnerCompatibilityReport"));
        assert!(contract.stays_pure_data_boundary());
        assert!(contract.forbids_capability("jsonl_io"));
        assert!(contract.forbids_capability("file_io"));
        assert!(contract.forbids_capability("http_sse"));
        assert!(contract.forbids_capability("process_spawn"));
        assert!(contract.forbids_capability("cargo_test_execution"));
        assert!(contract.forbids_capability("workspace_test_execution"));
        assert!(contract.forbids_capability("evolution_loop_test_execution"));
        assert!(contract.forbids_capability("model_call"));
        assert!(contract.forbids_capability("runner_switch_execution"));
        assert!(contract.forbids_capability("runner_wiring_execution"));
        assert!(contract.forbids_capability("runner_state_mutation"));
        assert!(contract.forbids_capability("remote_mac_call"));
        assert!(plan.stays_pure_data_boundary());
        assert!(!plan.may_block_current_runner());
        assert!(plan.preserves_legacy_runner);
    }

