    #[test]
    fn adapter_report_field_coverage_projects_from_emission_report() {
        let plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let gate = AdapterReportEmissionGate::for_stage(RootAdapterRolloutStage::Enforced);
        let complete_report = AdapterReportEmissionReport::from_gate_plan_and_evidence(
            &gate,
            &plan,
            &AdapterReportEmissionEvidence::complete_for_plan(&plan),
        );
        let missing_field_report = AdapterReportEmissionReport::from_gate_plan_and_evidence(
            &gate,
            &plan,
            &AdapterReportEmissionEvidence::from_observed(
                plan.report_names(),
                plan.future_events(),
            ),
        );

        assert!(complete_report.field_coverage_passed());
        assert!(!missing_field_report.field_coverage_passed());
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"apple_silicon_effect.feedback_applied")
        );
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"model_pool_attribution.validation_checked")
        );
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"model_pool_attribution.chain_not_ready_count")
        );
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"model_pool_attribution.model_unavailable_count")
        );
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"context_rot_trend.latest_noisy_records")
        );
        assert!(
            missing_field_report
                .missing_report_fields
                .contains(&"context_rot_remediation.allow_experiment_rollout")
        );

        let handoff_evidence = AdapterHandoffEvidence::full_handoff_passed()
            .with_adapter_report_field_coverage_from_report(&missing_field_report);
        let handoff_decision =
            AdapterHandoffChecklist::before_runner_wiring(RootAdapterRolloutStage::Enforced)
                .evaluate(&handoff_evidence);
        assert!(handoff_decision.blocked);
        assert!(
            handoff_decision
                .reasons
                .iter()
                .any(|reason| reason.contains("adapter report field coverage"))
        );

        let current_runner_evidence = CurrentRunnerCompatibilityEvidence::all_passed()
            .with_adapter_report_field_coverage_from_report(&missing_field_report);
        let current_runner_report = CurrentRunnerCompatibilityReport::from_gate_and_evidence(
            &CurrentRunnerCompatibilityGate::for_stage(RootAdapterRolloutStage::Enforced),
            &current_runner_evidence,
        );
        assert!(current_runner_report.compatibility_blocked);
        assert!(!current_runner_report.adapter_report_field_coverage_passed);

        let promotion_evidence = AdapterPromotionWindowEvidence::stable_report_only_window(3)
            .with_adapter_report_field_coverage_passed_runs_from_reports([
                &complete_report,
                &missing_field_report,
                &missing_field_report,
            ]);
        let promotion_report = AdapterPromotionWindowReport::from_gate_and_evidence(
            &AdapterPromotionWindowGate::for_stage(RootAdapterRolloutStage::Enforced),
            &promotion_evidence,
        );
        assert_eq!(
            promotion_report.adapter_report_field_coverage_passed_runs,
            1
        );
        assert!(promotion_report.promotion_blocked);
        assert!(
            promotion_report
                .failure_reasons
                .iter()
                .any(|reason| reason.contains("adapter report field coverage"))
        );
    }

    #[test]
    fn adapter_report_emission_gate_blocks_unattended_claim_before_promotion() {
        let plan = AdapterReportEmissionPlan::apple_silicon_development_effect();
        let mut reports = plan.report_names();
        let unattended_index = reports
            .iter()
            .position(|name| *name == "self_evolution_unattended_prerequisites_report_v1")
            .expect("unattended prerequisite step");
        let promotion_index = reports
            .iter()
            .position(|name| *name == "adapter_promotion_window_report_v1")
            .expect("promotion window step");
        reports.swap(unattended_index, promotion_index);

        let evidence = AdapterReportEmissionEvidence::from_observed(reports, plan.future_events());
        let gate = AdapterReportEmissionGate::for_stage(RootAdapterRolloutStage::Enforced);
        let report =
            AdapterReportEmissionReport::from_gate_plan_and_evidence(&gate, &plan, &evidence);

        assert!(report.emission_blocked);
        assert!(!report.allow_report_promotion);
        assert!(report.failure_reasons.iter().any(|reason| {
            reason.contains("self_evolution_unattended_prerequisites_report_v1")
                && reason.contains("adapter_promotion_window_report_v1")
        }));
    }

